var e=JSON.parse(`[{"id":14000,"term":"abbey","meaning":"수도원; 대성당","partOfSpeech":"n.","example":"Tourists visit the ancient abbey to admire its gothic architecture.","exampleTranslation":"관광객들은 고딕 건축물을 감상하기 위해 고대 수도원을 방문합니다.","level":32,"category":"빈도 학습"},{"id":14001,"term":"abdomen","meaning":"복부; 배","partOfSpeech":"n.","example":"The doctor pressed on the patient's abdomen to check for any pain.","exampleTranslation":"의사는 통증이 있는지 확인하기 위해 환자의 복부를 눌렀습니다.","level":32,"category":"빈도 학습"},{"id":14002,"term":"abolish","meaning":"폐지하다; 없애다","partOfSpeech":"v.","example":"Many countries have moved to abolish the death penalty entirely.","exampleTranslation":"많은 나라들이 사형 제도를 완전히 폐지하기 위해 움직이고 있습니다.","level":32,"category":"빈도 학습"},{"id":14003,"term":"accessory","meaning":"액세서리; 부속품; 공범","partOfSpeech":"n.","example":"A stylish belt can be the perfect accessory to complete any outfit.","exampleTranslation":"세련된 벨트는 어떤 옷차림도 완성시켜 주는 완벽한 액세서리가 될 수 있습니다.","level":32,"category":"빈도 학습"},{"id":14004,"term":"adore","meaning":"매우 좋아하다; 흠모하다","partOfSpeech":"v.","example":"The children absolutely adore their kind and funny new teacher.","exampleTranslation":"아이들은 친절하고 재미있는 새 선생님을 매우 좋아합니다.","level":32,"category":"빈도 학습"},{"id":14005,"term":"advocacy","meaning":"옹호; 지지; 변호","partOfSpeech":"n.","example":"Her advocacy for children's rights earned her international recognition.","exampleTranslation":"아동 권리에 대한 그녀의 옹호 활동은 그녀에게 국제적인 인정을 받게 했습니다.","level":32,"category":"빈도 학습"},{"id":14006,"term":"aerial","meaning":"공중의; 항공의; 안테나","partOfSpeech":"adj.","example":"The aerial photographs revealed the true extent of flood damage.","exampleTranslation":"항공 사진은 홍수 피해의 실제 규모를 드러냈습니다.","level":32,"category":"빈도 학습"},{"id":14007,"term":"aftermath","meaning":"여파; 후유증; 결과","partOfSpeech":"n.","example":"In the aftermath of the storm, many homes were left without power.","exampleTranslation":"폭풍이 지나간 여파로 많은 집들이 전기 없이 남겨졌습니다.","level":32,"category":"빈도 학습"},{"id":14008,"term":"aggravate","meaning":"악화시키다; 짜증나게 하다","partOfSpeech":"v.","example":"Eating spicy food can aggravate an existing stomach condition.","exampleTranslation":"매운 음식을 먹으면 기존의 위 상태를 악화시킬 수 있습니다.","level":32,"category":"빈도 학습"},{"id":14009,"term":"aggregate","meaning":"집계; 합계; 모으다","partOfSpeech":"n.","example":"The aggregate of all scores will determine the final ranking.","exampleTranslation":"모든 점수의 합계가 최종 순위를 결정할 것입니다.","level":32,"category":"빈도 학습"},{"id":14010,"term":"agitate","meaning":"동요시키다; 선동하다; 흔들다","partOfSpeech":"v.","example":"The controversial speech began to agitate the crowd in the square.","exampleTranslation":"논란이 많은 연설이 광장의 군중을 동요시키기 시작했습니다.","level":32,"category":"빈도 학습"},{"id":14011,"term":"aide","meaning":"보좌관; 조수; 도우미","partOfSpeech":"n.","example":"The senator's trusted aide prepared all the documents for the meeting.","exampleTranslation":"상원의원의 신뢰받는 보좌관이 회의를 위한 모든 서류를 준비했습니다.","level":32,"category":"빈도 학습"},{"id":14012,"term":"ail","meaning":"앓다; 괴롭히다; 아프다","partOfSpeech":"v.","example":"What seems to ail the patient is a severe lack of sleep.","exampleTranslation":"환자를 괴롭히는 것은 심각한 수면 부족인 것 같습니다.","level":32,"category":"빈도 학습"},{"id":14013,"term":"airways","meaning":"항공로; 기도; 방송국","partOfSpeech":"n.","example":"The new regulations will affect all major airways across the country.","exampleTranslation":"새로운 규정은 전국의 모든 주요 항공로에 영향을 미칠 것입니다.","level":32,"category":"빈도 학습"},{"id":14014,"term":"aisle","meaning":"통로; 복도","partOfSpeech":"n.","example":"Please keep the aisle clear so other passengers can move freely.","exampleTranslation":"다른 승객들이 자유롭게 이동할 수 있도록 통로를 비워두세요.","level":32,"category":"빈도 학습"},{"id":14015,"term":"albeit","meaning":"비록 ~이지만; ~임에도 불구하고","partOfSpeech":"conj.","example":"The project was a success, albeit a costly one for the company.","exampleTranslation":"그 프로젝트는 비록 회사에 비용이 많이 들었지만 성공이었습니다.","level":32,"category":"빈도 학습"},{"id":14016,"term":"algorithm","meaning":"알고리즘; 연산 절차","partOfSpeech":"n.","example":"The search engine uses a complex algorithm to rank web pages.","exampleTranslation":"검색 엔진은 웹 페이지의 순위를 매기기 위해 복잡한 알고리즘을 사용합니다.","level":32,"category":"빈도 학습"},{"id":14017,"term":"allegiance","meaning":"충성; 충성심; 복종","partOfSpeech":"n.","example":"Soldiers pledge their allegiance to the country they serve.","exampleTranslation":"군인들은 자신이 섬기는 나라에 충성을 맹세합니다.","level":32,"category":"빈도 학습"},{"id":14018,"term":"aloud","meaning":"소리 내어; 큰 소리로","partOfSpeech":"adv.","example":"The teacher asked the students to read the poem aloud in class.","exampleTranslation":"선생님은 학생들에게 수업 시간에 시를 소리 내어 읽으라고 했습니다.","level":32,"category":"빈도 학습"},{"id":14019,"term":"altar","meaning":"제단; 제물대","partOfSpeech":"n.","example":"Flowers and candles were placed on the altar before the ceremony.","exampleTranslation":"의식이 시작되기 전에 제단 위에 꽃과 촛불이 놓였습니다.","level":32,"category":"빈도 학습"},{"id":14020,"term":"altitude","meaning":"고도; 높이","partOfSpeech":"n.","example":"Pilots must monitor altitude carefully when flying over mountains.","exampleTranslation":"조종사들은 산 위를 비행할 때 고도를 주의 깊게 모니터해야 합니다.","level":32,"category":"빈도 학습"},{"id":14021,"term":"ambiguity","meaning":"모호함; 애매함","partOfSpeech":"n.","example":"The legal contract was rewritten to remove any ambiguity in its terms.","exampleTranslation":"법적 계약서는 조항의 모호함을 없애기 위해 다시 작성되었습니다.","level":32,"category":"빈도 학습"},{"id":14022,"term":"ammunition","meaning":"탄약; 탄환","partOfSpeech":"n.","example":"The soldiers ran low on ammunition during the extended battle.","exampleTranslation":"군인들은 장기간의 전투 중에 탄약이 부족해졌습니다.","level":32,"category":"빈도 학습"},{"id":14023,"term":"amnesty","meaning":"사면; 대사령","partOfSpeech":"n.","example":"The government declared amnesty for all political prisoners that year.","exampleTranslation":"정부는 그해 모든 정치범에 대한 사면을 선언했습니다.","level":32,"category":"빈도 학습"},{"id":14024,"term":"ample","meaning":"충분한; 넉넉한; 풍부한","partOfSpeech":"adj.","example":"There is ample space in the parking lot for all the visitors today.","exampleTranslation":"오늘 모든 방문객을 위한 충분한 주차 공간이 주차장에 있습니다.","level":32,"category":"빈도 학습"},{"id":14025,"term":"amplify","meaning":"증폭시키다; 확대하다; 강화하다","partOfSpeech":"v.","example":"The speakers amplify the sound so the audience at the back can hear.","exampleTranslation":"스피커는 뒤쪽 관객이 들을 수 있도록 소리를 증폭시킵니다.","level":33,"category":"빈도 학습"},{"id":14026,"term":"analogy","meaning":"유추; 비유; 유사점","partOfSpeech":"n.","example":"The teacher used an analogy to help students understand the complex idea.","exampleTranslation":"선생님은 학생들이 복잡한 개념을 이해하도록 돕기 위해 비유를 사용했습니다.","level":33,"category":"빈도 학습"},{"id":14027,"term":"analytic","meaning":"분석적인; 해석적인","partOfSpeech":"adj.","example":"Her analytic approach helped the team solve the problem efficiently.","exampleTranslation":"그녀의 분석적인 접근 방식은 팀이 문제를 효율적으로 해결하도록 도왔습니다.","level":33,"category":"빈도 학습"},{"id":14028,"term":"anatomy","meaning":"해부학; 신체 구조","partOfSpeech":"n.","example":"Medical students study anatomy to understand how the human body works.","exampleTranslation":"의대생들은 인체가 어떻게 작동하는지 이해하기 위해 해부학을 공부합니다.","level":33,"category":"빈도 학습"},{"id":14029,"term":"anecdote","meaning":"일화; 짧은 이야기","partOfSpeech":"n.","example":"The speaker shared a funny anecdote to break the ice with the audience.","exampleTranslation":"연사는 청중과 긴장을 풀기 위해 재미있는 일화를 나눴습니다.","level":33,"category":"빈도 학습"},{"id":14030,"term":"angler","meaning":"낚시꾼; 낚시하는 사람","partOfSpeech":"n.","example":"The angler waited patiently by the river for hours without a catch.","exampleTranslation":"낚시꾼은 몇 시간 동안 잡은 것 없이 강가에서 참을성 있게 기다렸습니다.","level":33,"category":"빈도 학습"},{"id":14031,"term":"anguish","meaning":"고통; 번민; 괴로움","partOfSpeech":"n.","example":"The parents felt deep anguish when their child went missing overnight.","exampleTranslation":"부모들은 아이가 밤새 행방불명되자 깊은 고통을 느꼈습니다.","level":33,"category":"빈도 학습"},{"id":14032,"term":"anomaly","meaning":"이상 현상; 변칙; 예외","partOfSpeech":"n.","example":"Scientists detected an anomaly in the data that required further investigation.","exampleTranslation":"과학자들은 추가 조사가 필요한 데이터의 이상 현상을 감지했습니다.","level":33,"category":"빈도 학습"},{"id":14033,"term":"ant","meaning":"개미","partOfSpeech":"n.","example":"A single ant can carry objects many times heavier than its own body.","exampleTranslation":"개미 한 마리는 자신의 몸무게보다 몇 배나 무거운 물체를 운반할 수 있습니다.","level":33,"category":"빈도 학습"},{"id":14034,"term":"antibiotic","meaning":"항생제; 항균 물질","partOfSpeech":"n.","example":"The doctor prescribed an antibiotic to treat the bacterial infection.","exampleTranslation":"의사는 세균 감염을 치료하기 위해 항생제를 처방했습니다.","level":33,"category":"빈도 학습"},{"id":14035,"term":"antibody","meaning":"항체","partOfSpeech":"n.","example":"The vaccine helps the body produce an antibody to fight the virus.","exampleTranslation":"백신은 신체가 바이러스와 싸우는 항체를 생성하도록 돕습니다.","level":33,"category":"빈도 학습"},{"id":14036,"term":"apparatus","meaning":"장치; 기구","partOfSpeech":"n.","example":"The laboratory apparatus must be cleaned after every experiment.","exampleTranslation":"실험실 장치는 매 실험 후에 세척해야 합니다.","level":33,"category":"빈도 학습"},{"id":14037,"term":"appendix","meaning":"부록; 맹장","partOfSpeech":"n.","example":"The report includes a detailed appendix with all the raw data.","exampleTranslation":"보고서에는 모든 원시 데이터가 담긴 상세한 부록이 포함되어 있습니다.","level":33,"category":"빈도 학습"},{"id":14038,"term":"appetite","meaning":"식욕; 욕구","partOfSpeech":"n.","example":"A long hike in the mountains can give you a strong appetite.","exampleTranslation":"산에서 오래 하이킹하면 강한 식욕이 생길 수 있습니다.","level":33,"category":"빈도 학습"},{"id":14039,"term":"applaud","meaning":"박수를 치다; 칭찬하다","partOfSpeech":"v.","example":"The audience began to applaud loudly at the end of the performance.","exampleTranslation":"공연이 끝나자 관객들이 큰 소리로 박수를 치기 시작했습니다.","level":33,"category":"빈도 학습"},{"id":14040,"term":"applause","meaning":"박수갈채; 칭찬","partOfSpeech":"n.","example":"The singer received warm applause from the crowd after her final song.","exampleTranslation":"가수는 마지막 노래 후 관중으로부터 따뜻한 박수갈채를 받았습니다.","level":33,"category":"빈도 학습"},{"id":14041,"term":"appliance","meaning":"가전제품; 기기","partOfSpeech":"n.","example":"Every kitchen appliance in our home runs on electricity.","exampleTranslation":"우리 집의 모든 주방 가전제품은 전기로 작동합니다.","level":33,"category":"빈도 학습"},{"id":14042,"term":"apprehend","meaning":"체포하다; 이해하다","partOfSpeech":"v.","example":"Police managed to apprehend the suspect near the train station.","exampleTranslation":"경찰은 기차역 근처에서 용의자를 체포하는 데 성공했습니다.","level":33,"category":"빈도 학습"},{"id":14043,"term":"apprentice","meaning":"견습생; 도제","partOfSpeech":"n.","example":"The young apprentice learned carpentry skills from the master craftsman.","exampleTranslation":"젊은 견습생은 숙련된 장인으로부터 목공 기술을 배웠습니다.","level":33,"category":"빈도 학습"},{"id":14044,"term":"appropriated","meaning":"(자금·토지 등을) 책정한; 전용한","partOfSpeech":"adj.","example":"The funds appropriated for the project were spent within a year.","exampleTranslation":"그 사업에 책정된 자금은 1년 안에 모두 쓰였습니다.","level":33,"category":"빈도 학습"},{"id":14045,"term":"apt","meaning":"적절한; 재능 있는","partOfSpeech":"adj.","example":"Her apt description of the problem helped everyone understand quickly.","exampleTranslation":"그녀의 적절한 문제 설명이 모든 사람이 빨리 이해하는 데 도움을 주었습니다.","level":33,"category":"빈도 학습"},{"id":14046,"term":"aquarium","meaning":"수족관; 어항","partOfSpeech":"n.","example":"We spent the afternoon watching colorful fish at the aquarium.","exampleTranslation":"우리는 수족관에서 화려한 물고기를 구경하며 오후를 보냈습니다.","level":33,"category":"빈도 학습"},{"id":14047,"term":"arbitrary","meaning":"임의적인; 독단적인","partOfSpeech":"adj.","example":"The manager made an arbitrary decision without consulting the team.","exampleTranslation":"관리자는 팀과 상의하지 않고 임의적인 결정을 내렸습니다.","level":33,"category":"빈도 학습"},{"id":14048,"term":"arbitrate","meaning":"중재하다; 조정하다","partOfSpeech":"v.","example":"A neutral party was asked to arbitrate the dispute between the two companies.","exampleTranslation":"두 회사 간의 분쟁을 중재하기 위해 중립적인 당사자가 요청되었습니다.","level":33,"category":"빈도 학습"},{"id":14049,"term":"arc","meaning":"호; 곡선","partOfSpeech":"n.","example":"The rainbow formed a perfect arc across the sky after the rain.","exampleTranslation":"비가 온 후 무지개가 하늘을 가로질러 완벽한 호를 형성했습니다.","level":33,"category":"빈도 학습"},{"id":14050,"term":"arctic","meaning":"북극의; 극도로 추운","partOfSpeech":"adj.","example":"The arctic winds made it nearly impossible to walk outside today.","exampleTranslation":"북극의 바람이 불어 오늘 밖을 걷는 것이 거의 불가능했습니다.","level":33,"category":"빈도 학습"},{"id":14051,"term":"artery","meaning":"동맥; 주요 도로","partOfSpeech":"n.","example":"The doctor explained that the main artery carries blood away from the heart.","exampleTranslation":"의사는 주요 동맥이 심장에서 혈액을 운반한다고 설명했습니다.","level":33,"category":"빈도 학습"},{"id":14052,"term":"artillery","meaning":"포병대; 대포","partOfSpeech":"n.","example":"The general ordered the artillery to fire on the enemy's position.","exampleTranslation":"장군은 포병대에게 적의 진지에 포격하라고 명령했습니다.","level":33,"category":"빈도 학습"},{"id":14053,"term":"ascend","meaning":"올라가다; 오르다","partOfSpeech":"v.","example":"Climbers need proper gear to safely ascend the steep mountain trail.","exampleTranslation":"등산가들은 가파른 산길을 안전하게 오르기 위해 적절한 장비가 필요합니다.","level":33,"category":"빈도 학습"},{"id":14054,"term":"assimilate","meaning":"동화되다; 흡수하다","partOfSpeech":"v.","example":"It takes time for immigrants to assimilate into a new culture.","exampleTranslation":"이민자들이 새로운 문화에 동화되는 데는 시간이 걸립니다.","level":33,"category":"빈도 학습"},{"id":14055,"term":"asthma","meaning":"천식","partOfSpeech":"n.","example":"Her asthma gets worse when she is around cigarette smoke.","exampleTranslation":"그녀의 천식은 담배 연기 주변에 있을 때 더 심해집니다.","level":33,"category":"빈도 학습"},{"id":14056,"term":"asylum","meaning":"망명; 보호 시설","partOfSpeech":"n.","example":"The refugee family applied for asylum in the neighboring country.","exampleTranslation":"난민 가족은 이웃 나라에 망명을 신청했습니다.","level":33,"category":"빈도 학습"},{"id":14057,"term":"audible","meaning":"들을 수 있는; 청취 가능한","partOfSpeech":"adj.","example":"The warning signal must be audible from at least fifty meters away.","exampleTranslation":"경고 신호는 최소 50미터 거리에서도 들을 수 있어야 합니다.","level":33,"category":"빈도 학습"},{"id":14058,"term":"authoritarian","meaning":"권위주의적인; 독재적인","partOfSpeech":"adj.","example":"The authoritarian leader refused to allow any public protests in the country.","exampleTranslation":"권위주의적인 지도자는 국내에서 어떠한 공개 시위도 허용하지 않았습니다.","level":33,"category":"빈도 학습"},{"id":14059,"term":"autobiography","meaning":"자서전","partOfSpeech":"n.","example":"The retired athlete wrote an autobiography about her career and personal struggles.","exampleTranslation":"은퇴한 운동선수는 자신의 경력과 개인적 고난에 대한 자서전을 썼습니다.","level":33,"category":"빈도 학습"},{"id":14060,"term":"automate","meaning":"자동화하다","partOfSpeech":"v.","example":"Many factories now automate repetitive tasks to increase efficiency.","exampleTranslation":"많은 공장들이 효율성을 높이기 위해 반복적인 작업을 자동화합니다.","level":33,"category":"빈도 학습"},{"id":14061,"term":"autonomous","meaning":"자율적인; 독립적인","partOfSpeech":"adj.","example":"The company is developing autonomous vehicles that can drive without a human.","exampleTranslation":"그 회사는 사람 없이 주행할 수 있는 자율 주행 차량을 개발하고 있습니다.","level":33,"category":"빈도 학습"},{"id":14062,"term":"aviation","meaning":"항공; 비행","partOfSpeech":"n.","example":"The aviation industry has grown significantly over the past few decades.","exampleTranslation":"항공 산업은 지난 수십 년 동안 크게 성장했습니다.","level":33,"category":"빈도 학습"},{"id":14063,"term":"awe","meaning":"경외감; 경이로움","partOfSpeech":"n.","example":"The tourists stood in awe as they gazed at the massive waterfall.","exampleTranslation":"관광객들은 거대한 폭포를 바라보며 경외감에 서 있었습니다.","level":33,"category":"빈도 학습"},{"id":14064,"term":"axis","meaning":"축; 기준선","partOfSpeech":"n.","example":"Earth rotates on its axis once every twenty-four hours.","exampleTranslation":"지구는 24시간마다 한 번씩 자신의 축을 중심으로 회전합니다.","level":33,"category":"빈도 학습"},{"id":14065,"term":"badge","meaning":"배지; 표식","partOfSpeech":"n.","example":"All employees must wear their badge while inside the office building.","exampleTranslation":"모든 직원은 사무실 건물 내에서 배지를 착용해야 합니다.","level":33,"category":"빈도 학습"},{"id":14066,"term":"bail","meaning":"보석금; 보석으로 석방하다","partOfSpeech":"n.","example":"The judge set the bail at ten thousand dollars for the defendant.","exampleTranslation":"판사는 피고인의 보석금을 1만 달러로 정했습니다.","level":33,"category":"빈도 학습"},{"id":14067,"term":"bait","meaning":"미끼; 유혹하다","partOfSpeech":"n.","example":"The fisherman used a worm as bait to attract fish to his hook.","exampleTranslation":"어부는 낚시 바늘에 물고기를 유인하기 위해 지렁이를 미끼로 사용했습니다.","level":33,"category":"빈도 학습"},{"id":14068,"term":"balcony","meaning":"발코니; 베란다","partOfSpeech":"n.","example":"She enjoys drinking her morning coffee on the balcony overlooking the park.","exampleTranslation":"그녀는 공원이 내려다보이는 발코니에서 아침 커피를 즐깁니다.","level":33,"category":"빈도 학습"},{"id":14069,"term":"bald","meaning":"대머리의; 민둥한","partOfSpeech":"adj.","example":"The bald eagle is one of the most recognized symbols of the United States.","exampleTranslation":"흰머리수리는 미국의 가장 잘 알려진 상징 중 하나입니다.","level":33,"category":"빈도 학습"},{"id":14070,"term":"banner","meaning":"현수막; 깃발","partOfSpeech":"n.","example":"Supporters held up a large banner with the candidate's name at the rally.","exampleTranslation":"지지자들은 집회에서 후보자 이름이 적힌 큰 현수막을 들었습니다.","level":33,"category":"빈도 학습"},{"id":14071,"term":"baptist","meaning":"침례교 신자; 침례교의","partOfSpeech":"n.","example":"The baptist congregation gathered every Sunday morning for worship.","exampleTranslation":"침례교 신자들은 예배를 위해 매주 일요일 아침에 모였습니다.","level":33,"category":"빈도 학습"},{"id":14072,"term":"baron","meaning":"남작; 거물","partOfSpeech":"n.","example":"The oil baron owned several large companies across the country.","exampleTranslation":"그 석유 거물은 전국에 여러 대형 회사를 소유하고 있었습니다.","level":33,"category":"빈도 학습"},{"id":14073,"term":"basketball","meaning":"농구","partOfSpeech":"n.","example":"My brother plays basketball with his friends every weekend at the park.","exampleTranslation":"내 형은 매주 주말에 공원에서 친구들과 농구를 합니다.","level":33,"category":"빈도 학습"},{"id":14074,"term":"batch","meaning":"한 묶음; 일괄 처리","partOfSpeech":"n.","example":"The baker prepared a fresh batch of cookies for the school event.","exampleTranslation":"제빵사는 학교 행사를 위해 쿠키 한 묶음을 신선하게 준비했습니다.","level":33,"category":"빈도 학습"},{"id":14075,"term":"battalion","meaning":"대대; 많은 무리","partOfSpeech":"n.","example":"The battalion was ordered to march toward the northern border at dawn.","exampleTranslation":"대대는 새벽에 북쪽 국경을 향해 행군하라는 명령을 받았습니다.","level":33,"category":"빈도 학습"},{"id":14076,"term":"beloved","meaning":"사랑하는; 소중한","partOfSpeech":"adj.","example":"The community gathered to honor their beloved teacher who had retired.","exampleTranslation":"지역 사회는 은퇴한 그들의 사랑하는 선생님을 기리기 위해 모였습니다.","level":33,"category":"빈도 학습"},{"id":14077,"term":"beneficiary","meaning":"수혜자; 수익자","partOfSpeech":"n.","example":"She named her daughter as the beneficiary of her life insurance policy.","exampleTranslation":"그녀는 딸을 생명보험의 수혜자로 지명했습니다.","level":33,"category":"빈도 학습"},{"id":14078,"term":"beta","meaning":"베타(시험판); 두 번째","partOfSpeech":"n.","example":"The software team released a beta version of the app for public testing.","exampleTranslation":"소프트웨어 팀은 공개 테스트를 위해 앱의 베타 버전을 출시했습니다.","level":33,"category":"빈도 학습"},{"id":14079,"term":"bewilder","meaning":"당혹하게 하다; 어리둥절하게 하다","partOfSpeech":"v.","example":"The complex instructions tend to bewilder new users of the software.","exampleTranslation":"복잡한 설명은 소프트웨어 신규 사용자들을 어리둥절하게 하는 경향이 있습니다.","level":33,"category":"빈도 학습"},{"id":14080,"term":"bilateral","meaning":"양측의; 쌍무적인","partOfSpeech":"adj.","example":"The two nations signed a bilateral trade agreement to boost their economies.","exampleTranslation":"두 나라는 경제를 활성화하기 위해 양자 무역 협정에 서명했습니다.","level":33,"category":"빈도 학습"},{"id":14081,"term":"binoculars","meaning":"쌍안경","partOfSpeech":"n.","example":"She used her binoculars to watch the birds nesting in the tall trees.","exampleTranslation":"그녀는 쌍안경을 사용하여 높은 나무에 둥지를 튼 새들을 관찰했습니다.","level":33,"category":"빈도 학습"},{"id":14082,"term":"bleak","meaning":"황량한; 암울한","partOfSpeech":"adj.","example":"The job market looks bleak for recent graduates this year.","exampleTranslation":"올해 최근 졸업생들에게 취업 시장은 암울해 보입니다.","level":33,"category":"빈도 학습"},{"id":14083,"term":"blockade","meaning":"봉쇄; 차단","partOfSpeech":"n.","example":"The naval blockade prevented supply ships from entering the port.","exampleTranslation":"해상 봉쇄로 인해 보급선이 항구에 들어오지 못했습니다.","level":33,"category":"빈도 학습"},{"id":14084,"term":"blossom","meaning":"꽃; 꽃이 피다","partOfSpeech":"n.","example":"The cherry blossom season attracts thousands of visitors to the park each spring.","exampleTranslation":"벚꽃 시즌에는 매년 봄 수천 명의 방문객이 공원을 찾습니다.","level":33,"category":"빈도 학습"},{"id":14085,"term":"blouse","meaning":"블라우스; 여성용 상의","partOfSpeech":"n.","example":"She wore a silk blouse with a pair of dark trousers to the interview.","exampleTranslation":"그녀는 면접에 실크 블라우스와 짙은색 바지를 입고 갔습니다.","level":33,"category":"빈도 학습"},{"id":14086,"term":"blunt","meaning":"직설적인; 무딘","partOfSpeech":"adj.","example":"She was blunt about her opinion of the new policy.","exampleTranslation":"그녀는 새 정책에 대한 자신의 의견을 직설적으로 말했어요.","category":"빈도 학습","level":33},{"id":14087,"term":"blush","meaning":"얼굴을 붉히다; 홍조","partOfSpeech":"v.","example":"She tends to blush whenever someone compliments her work.","exampleTranslation":"그녀는 누군가 그녀의 작업을 칭찬할 때마다 얼굴을 붉히는 경향이 있어요.","category":"빈도 학습","level":33},{"id":14088,"term":"botany","meaning":"식물학","partOfSpeech":"n.","example":"She studied botany to learn more about plant species.","exampleTranslation":"그녀는 식물 종류에 대해 더 알기 위해 식물학을 공부했어요.","category":"빈도 학습","level":33},{"id":14089,"term":"bourgeois","meaning":"중산층의; 속물적인","partOfSpeech":"adj.","example":"His bourgeois taste in furniture surprised many of his friends.","exampleTranslation":"가구에 대한 그의 중산층적인 취향은 많은 친구들을 놀라게 했어요.","category":"빈도 학습","level":33},{"id":14090,"term":"bout","meaning":"한 차례; 발작","partOfSpeech":"n.","example":"He had a bad bout of flu that lasted two weeks.","exampleTranslation":"그는 2주 동안 지속된 심한 독감 발작을 겪었어요.","category":"빈도 학습","level":33},{"id":14091,"term":"bowel","meaning":"장; 내장","partOfSpeech":"n.","example":"A healthy diet can improve bowel function significantly.","exampleTranslation":"건강한 식단은 장 기능을 크게 향상시킬 수 있어요.","category":"빈도 학습","level":33},{"id":14092,"term":"boycott","meaning":"불매운동; 보이콧하다","partOfSpeech":"v.","example":"Consumers decided to boycott the brand over its labor practices.","exampleTranslation":"소비자들은 그 브랜드의 노동 관행에 항의해 불매운동을 하기로 결정했어요.","category":"빈도 학습","level":33},{"id":14093,"term":"brace","meaning":"버팀대; 각오하다","partOfSpeech":"v.","example":"You should brace yourself for some difficult news.","exampleTranslation":"힘든 소식을 들을 각오를 해야 해요.","category":"빈도 학습","level":33},{"id":14094,"term":"bracket","meaning":"괄호; 범주","partOfSpeech":"n.","example":"Please put the numbers in a bracket to separate them clearly.","exampleTranslation":"숫자들을 명확히 구분하기 위해 괄호 안에 넣어 주세요.","category":"빈도 학습","level":33},{"id":14095,"term":"bribe","meaning":"뇌물; 뇌물을 주다","partOfSpeech":"n.","example":"The officer refused to accept a bribe from the suspect.","exampleTranslation":"그 경찰관은 용의자로부터 뇌물 받기를 거부했어요.","category":"빈도 학습","level":33},{"id":14096,"term":"brigade","meaning":"여단; 소방대","partOfSpeech":"n.","example":"The fire brigade arrived at the scene within minutes.","exampleTranslation":"소방대가 몇 분 안에 현장에 도착했어요.","category":"빈도 학습","level":33},{"id":14097,"term":"brisk","meaning":"활기찬; 쌀쌀한","partOfSpeech":"adj.","example":"We went for a brisk walk in the park before breakfast.","exampleTranslation":"우리는 아침 식사 전에 공원에서 활기차게 걷기를 했어요.","category":"빈도 학습","level":33},{"id":14098,"term":"brochure","meaning":"안내 책자; 소책자","partOfSpeech":"n.","example":"The travel agency gave us a colorful brochure about the tour.","exampleTranslation":"여행사에서 투어에 관한 화려한 안내 책자를 주었어요.","category":"빈도 학습","level":33},{"id":14099,"term":"brow","meaning":"이마; 눈썹","partOfSpeech":"n.","example":"He wiped sweat from his brow after the long run.","exampleTranslation":"그는 오랜 달리기 후 이마의 땀을 닦았어요.","category":"빈도 학습","level":33},{"id":14100,"term":"buckle","meaning":"버클; 구부러지다","partOfSpeech":"n.","example":"He tightened the buckle on his bag before heading out.","exampleTranslation":"그는 나가기 전에 가방의 버클을 단단히 조였어요.","category":"빈도 학습","level":33},{"id":14101,"term":"bud","meaning":"꽃봉오리; 싹","partOfSpeech":"n.","example":"The tree had its first bud of the season in early spring.","exampleTranslation":"그 나무는 이른 봄에 그 계절의 첫 꽃봉오리를 맺었어요.","category":"빈도 학습","level":33},{"id":14102,"term":"buffer","meaning":"완충재; 완충 역할을 하다","partOfSpeech":"n.","example":"A buffer zone between the two countries helped reduce tensions.","exampleTranslation":"두 나라 사이의 완충 지대는 긴장을 줄이는 데 도움이 됐어요.","category":"빈도 학습","level":33},{"id":14103,"term":"bulge","meaning":"부풀다; 불룩한 부분","partOfSpeech":"v.","example":"His pockets began to bulge with all the coins he had collected.","exampleTranslation":"그가 모은 동전들로 주머니가 불룩해지기 시작했어요.","category":"빈도 학습","level":33},{"id":14104,"term":"bulletin","meaning":"게시물; 공고","partOfSpeech":"n.","example":"The school posted a bulletin about the upcoming exam schedule.","exampleTranslation":"학교는 다가오는 시험 일정에 대한 공고를 게시했어요.","category":"빈도 학습","level":33},{"id":14105,"term":"burgle","meaning":"침입 절도하다","partOfSpeech":"v.","example":"Thieves tried to burgle the shop after it closed for the night.","exampleTranslation":"도둑들은 가게가 야간 영업을 마친 후 침입 절도를 시도했어요.","category":"빈도 학습","level":33},{"id":14106,"term":"bust","meaning":"흉상; 파산하다","partOfSpeech":"n.","example":"A marble bust of the president stood in the lobby.","exampleTranslation":"로비에 대통령의 대리석 흉상이 서 있었어요.","category":"빈도 학습","level":33},{"id":14107,"term":"butcher","meaning":"정육점 주인; 도살하다","partOfSpeech":"n.","example":"The butcher recommended a fresh cut of beef for the stew.","exampleTranslation":"정육점 주인이 스튜용으로 신선한 쇠고기 부위를 추천했어요.","category":"빈도 학습","level":33},{"id":14108,"term":"butt","meaning":"끝부분; 엉덩이","partOfSpeech":"n.","example":"He leaned the butt of the rifle against the wall carefully.","exampleTranslation":"그는 소총의 개머리판을 조심스럽게 벽에 기댔어요.","category":"빈도 학습","level":33},{"id":14109,"term":"bypass","meaning":"우회하다; 우회로","partOfSpeech":"v.","example":"Drivers chose to bypass the busy city center during rush hour.","exampleTranslation":"운전자들은 러시아워 때 혼잡한 시내 중심가를 우회하기로 했어요.","category":"빈도 학습","level":33},{"id":14110,"term":"calf","meaning":"송아지; 종아리","partOfSpeech":"n.","example":"The farmer watched the calf take its first steps in the barn.","exampleTranslation":"농부는 헛간에서 송아지가 첫걸음을 내딛는 것을 지켜봤어요.","category":"빈도 학습","level":33},{"id":14111,"term":"candy","meaning":"사탕; 캔디","partOfSpeech":"n.","example":"She gave each child a piece of candy as a reward.","exampleTranslation":"그녀는 보상으로 각 아이에게 사탕 하나씩을 주었어요.","category":"빈도 학습","level":33},{"id":14112,"term":"cane","meaning":"지팡이; 사탕수수","partOfSpeech":"n.","example":"The elderly man walked slowly with the help of a cane.","exampleTranslation":"그 노인은 지팡이의 도움으로 천천히 걸었어요.","category":"빈도 학습","level":33},{"id":14113,"term":"cannon","meaning":"대포","partOfSpeech":"n.","example":"The museum displayed an old cannon from the Civil War era.","exampleTranslation":"박물관은 남북전쟁 시대의 오래된 대포를 전시했어요.","category":"빈도 학습","level":33},{"id":14114,"term":"captive","meaning":"포로; 사로잡힌","partOfSpeech":"adj.","example":"The captive animal paced restlessly inside its small enclosure.","exampleTranslation":"사로잡힌 동물은 좁은 우리 안에서 불안하게 왔다 갔다 했어요.","category":"빈도 학습","level":33},{"id":14115,"term":"carbohydrate","meaning":"탄수화물","partOfSpeech":"n.","example":"Rice is a common source of carbohydrate in many Asian diets.","exampleTranslation":"쌀은 많은 아시아 식단에서 탄수화물의 일반적인 공급원이에요.","category":"빈도 학습","level":33},{"id":14116,"term":"cardboard","meaning":"판지; 골판지","partOfSpeech":"n.","example":"She packed her books in a cardboard box before moving.","exampleTranslation":"그녀는 이사하기 전에 책들을 판지 상자에 넣었어요.","category":"빈도 학습","level":33},{"id":14117,"term":"cardinal","meaning":"기본적인; 추기경","partOfSpeech":"adj.","example":"Honesty is a cardinal virtue in any professional setting.","exampleTranslation":"정직함은 어떤 직업적 환경에서도 기본적인 덕목이에요.","category":"빈도 학습","level":33},{"id":14118,"term":"cassette","meaning":"카세트 테이프","partOfSpeech":"n.","example":"He found an old cassette of his favorite band in the attic.","exampleTranslation":"그는 다락방에서 자신이 좋아하는 밴드의 오래된 카세트를 발견했어요.","category":"빈도 학습","level":33},{"id":14119,"term":"catastrophe","meaning":"대참사; 재앙","partOfSpeech":"n.","example":"The earthquake was a catastrophe that affected thousands of families.","exampleTranslation":"그 지진은 수천 가족에게 영향을 미친 대참사였어요.","category":"빈도 학습","level":33},{"id":14120,"term":"causal","meaning":"인과관계의; 원인이 되는","partOfSpeech":"adj.","example":"Scientists found a causal link between the drug and the side effects.","exampleTranslation":"과학자들은 그 약과 부작용 사이의 인과관계를 발견했어요.","category":"빈도 학습","level":33},{"id":14121,"term":"cellar","meaning":"지하실; 저장실","partOfSpeech":"n.","example":"They stored wine in the cool cellar beneath the house.","exampleTranslation":"그들은 집 아래 시원한 지하실에 와인을 보관했어요.","category":"빈도 학습","level":33},{"id":14122,"term":"cellular","meaning":"세포의; 휴대전화의","partOfSpeech":"adj.","example":"The study examined cellular damage caused by radiation exposure.","exampleTranslation":"그 연구는 방사선 노출로 인한 세포 손상을 조사했어요.","category":"빈도 학습","level":33},{"id":14123,"term":"cement","meaning":"시멘트; 굳히다","partOfSpeech":"n.","example":"Workers mixed cement and water to lay the foundation of the building.","exampleTranslation":"인부들은 건물의 기초를 놓기 위해 시멘트와 물을 섞었어요.","category":"빈도 학습","level":33},{"id":14124,"term":"ceramic","meaning":"도자기; 도자기의","partOfSpeech":"adj.","example":"The artist displayed her ceramic bowls at the local craft fair.","exampleTranslation":"그 예술가는 지역 공예 박람회에서 도자기 그릇들을 전시했어요.","category":"빈도 학습","level":33},{"id":14125,"term":"cereal","meaning":"시리얼; 곡물","partOfSpeech":"n.","example":"He eats a bowl of cereal with milk every morning for breakfast.","exampleTranslation":"그는 매일 아침 식사로 우유와 함께 시리얼 한 그릇을 먹어요.","category":"빈도 학습","level":33},{"id":14126,"term":"chalk","meaning":"분필; 백악","partOfSpeech":"n.","example":"The teacher used chalk to write the math equation on the board.","exampleTranslation":"선생님은 칠판에 수학 방정식을 쓰기 위해 분필을 사용했어요.","category":"빈도 학습","level":33},{"id":14127,"term":"chant","meaning":"구호를 외치다; 성가","partOfSpeech":"v.","example":"The crowd began to chant the name of their favorite player.","exampleTranslation":"군중은 자신들이 좋아하는 선수의 이름을 외치기 시작했어요.","category":"빈도 학습","level":33},{"id":14128,"term":"chap","meaning":"남자; 녀석","partOfSpeech":"n.","example":"He is a friendly chap who always greets everyone with a smile.","exampleTranslation":"그는 항상 미소로 모든 사람에게 인사하는 친근한 남자예요.","category":"빈도 학습","level":33},{"id":14129,"term":"charitable","meaning":"자선의; 관대한","partOfSpeech":"adj.","example":"The charitable organization donated supplies to flood victims.","exampleTranslation":"그 자선 단체는 홍수 피해자들에게 물자를 기증했어요.","category":"빈도 학습","level":33},{"id":14130,"term":"chatter","meaning":"재잘거리다; 수다","partOfSpeech":"v.","example":"The students began to chatter excitedly before the class started.","exampleTranslation":"수업이 시작되기 전에 학생들이 신나게 재잘거리기 시작했어요.","category":"빈도 학습","level":33},{"id":14131,"term":"chemist","meaning":"화학자; 약사","partOfSpeech":"n.","example":"The chemist discovered a new compound in the laboratory.","exampleTranslation":"그 화학자는 실험실에서 새로운 화합물을 발견했어요.","category":"빈도 학습","level":34},{"id":14132,"term":"cherry","meaning":"체리; 벚나무","partOfSpeech":"n.","example":"She picked a ripe cherry from the tree in the backyard.","exampleTranslation":"그녀는 뒷마당의 나무에서 잘 익은 체리를 땄어요.","category":"빈도 학습","level":34},{"id":14133,"term":"chimney","meaning":"굴뚝","partOfSpeech":"n.","example":"Smoke rose from the chimney as the family warmed themselves by the fire.","exampleTranslation":"가족이 불 앞에서 몸을 녹이는 동안 굴뚝에서 연기가 피어올랐어요.","category":"빈도 학습","level":34},{"id":14134,"term":"chord","meaning":"화음; 코드","partOfSpeech":"n.","example":"He strummed a beautiful chord on the guitar to start the song.","exampleTranslation":"그는 노래를 시작하기 위해 기타로 아름다운 화음을 연주했어요.","category":"빈도 학습","level":34},{"id":14135,"term":"chorus","meaning":"합창; 후렴","partOfSpeech":"n.","example":"The entire audience sang along with the chorus of the hit song.","exampleTranslation":"전체 관객이 인기 곡의 후렴을 따라 불렀어요.","category":"빈도 학습","level":34},{"id":14136,"term":"chuck","meaning":"내던지다; 포기하다","partOfSpeech":"v.","example":"He decided to chuck his old notes into the recycling bin.","exampleTranslation":"그는 오래된 노트를 재활용 통에 내던지기로 했어요.","level":34,"category":"빈도 학습"},{"id":14137,"term":"chuckle","meaning":"낮게 웃다; 빙그레 웃음","partOfSpeech":"v.","example":"She gave a quiet chuckle when she read the funny message.","exampleTranslation":"그녀는 재미있는 메시지를 읽고 조용히 빙그레 웃었어요.","level":34,"category":"빈도 학습"},{"id":14138,"term":"cigar","meaning":"시가; 엽궐련","partOfSpeech":"n.","example":"The old man sat on the porch and lit a cigar after dinner.","exampleTranslation":"노인은 저녁 식사 후 현관에 앉아 시가에 불을 붙였어요.","level":34,"category":"빈도 학습"},{"id":14139,"term":"circus","meaning":"서커스; 곡예단","partOfSpeech":"n.","example":"The children screamed with excitement at the circus show.","exampleTranslation":"아이들은 서커스 공연에 흥분해서 소리를 질렀어요.","level":34,"category":"빈도 학습"},{"id":14140,"term":"clamp","meaning":"죔쇠로 고정하다; 꽉 죄다","partOfSpeech":"v.","example":"The carpenter used a clamp to hold the two pieces of wood together.","exampleTranslation":"목수는 두 나무 조각을 함께 고정하기 위해 죔쇠를 사용했어요.","level":34,"category":"빈도 학습"},{"id":14141,"term":"clan","meaning":"씨족; 일가","partOfSpeech":"n.","example":"The entire clan gathered for the annual family reunion.","exampleTranslation":"온 씨족이 연례 가족 모임을 위해 모였어요.","level":34,"category":"빈도 학습"},{"id":14142,"term":"clap","meaning":"박수치다; 손뼉 치다","partOfSpeech":"v.","example":"The audience began to clap loudly at the end of the performance.","exampleTranslation":"공연이 끝나자 관객들이 큰 박수를 치기 시작했어요.","level":34,"category":"빈도 학습"},{"id":14143,"term":"clasp","meaning":"꽉 잡다; 걸쇠","partOfSpeech":"v.","example":"She reached out to clasp her mother's hand tightly.","exampleTranslation":"그녀는 어머니의 손을 꽉 잡으려고 손을 뻗었어요.","level":34,"category":"빈도 학습"},{"id":14144,"term":"claw","meaning":"발톱; 발톱으로 할퀴다","partOfSpeech":"n.","example":"The eagle used its claw to grip the branch firmly.","exampleTranslation":"독수리는 발톱으로 나뭇가지를 단단히 붙잡았어요.","level":34,"category":"빈도 학습"},{"id":14145,"term":"cleanse","meaning":"깨끗이 씻다; 정화하다","partOfSpeech":"v.","example":"Use this gentle soap to cleanse your face every morning.","exampleTranslation":"매일 아침 이 순한 비누로 얼굴을 깨끗이 씻으세요.","level":34,"category":"빈도 학습"},{"id":14146,"term":"clench","meaning":"꽉 쥐다; 이를 악물다","partOfSpeech":"v.","example":"He tried to clench his fist to stop his hand from shaking.","exampleTranslation":"그는 손이 떨리지 않도록 주먹을 꽉 쥐려고 했어요.","level":34,"category":"빈도 학습"},{"id":14147,"term":"clergy","meaning":"성직자; 성직자 집단","partOfSpeech":"n.","example":"The clergy gathered in the chapel to discuss community matters.","exampleTranslation":"성직자들은 지역 사안을 논의하기 위해 예배당에 모였어요.","level":34,"category":"빈도 학습"},{"id":14148,"term":"cloak","meaning":"망토; 감추다","partOfSpeech":"n.","example":"The wizard wore a long dark cloak that swept the floor.","exampleTranslation":"마법사는 바닥을 쓸 정도로 긴 검은 망토를 입었어요.","level":34,"category":"빈도 학습"},{"id":14149,"term":"clown","meaning":"광대; 어릿광대","partOfSpeech":"n.","example":"The clown made all the children laugh with funny tricks.","exampleTranslation":"광대는 재미있는 묘기로 아이들 모두를 웃게 만들었어요.","level":34,"category":"빈도 학습"},{"id":14150,"term":"coarse","meaning":"거친; 굵은","partOfSpeech":"adj.","example":"The coarse sandpaper scratched the surface of the old table.","exampleTranslation":"거친 사포가 오래된 탁자 표면을 긁었어요.","level":34,"category":"빈도 학습"},{"id":14151,"term":"cocaine","meaning":"코카인","partOfSpeech":"n.","example":"The police found cocaine hidden inside the luggage at the airport.","exampleTranslation":"경찰은 공항에서 수하물 안에 숨겨진 코카인을 발견했어요.","level":34,"category":"빈도 학습"},{"id":14152,"term":"cocktail","meaning":"칵테일; 혼합물","partOfSpeech":"n.","example":"She ordered a refreshing cocktail at the rooftop bar.","exampleTranslation":"그녀는 옥상 바에서 상쾌한 칵테일을 주문했어요.","level":34,"category":"빈도 학습"},{"id":14153,"term":"coefficient","meaning":"계수; 비율","partOfSpeech":"n.","example":"The friction coefficient determines how easily an object slides on a surface.","exampleTranslation":"마찰 계수는 물체가 표면에서 얼마나 쉽게 미끄러지는지를 결정해요.","level":34,"category":"빈도 학습"},{"id":14154,"term":"coerce","meaning":"강요하다; 강제하다","partOfSpeech":"v.","example":"No one should coerce another person into signing a contract.","exampleTranslation":"누구도 다른 사람에게 계약서에 서명하도록 강요해서는 안 돼요.","level":34,"category":"빈도 학습"},{"id":14155,"term":"coil","meaning":"코일; 똬리를 틀다","partOfSpeech":"n.","example":"The snake formed a tight coil on the warm rock.","exampleTranslation":"뱀은 따뜻한 바위 위에서 단단한 똬리를 틀었어요.","level":34,"category":"빈도 학습"},{"id":14156,"term":"coke","meaning":"코크스; 콜라(구어)","partOfSpeech":"n.","example":"The factory burns coke to generate heat for the furnace.","exampleTranslation":"공장은 용광로에 열을 공급하기 위해 코크스를 태워요.","level":34,"category":"빈도 학습"},{"id":14157,"term":"collision","meaning":"충돌; 접촉 사고","partOfSpeech":"n.","example":"The two vehicles were damaged in the collision at the intersection.","exampleTranslation":"두 차량은 교차로에서의 충돌로 손상되었어요.","level":34,"category":"빈도 학습"},{"id":14158,"term":"comb","meaning":"빗; 빗질하다","partOfSpeech":"n.","example":"He always carries a small comb in his shirt pocket.","exampleTranslation":"그는 항상 셔츠 주머니에 작은 빗을 넣고 다녀요.","level":34,"category":"빈도 학습"},{"id":14159,"term":"commemorate","meaning":"기념하다; 추모하다","partOfSpeech":"v.","example":"The city held a ceremony to commemorate the victims of the disaster.","exampleTranslation":"시는 재난 피해자들을 추모하기 위한 행사를 열었어요.","level":34,"category":"빈도 학습"},{"id":14160,"term":"commence","meaning":"시작하다; 개시하다","partOfSpeech":"v.","example":"The meeting will commence at nine o'clock sharp tomorrow morning.","exampleTranslation":"회의는 내일 아침 9시 정각에 시작될 거예요.","level":34,"category":"빈도 학습"},{"id":14161,"term":"commend","meaning":"칭찬하다; 추천하다","partOfSpeech":"v.","example":"The principal wanted to commend the students for their hard work.","exampleTranslation":"교장은 학생들의 노고를 칭찬하고 싶었어요.","level":34,"category":"빈도 학습"},{"id":14162,"term":"commonwealth","meaning":"연방; 공화국","partOfSpeech":"n.","example":"Several nations formed a commonwealth to promote shared economic goals.","exampleTranslation":"여러 나라가 공동의 경제 목표를 증진하기 위해 연방을 구성했어요.","level":34,"category":"빈도 학습"},{"id":14163,"term":"communal","meaning":"공동의; 공용의","partOfSpeech":"adj.","example":"The residents share a communal garden behind their apartment building.","exampleTranslation":"주민들은 아파트 뒤에 있는 공동 정원을 함께 사용해요.","level":34,"category":"빈도 학습"},{"id":14164,"term":"communism","meaning":"공산주의","partOfSpeech":"n.","example":"Students studied the rise and fall of communism in twentieth-century Europe.","exampleTranslation":"학생들은 20세기 유럽에서 공산주의의 흥망성쇠를 공부했어요.","level":34,"category":"빈도 학습"},{"id":14165,"term":"compartment","meaning":"칸; 구획","partOfSpeech":"n.","example":"She placed her passport in the small compartment of her bag.","exampleTranslation":"그녀는 가방의 작은 칸에 여권을 넣었어요.","level":34,"category":"빈도 학습"},{"id":14166,"term":"compassion","meaning":"연민; 동정심","partOfSpeech":"n.","example":"The nurse showed great compassion toward every patient in the ward.","exampleTranslation":"간호사는 병동의 모든 환자에게 큰 연민을 보여줬어요.","level":34,"category":"빈도 학습"},{"id":14167,"term":"compliment","meaning":"칭찬; 칭찬하다","partOfSpeech":"n.","example":"He gave her a sincere compliment about her presentation skills.","exampleTranslation":"그는 그녀의 발표 실력에 대해 진심 어린 칭찬을 했어요.","level":34,"category":"빈도 학습"},{"id":14168,"term":"composite","meaning":"합성의; 복합물","partOfSpeech":"adj.","example":"The engineer used a composite material to build a lighter aircraft frame.","exampleTranslation":"엔지니어는 더 가벼운 항공기 골격을 만들기 위해 합성 소재를 사용했어요.","level":34,"category":"빈도 학습"},{"id":14169,"term":"compost","meaning":"퇴비; 퇴비로 만들다","partOfSpeech":"n.","example":"She adds kitchen scraps to the compost bin every day.","exampleTranslation":"그녀는 매일 주방 쓰레기를 퇴비통에 넣어요.","level":34,"category":"빈도 학습"},{"id":14170,"term":"comrade","meaning":"동지; 전우","partOfSpeech":"n.","example":"He fought side by side with his comrade during the long battle.","exampleTranslation":"그는 긴 전투 동안 전우와 나란히 싸웠어요.","level":34,"category":"빈도 학습"},{"id":14171,"term":"conclusive","meaning":"결정적인; 확실한","partOfSpeech":"adj.","example":"The DNA test provided conclusive evidence that he was innocent.","exampleTranslation":"DNA 검사는 그가 무고하다는 결정적인 증거를 제공했어요.","level":34,"category":"빈도 학습"},{"id":14172,"term":"condense","meaning":"압축하다; 요약하다","partOfSpeech":"v.","example":"Please condense your report into a single page for the meeting.","exampleTranslation":"회의를 위해 보고서를 한 페이지로 압축해 주세요.","level":34,"category":"빈도 학습"},{"id":14173,"term":"cone","meaning":"원뿔; 솔방울","partOfSpeech":"n.","example":"The traffic cone was placed at the center of the road to warn drivers.","exampleTranslation":"운전자에게 경고하기 위해 도로 한가운데에 원뿔 표지가 놓였어요.","level":34,"category":"빈도 학습"},{"id":14174,"term":"confederate","meaning":"연합한; 동맹자","partOfSpeech":"adj.","example":"The confederate states agreed to share military resources during the conflict.","exampleTranslation":"연합 주들은 분쟁 중 군사 자원을 공유하기로 합의했어요.","level":34,"category":"빈도 학습"},{"id":14175,"term":"confide","meaning":"털어놓다; 비밀을 말하다","partOfSpeech":"v.","example":"She felt safe enough to confide her secret to her best friend.","exampleTranslation":"그녀는 가장 친한 친구에게 비밀을 털어놓을 만큼 안심했어요.","level":34,"category":"빈도 학습"},{"id":14176,"term":"congest","meaning":"혼잡하게 하다; 막히게 하다","partOfSpeech":"v.","example":"Heavy rainfall can congest the drainage system in old city areas.","exampleTranslation":"폭우는 오래된 도심 지역의 배수 시스템을 막히게 할 수 있어요.","level":34,"category":"빈도 학습"},{"id":14177,"term":"conquer","meaning":"정복하다; 극복하다","partOfSpeech":"v.","example":"The army managed to conquer the enemy territory after months of fighting.","exampleTranslation":"군대는 몇 달간의 전투 끝에 적의 영토를 정복하는 데 성공했어요.","level":34,"category":"빈도 학습"},{"id":14178,"term":"consecutive","meaning":"연속적인; 잇따른","partOfSpeech":"adj.","example":"The team won five consecutive matches without a single defeat.","exampleTranslation":"그 팀은 단 한 번도 지지 않고 연속으로 다섯 경기를 이겼어요.","level":34,"category":"빈도 학습"},{"id":14179,"term":"consortium","meaning":"컨소시엄; 기업 연합","partOfSpeech":"n.","example":"A consortium of tech firms invested in the new research center.","exampleTranslation":"기술 기업들의 컨소시엄이 새 연구 센터에 투자했어요.","level":34,"category":"빈도 학습"},{"id":14180,"term":"conspicuous","meaning":"눈에 띄는; 뚜렷한","partOfSpeech":"adj.","example":"The bright red jacket made her conspicuous in the crowd.","exampleTranslation":"밝은 빨간 재킷이 군중 속에서 그녀를 눈에 띄게 만들었어요.","level":34,"category":"빈도 학습"},{"id":14181,"term":"convene","meaning":"소집하다; 모이다","partOfSpeech":"v.","example":"The board will convene next Monday to review the annual budget.","exampleTranslation":"이사회는 연간 예산을 검토하기 위해 다음 월요일에 소집될 거예요.","level":34,"category":"빈도 학습"},{"id":14182,"term":"converge","meaning":"수렴하다; 한 점으로 모이다","partOfSpeech":"v.","example":"The two rivers converge just south of the old stone bridge.","exampleTranslation":"두 강은 오래된 돌다리 바로 남쪽에서 합류해요.","level":34,"category":"빈도 학습"},{"id":14183,"term":"conversely","meaning":"반대로; 역으로","partOfSpeech":"adv.","example":"Exercise improves health; conversely, a sedentary lifestyle can cause problems.","exampleTranslation":"운동은 건강을 향상시키며, 반대로 앉아서 생활하는 방식은 문제를 일으킬 수 있어요.","level":34,"category":"빈도 학습"},{"id":14184,"term":"coral","meaning":"산호; 산호색","partOfSpeech":"n.","example":"Divers were amazed by the colorful coral growing on the ocean floor.","exampleTranslation":"잠수부들은 해저에서 자라는 알록달록한 산호에 감탄했어요.","level":34,"category":"빈도 학습"},{"id":14185,"term":"corpse","meaning":"시체; 주검","partOfSpeech":"n.","example":"The detective examined the corpse carefully for any signs of a struggle.","exampleTranslation":"형사는 몸싸움의 흔적이 있는지 시체를 꼼꼼히 살펴봤어요.","level":34,"category":"빈도 학습"},{"id":14186,"term":"cosmetic","meaning":"화장품의; 외관상의","partOfSpeech":"adj.","example":"The repair was purely cosmetic and did not fix the real problem.","exampleTranslation":"그 수리는 순전히 외관상의 것이었고 실제 문제는 해결하지 못했어요.","level":34,"category":"빈도 학습"},{"id":14187,"term":"cozy","meaning":"아늑한; 편안한","partOfSpeech":"adj.","example":"The cabin felt cozy with a fire burning in the fireplace.","exampleTranslation":"벽난로에 불이 타오르며 그 오두막은 아늑하게 느껴졌어요.","level":34,"category":"빈도 학습"},{"id":14188,"term":"courtyard","meaning":"안뜰; 중정","partOfSpeech":"n.","example":"Students gathered in the courtyard during the lunch break.","exampleTranslation":"학생들이 점심시간에 안뜰에 모였어요.","level":34,"category":"빈도 학습"},{"id":14189,"term":"covenant","meaning":"계약; 서약","partOfSpeech":"n.","example":"The two nations signed a covenant to maintain lasting peace.","exampleTranslation":"두 나라는 지속적인 평화를 유지하기 위해 협약을 체결했어요.","level":34,"category":"빈도 학습"},{"id":14190,"term":"cowboy","meaning":"카우보이; 목동","partOfSpeech":"n.","example":"The cowboy rode his horse across the open plains.","exampleTranslation":"카우보이가 탁 트인 평원을 가로질러 말을 탔어요.","level":34,"category":"빈도 학습"},{"id":14191,"term":"crab","meaning":"게; 집게발 동물","partOfSpeech":"n.","example":"A crab scuttled sideways across the wet sand.","exampleTranslation":"게 한 마리가 축축한 모래 위를 옆으로 재빠르게 지나갔어요.","level":34,"category":"빈도 학습"},{"id":14192,"term":"cradle","meaning":"요람; 발상지","partOfSpeech":"n.","example":"The mother gently rocked the cradle to soothe the baby.","exampleTranslation":"어머니가 아기를 달래기 위해 요람을 부드럽게 흔들었어요.","level":34,"category":"빈도 학습"},{"id":14193,"term":"cramp","meaning":"경련; 쥐","partOfSpeech":"n.","example":"He stopped running because a cramp suddenly hit his leg.","exampleTranslation":"그는 갑자기 다리에 경련이 와서 달리기를 멈췄어요.","level":34,"category":"빈도 학습"},{"id":14194,"term":"crane","meaning":"두루미; 기중기","partOfSpeech":"n.","example":"A large crane lifted the steel beams to the top floor.","exampleTranslation":"대형 기중기가 철제 빔을 꼭대기 층으로 들어 올렸어요.","level":34,"category":"빈도 학습"},{"id":14195,"term":"creek","meaning":"개울; 작은 시내","partOfSpeech":"n.","example":"The children played near the creek on a hot summer day.","exampleTranslation":"아이들이 더운 여름날 개울 근처에서 놀았어요.","level":34,"category":"빈도 학습"},{"id":14196,"term":"crest","meaning":"꼭대기; 정상; 문장(紋章)","partOfSpeech":"n.","example":"They reached the crest of the hill just before sunset.","exampleTranslation":"그들은 해가 지기 직전에 언덕 꼭대기에 도달했어요.","level":34,"category":"빈도 학습"},{"id":14197,"term":"cricket","meaning":"크리켓(스포츠); 귀뚜라미","partOfSpeech":"n.","example":"Cricket is the most popular sport in many South Asian countries.","exampleTranslation":"크리켓은 많은 남아시아 국가에서 가장 인기 있는 스포츠예요.","level":34,"category":"빈도 학습"},{"id":14198,"term":"cripple","meaning":"불구로 만들다; 심각하게 손상시키다","partOfSpeech":"v.","example":"Heavy storms can cripple transportation networks for days.","exampleTranslation":"심한 폭풍은 수일 동안 교통망을 심각하게 마비시킬 수 있어요.","level":34,"category":"빈도 학습"},{"id":14199,"term":"crook","meaning":"사기꾼; 악당; 굽은 것","partOfSpeech":"n.","example":"The police arrested the crook after a long investigation.","exampleTranslation":"경찰이 오랜 수사 끝에 그 사기꾼을 체포했어요.","level":34,"category":"빈도 학습"},{"id":14200,"term":"crouch","meaning":"웅크리다; 쭈그리다","partOfSpeech":"v.","example":"The hikers had to crouch to enter the small cave.","exampleTranslation":"등산객들은 좁은 동굴에 들어가기 위해 웅크려야 했어요.","level":34,"category":"빈도 학습"},{"id":14201,"term":"crunch","meaning":"아삭아삭 씹다; 위기; 부족","partOfSpeech":"v.","example":"She loves to crunch on potato chips while watching movies.","exampleTranslation":"그녀는 영화를 보면서 감자칩을 아삭아삭 씹어 먹는 것을 좋아해요.","level":34,"category":"빈도 학습"},{"id":14202,"term":"crusade","meaning":"십자군 전쟁; 개혁 운동","partOfSpeech":"n.","example":"She led a crusade against corruption in local government.","exampleTranslation":"그녀는 지방 정부의 부패에 맞선 개혁 운동을 이끌었어요.","level":34,"category":"빈도 학습"},{"id":14203,"term":"cub","meaning":"새끼 곰; 어린 동물","partOfSpeech":"n.","example":"The bear cub followed its mother closely through the forest.","exampleTranslation":"새끼 곰이 숲속에서 어미를 바짝 따라다녔어요.","level":34,"category":"빈도 학습"},{"id":14204,"term":"cue","meaning":"신호; 단서; 큐대","partOfSpeech":"n.","example":"The director gave the actor a cue to begin the scene.","exampleTranslation":"감독이 배우에게 장면을 시작하라는 신호를 보냈어요.","level":34,"category":"빈도 학습"},{"id":14205,"term":"culminate","meaning":"절정에 달하다; 정점에 이르다","partOfSpeech":"v.","example":"Years of training can culminate in an Olympic gold medal.","exampleTranslation":"수년간의 훈련은 올림픽 금메달이라는 정점에 이를 수 있어요.","level":34,"category":"빈도 학습"},{"id":14206,"term":"cupboard","meaning":"찬장; 수납장","partOfSpeech":"n.","example":"She found an old photo album in the back of the cupboard.","exampleTranslation":"그녀는 찬장 안쪽에서 오래된 앨범을 발견했어요.","level":34,"category":"빈도 학습"},{"id":14207,"term":"curator","meaning":"큐레이터; 박물관 관리자","partOfSpeech":"n.","example":"The curator arranged the paintings carefully for the new exhibition.","exampleTranslation":"큐레이터가 새 전시회를 위해 그림들을 신중하게 배치했어요.","level":34,"category":"빈도 학습"},{"id":14208,"term":"curb","meaning":"억제하다; 도로 연석","partOfSpeech":"v.","example":"The government introduced new laws to curb excessive spending.","exampleTranslation":"정부는 과도한 지출을 억제하기 위해 새로운 법을 도입했어요.","level":34,"category":"빈도 학습"},{"id":14209,"term":"cushion","meaning":"쿠션; 완충재; 충격을 완화하다","partOfSpeech":"n.","example":"She placed a soft cushion on the chair for extra comfort.","exampleTranslation":"그녀는 더 편안하게 앉으려고 의자에 부드러운 쿠션을 놓았어요.","level":34,"category":"빈도 학습"},{"id":14210,"term":"cylinder","meaning":"원기둥; 실린더","partOfSpeech":"n.","example":"The engine has eight pistons moving inside each cylinder.","exampleTranslation":"그 엔진은 각 실린더 안에서 움직이는 여덟 개의 피스톤이 있어요.","level":34,"category":"빈도 학습"},{"id":14211,"term":"dairy","meaning":"유제품; 낙농의","partOfSpeech":"n.","example":"The local dairy delivers fresh milk every morning.","exampleTranslation":"그 지역 낙농장은 매일 아침 신선한 우유를 배달해요.","level":34,"category":"빈도 학습"},{"id":14212,"term":"dale","meaning":"골짜기; 계곡","partOfSpeech":"n.","example":"A quiet stream ran through the dale between the two hills.","exampleTranslation":"두 언덕 사이의 골짜기를 따라 조용한 시냇물이 흘렀어요.","level":34,"category":"빈도 학습"},{"id":14213,"term":"dangle","meaning":"매달리다; 흔들거리다","partOfSpeech":"v.","example":"Keys dangle from the hook near the front door.","exampleTranslation":"현관문 근처 걸이에 열쇠가 매달려 흔들리고 있어요.","level":34,"category":"빈도 학습"},{"id":14214,"term":"dart","meaning":"돌진하다; 다트(게임)","partOfSpeech":"v.","example":"A small fish can dart away quickly when it senses danger.","exampleTranslation":"작은 물고기는 위험을 감지하면 재빠르게 돌진해 도망칠 수 있어요.","level":34,"category":"빈도 학습"},{"id":14215,"term":"daunt","meaning":"겁먹게 하다; 위협하다","partOfSpeech":"v.","example":"A long list of tasks should not daunt a determined person.","exampleTranslation":"긴 할 일 목록도 의지가 강한 사람을 겁먹게 해서는 안 돼요.","level":34,"category":"빈도 학습"},{"id":14216,"term":"dazzle","meaning":"눈을 부시게 하다; 황홀하게 하다","partOfSpeech":"v.","example":"The fireworks display can dazzle the entire crowd every year.","exampleTranslation":"불꽃놀이는 매년 모든 관중의 눈을 황홀하게 할 수 있어요.","level":34,"category":"빈도 학습"},{"id":14217,"term":"debris","meaning":"잔해; 파편","partOfSpeech":"n.","example":"Workers spent days clearing debris from the collapsed building.","exampleTranslation":"작업자들이 붕괴된 건물의 잔해를 치우는 데 며칠을 보냈어요.","level":34,"category":"빈도 학습"},{"id":14218,"term":"deceased","meaning":"고인이 된; 사망한","partOfSpeech":"adj.","example":"The lawyer read the will on behalf of the deceased person.","exampleTranslation":"변호사가 고인을 대신하여 유언장을 낭독했어요.","level":34,"category":"빈도 학습"},{"id":14219,"term":"decree","meaning":"명령; 법령; 포고하다","partOfSpeech":"n.","example":"The king issued a decree to lower taxes for the poor.","exampleTranslation":"왕은 가난한 사람들의 세금을 낮추라는 법령을 내렸어요.","level":34,"category":"빈도 학습"},{"id":14220,"term":"deed","meaning":"행위; 행동; 증서","partOfSpeech":"n.","example":"Every good deed you do can make someone's day brighter.","exampleTranslation":"당신이 하는 모든 선행은 누군가의 하루를 더 밝게 만들 수 있어요.","level":34,"category":"빈도 학습"},{"id":14221,"term":"default","meaning":"기본값; 채무 불이행; 기본으로 설정되다","partOfSpeech":"n.","example":"The system will use the default setting if you make no changes.","exampleTranslation":"변경 사항이 없으면 시스템은 기본값 설정을 사용할 거예요.","level":34,"category":"빈도 학습"},{"id":14222,"term":"definitive","meaning":"결정적인; 최종적인; 확정적인","partOfSpeech":"adj.","example":"The scientist published a definitive study on climate change.","exampleTranslation":"그 과학자는 기후 변화에 관한 결정적인 연구를 발표했어요.","level":34,"category":"빈도 학습"},{"id":14223,"term":"degrade","meaning":"저하시키다; 품위를 떨어뜨리다","partOfSpeech":"v.","example":"Exposure to sunlight can degrade the quality of some materials.","exampleTranslation":"햇빛에 노출되면 일부 소재의 품질이 저하될 수 있어요.","level":34,"category":"빈도 학습"},{"id":14224,"term":"delete","meaning":"삭제하다; 지우다","partOfSpeech":"v.","example":"Please delete any unnecessary files to free up storage space.","exampleTranslation":"저장 공간을 확보하려면 불필요한 파일을 삭제해 주세요.","level":34,"category":"빈도 학습"},{"id":14225,"term":"delta","meaning":"삼각주; 변화량","partOfSpeech":"n.","example":"The Nile delta is one of the largest river deltas in the world.","exampleTranslation":"나일강 삼각주는 세계에서 가장 큰 강 삼각주 중 하나예요.","level":34,"category":"빈도 학습"},{"id":14226,"term":"demise","meaning":"죽음; 소멸; 종말","partOfSpeech":"n.","example":"Poor management led to the demise of the once-famous company.","exampleTranslation":"잘못된 경영이 한때 유명했던 그 회사의 종말을 초래했어요.","level":34,"category":"빈도 학습"},{"id":14227,"term":"demon","meaning":"악마; 귀신","partOfSpeech":"n.","example":"In the story, a brave hero fought the demon to save the village.","exampleTranslation":"그 이야기에서 용감한 영웅이 마을을 구하기 위해 악마와 싸웠어요.","level":34,"category":"빈도 학습"},{"id":14228,"term":"denounce","meaning":"비난하다; 공개적으로 규탄하다","partOfSpeech":"v.","example":"World leaders publicly denounce any act of political violence.","exampleTranslation":"세계 지도자들은 모든 정치적 폭력 행위를 공개적으로 규탄해요.","level":34,"category":"빈도 학습"},{"id":14229,"term":"dentist","meaning":"치과 의사","partOfSpeech":"n.","example":"My dentist recommended brushing teeth after every meal.","exampleTranslation":"내 치과 의사는 매 식사 후 이를 닦으라고 권했어요.","level":34,"category":"빈도 학습"},{"id":14230,"term":"deplete","meaning":"고갈시키다; 소진하다","partOfSpeech":"v.","example":"Overfarming can quickly deplete the nutrients in the soil.","exampleTranslation":"과도한 농업은 토양의 영양분을 빠르게 고갈시킬 수 있어요.","level":34,"category":"빈도 학습"},{"id":14231,"term":"depot","meaning":"창고; 차고; 버스 정류장","partOfSpeech":"n.","example":"All buses return to the depot at the end of each route.","exampleTranslation":"모든 버스는 노선이 끝나면 차고로 돌아와요.","level":34,"category":"빈도 학습"},{"id":14232,"term":"descent","meaning":"하강; 내리막; 혈통","partOfSpeech":"n.","example":"The descent from the mountain was steeper than the climb up.","exampleTranslation":"산에서의 하강은 올라갈 때보다 더 가팔랐어요.","level":34,"category":"빈도 학습"},{"id":14233,"term":"detention","meaning":"구금; 방과 후 남기기","partOfSpeech":"n.","example":"The student received detention for repeatedly breaking school rules.","exampleTranslation":"그 학생은 학교 규칙을 반복적으로 어겨 방과 후 남기기 벌을 받았어요.","level":34,"category":"빈도 학습"},{"id":14234,"term":"deviate","meaning":"벗어나다; 이탈하다","partOfSpeech":"v.","example":"The pilot had to deviate from the original flight path due to a storm.","exampleTranslation":"조종사는 폭풍 때문에 원래 항로에서 이탈해야 했어요.","level":34,"category":"빈도 학습"},{"id":14235,"term":"diagnostic","meaning":"진단의; 진단 검사","partOfSpeech":"adj.","example":"The hospital runs a diagnostic test before starting any treatment.","exampleTranslation":"그 병원은 치료를 시작하기 전에 진단 검사를 실시해요.","level":34,"category":"빈도 학습"},{"id":14236,"term":"dice","meaning":"주사위; 깍둑썰기하다","partOfSpeech":"n.","example":"She rolled the dice and moved her piece forward three spaces.","exampleTranslation":"그녀는 주사위를 굴려 말을 세 칸 앞으로 이동시켰습니다.","level":34,"category":"빈도 학습"},{"id":14237,"term":"diesel","meaning":"디젤; 경유","partOfSpeech":"n.","example":"This truck runs on diesel, not regular gasoline.","exampleTranslation":"이 트럭은 일반 휘발유가 아닌 디젤로 운행됩니다.","level":34,"category":"빈도 학습"},{"id":14238,"term":"differential","meaning":"차등적인; 미분; 차이","partOfSpeech":"adj.","example":"The company applies a differential pay scale based on experience level.","exampleTranslation":"그 회사는 경력 수준에 따라 차등 임금제를 적용합니다.","level":35,"category":"빈도 학습"},{"id":14239,"term":"diffuse","meaning":"확산시키다; 퍼뜨리다; 분산된","partOfSpeech":"v.","example":"Opening the windows helped diffuse the smoke throughout the room.","exampleTranslation":"창문을 열자 연기가 방 전체로 퍼지는 데 도움이 되었습니다.","level":35,"category":"빈도 학습"},{"id":14240,"term":"dilute","meaning":"희석하다; 묽게 하다","partOfSpeech":"v.","example":"You should dilute the cleaning solution with water before using it.","exampleTranslation":"사용하기 전에 세정액을 물로 희석해야 합니다.","level":35,"category":"빈도 학습"},{"id":14241,"term":"dinosaur","meaning":"공룡; 시대에 뒤떨어진 것","partOfSpeech":"n.","example":"The museum displayed a life-size skeleton of a dinosaur in the main hall.","exampleTranslation":"박물관 중앙 홀에는 실물 크기의 공룡 골격이 전시되어 있었습니다.","level":35,"category":"빈도 학습"},{"id":14242,"term":"diocese","meaning":"교구; 주교 관할 구역","partOfSpeech":"n.","example":"The bishop oversees all the churches within his diocese.","exampleTranslation":"주교는 자신의 교구 내 모든 교회를 감독합니다.","level":35,"category":"빈도 학습"},{"id":14243,"term":"diplomacy","meaning":"외교; 외교술","partOfSpeech":"n.","example":"Skilled diplomacy helped the two countries reach a peaceful agreement.","exampleTranslation":"능숙한 외교술 덕분에 두 나라가 평화적인 합의에 도달했습니다.","level":35,"category":"빈도 학습"},{"id":14244,"term":"disapprove","meaning":"반대하다; 못마땅해하다","partOfSpeech":"v.","example":"Her parents disapprove of her decision to drop out of college.","exampleTranslation":"그녀의 부모님은 그녀가 대학을 중퇴하기로 한 결정을 못마땅해합니다.","level":35,"category":"빈도 학습"},{"id":14245,"term":"disarm","meaning":"무장 해제하다; 안심시키다","partOfSpeech":"v.","example":"The officer managed to disarm the suspect without any violence.","exampleTranslation":"경찰관은 폭력 없이 용의자의 무장을 해제하는 데 성공했습니다.","level":35,"category":"빈도 학습"},{"id":14246,"term":"discern","meaning":"식별하다; 파악하다","partOfSpeech":"v.","example":"It was hard to discern the truth from all the conflicting reports.","exampleTranslation":"상충되는 보고들 속에서 진실을 파악하기가 어려웠습니다.","level":35,"category":"빈도 학습"},{"id":14247,"term":"discrepancy","meaning":"불일치; 차이","partOfSpeech":"n.","example":"The auditor found a discrepancy between the two financial reports.","exampleTranslation":"감사자는 두 재무 보고서 사이에서 불일치를 발견했습니다.","level":35,"category":"빈도 학습"},{"id":14248,"term":"disgrace","meaning":"망신; 불명예; 창피를 주다","partOfSpeech":"n.","example":"He felt deep disgrace after making such a public mistake.","exampleTranslation":"그는 그런 공개적인 실수를 저지른 후 깊은 불명예를 느꼈습니다.","level":35,"category":"빈도 학습"},{"id":14249,"term":"disintegrate","meaning":"붕괴하다; 산산이 부서지다","partOfSpeech":"v.","example":"The old wooden bridge began to disintegrate after years of neglect.","exampleTranslation":"오래된 나무 다리는 수년간 방치된 끝에 무너지기 시작했습니다.","level":35,"category":"빈도 학습"},{"id":14250,"term":"dismantle","meaning":"해체하다; 분해하다","partOfSpeech":"v.","example":"Workers were hired to dismantle the old factory before construction began.","exampleTranslation":"공사가 시작되기 전에 오래된 공장을 해체하기 위해 인부들이 고용되었습니다.","level":35,"category":"빈도 학습"},{"id":14251,"term":"dismay","meaning":"당혹감; 낙담시키다","partOfSpeech":"n.","example":"To everyone's dismay, the event was cancelled at the last minute.","exampleTranslation":"모두가 당혹스럽게도 행사가 마지막 순간에 취소되었습니다.","level":35,"category":"빈도 학습"},{"id":14252,"term":"dispense","meaning":"분배하다; 조제하다","partOfSpeech":"v.","example":"The machine can dispense hot coffee in under thirty seconds.","exampleTranslation":"그 기계는 30초 안에 뜨거운 커피를 제공할 수 있습니다.","level":35,"category":"빈도 학습"},{"id":14253,"term":"disposition","meaning":"성향; 기질; 처분","partOfSpeech":"n.","example":"She has a cheerful disposition that makes everyone around her feel welcome.","exampleTranslation":"그녀는 주변 모든 사람들을 편안하게 만드는 밝은 기질을 가지고 있습니다.","level":35,"category":"빈도 학습"},{"id":14254,"term":"dissatisfy","meaning":"불만족시키다; 불만스럽게 하다","partOfSpeech":"v.","example":"Poor customer service tends to dissatisfy even the most loyal shoppers.","exampleTranslation":"불량한 고객 서비스는 가장 충성스러운 구매자조차도 불만스럽게 만드는 경향이 있습니다.","level":35,"category":"빈도 학습"},{"id":14255,"term":"dissent","meaning":"반대 의견; 이의를 제기하다","partOfSpeech":"n.","example":"One member voiced dissent during the vote on the new policy.","exampleTranslation":"새 정책에 대한 투표 중 한 구성원이 반대 의견을 표명했습니다.","level":35,"category":"빈도 학습"},{"id":14256,"term":"ditch","meaning":"도랑; 버리다; 포기하다","partOfSpeech":"n.","example":"The car slid off the road and landed in a ditch filled with water.","exampleTranslation":"차가 도로에서 미끄러져 물이 가득 찬 도랑에 빠졌습니다.","level":35,"category":"빈도 학습"},{"id":14257,"term":"diverge","meaning":"갈라지다; 분기하다","partOfSpeech":"v.","example":"The two paths diverge at the top of the hill.","exampleTranslation":"두 길은 언덕 꼭대기에서 갈라집니다.","level":35,"category":"빈도 학습"},{"id":14258,"term":"diversify","meaning":"다각화하다; 다양화하다","partOfSpeech":"v.","example":"Investors are advised to diversify their portfolio to reduce risk.","exampleTranslation":"투자자들은 위험을 줄이기 위해 포트폴리오를 다각화하도록 권고받습니다.","level":35,"category":"빈도 학습"},{"id":14259,"term":"diversion","meaning":"우회; 전환; 기분 전환","partOfSpeech":"n.","example":"The road was closed, so drivers followed a diversion through the town.","exampleTranslation":"도로가 폐쇄되어 운전자들은 도심을 통과하는 우회 경로를 따랐습니다.","level":35,"category":"빈도 학습"},{"id":14260,"term":"divert","meaning":"우회시키다; 전환하다","partOfSpeech":"v.","example":"The airline had to divert the flight due to bad weather at the destination.","exampleTranslation":"항공사는 목적지의 악천후로 인해 항공편을 우회시켜야 했습니다.","level":35,"category":"빈도 학습"},{"id":14261,"term":"dizzy","meaning":"어지러운; 현기증이 나는","partOfSpeech":"adj.","example":"She felt dizzy after spinning around too many times.","exampleTranslation":"그녀는 너무 많이 빙글빙글 돌고 난 후 어지러움을 느꼈습니다.","level":35,"category":"빈도 학습"},{"id":14262,"term":"dodge","meaning":"피하다; 빠져나가다","partOfSpeech":"v.","example":"He managed to dodge the flying ball just in time.","exampleTranslation":"그는 가까스로 날아오는 공을 간신히 피해냈습니다.","level":35,"category":"빈도 학습"},{"id":14263,"term":"dole","meaning":"실업 급여; 나눠주다","partOfSpeech":"n.","example":"After losing his job, he had to live on the dole for several months.","exampleTranslation":"직장을 잃은 후 그는 몇 달 동안 실업 급여로 생활해야 했습니다.","level":35,"category":"빈도 학습"},{"id":14264,"term":"dominance","meaning":"지배; 우세; 우위","partOfSpeech":"n.","example":"The company established its dominance in the market over two decades.","exampleTranslation":"그 회사는 20년에 걸쳐 시장에서의 지배적 지위를 확립했습니다.","level":35,"category":"빈도 학습"},{"id":14265,"term":"doom","meaning":"파멸; 운명; 죽음","partOfSpeech":"n.","example":"The old legend spoke of doom that would fall on the valley.","exampleTranslation":"오래된 전설은 그 계곡에 닥칠 파멸에 대해 말하고 있었습니다.","level":35,"category":"빈도 학습"},{"id":14266,"term":"drape","meaning":"걸치다; 덮다; 커튼","partOfSpeech":"v.","example":"She decided to drape a blanket over the sofa for a cozy look.","exampleTranslation":"그녀는 아늑한 느낌을 위해 소파 위에 담요를 걸쳐놓기로 했습니다.","level":35,"category":"빈도 학습"},{"id":14267,"term":"drastic","meaning":"급격한; 과감한; 극단적인","partOfSpeech":"adj.","example":"The doctor recommended drastic lifestyle changes to improve his health.","exampleTranslation":"의사는 그의 건강 개선을 위해 과감한 생활 방식 변화를 권고했습니다.","level":35,"category":"빈도 학습"},{"id":14268,"term":"dread","meaning":"두려움; 몹시 무서워하다","partOfSpeech":"n.","example":"She felt a deep sense of dread every time she had to speak in public.","exampleTranslation":"그녀는 공개 발표를 할 때마다 깊은 두려움을 느꼈습니다.","level":35,"category":"빈도 학습"},{"id":14269,"term":"dreadful","meaning":"끔찍한; 지독한","partOfSpeech":"adj.","example":"The dreadful smell from the drains made it impossible to eat outside.","exampleTranslation":"하수구에서 나는 끔찍한 냄새로 인해 밖에서 식사하는 것이 불가능했습니다.","level":35,"category":"빈도 학습"},{"id":14270,"term":"drought","meaning":"가뭄","partOfSpeech":"n.","example":"The severe drought caused crop failures across the entire region.","exampleTranslation":"심각한 가뭄으로 인해 지역 전체에 걸쳐 작물 피해가 발생했습니다.","level":35,"category":"빈도 학습"},{"id":14271,"term":"drunken","meaning":"술 취한; 만취 상태의","partOfSpeech":"adj.","example":"A drunken passenger was removed from the train by security staff.","exampleTranslation":"술 취한 승객이 보안 직원에 의해 기차에서 하차 조치되었습니다.","level":35,"category":"빈도 학습"},{"id":14272,"term":"dub","meaning":"더빙하다; 별명을 붙이다","partOfSpeech":"v.","example":"They decided to dub the foreign film into Korean for local audiences.","exampleTranslation":"그들은 현지 관객을 위해 외국 영화를 한국어로 더빙하기로 결정했습니다.","level":35,"category":"빈도 학습"},{"id":14273,"term":"dubious","meaning":"의심스러운; 미심쩍은","partOfSpeech":"adj.","example":"She was dubious about the salesman's overly generous offer.","exampleTranslation":"그녀는 판매원의 지나치게 관대한 제안에 대해 의심스러웠습니다.","level":35,"category":"빈도 학습"},{"id":14274,"term":"dumb","meaning":"말을 못하는; 어리석은","partOfSpeech":"adj.","example":"He stood dumb with shock when he heard the unexpected news.","exampleTranslation":"그는 예상치 못한 소식을 듣고 충격으로 말을 잃었습니다.","level":35,"category":"빈도 학습"},{"id":14275,"term":"duplicate","meaning":"복사본; 복제하다; 동일한","partOfSpeech":"v.","example":"Please duplicate this document and send a copy to each department.","exampleTranslation":"이 문서를 복사해서 각 부서에 한 부씩 보내주세요.","level":35,"category":"빈도 학습"},{"id":14276,"term":"durable","meaning":"내구성 있는; 오래가는","partOfSpeech":"adj.","example":"These boots are made of durable leather that can last for years.","exampleTranslation":"이 부츠는 수년간 사용할 수 있는 내구성 있는 가죽으로 만들어졌습니다.","level":35,"category":"빈도 학습"},{"id":14277,"term":"dusk","meaning":"황혼; 해질녘","partOfSpeech":"n.","example":"They sat on the porch and watched the sky turn orange at dusk.","exampleTranslation":"그들은 베란다에 앉아 황혼 무렵 하늘이 주황빛으로 물드는 것을 지켜봤습니다.","level":35,"category":"빈도 학습"},{"id":14278,"term":"dwarf","meaning":"난쟁이; 왜소하게 만들다","partOfSpeech":"n.","example":"The new skyscraper will dwarf every other building on that street.","exampleTranslation":"새 고층 빌딩은 그 거리의 다른 모든 건물을 왜소하게 만들 것입니다.","level":35,"category":"빈도 학습"},{"id":14279,"term":"dye","meaning":"염료; 염색하다","partOfSpeech":"n.","example":"She used a natural dye to color the fabric a deep shade of blue.","exampleTranslation":"그녀는 천을 짙은 파란색으로 물들이기 위해 천연 염료를 사용했습니다.","level":35,"category":"빈도 학습"},{"id":14281,"term":"earnest","meaning":"진지한; 성실한","partOfSpeech":"adj.","example":"She made an earnest effort to improve her communication skills.","exampleTranslation":"그녀는 커뮤니케이션 기술을 향상시키기 위해 진지한 노력을 기울였습니다.","level":35,"category":"빈도 학습"},{"id":14282,"term":"earthquake","meaning":"지진","partOfSpeech":"n.","example":"A powerful earthquake struck the coastal city early in the morning.","exampleTranslation":"이른 아침 강력한 지진이 해안 도시를 강타했습니다.","level":35,"category":"빈도 학습"},{"id":14283,"term":"eccentric","meaning":"별난; 괴짜의","partOfSpeech":"adj.","example":"The eccentric professor always wore mismatched socks to class.","exampleTranslation":"그 별난 교수는 항상 짝짝이 양말을 신고 수업에 들어왔습니다.","level":35,"category":"빈도 학습"},{"id":14284,"term":"eclipse","meaning":"일식; 월식; 가리다","partOfSpeech":"n.","example":"Thousands of people gathered outside to watch the solar eclipse.","exampleTranslation":"수천 명의 사람들이 일식을 보기 위해 밖에 모였습니다.","level":35,"category":"빈도 학습"},{"id":14285,"term":"ecology","meaning":"생태학; 생태계","partOfSpeech":"n.","example":"Scientists study ecology to understand how living things interact with their environment.","exampleTranslation":"과학자들은 생물이 환경과 어떻게 상호작용하는지 이해하기 위해 생태학을 연구합니다.","level":35,"category":"빈도 학습"},{"id":14286,"term":"ecstasy","meaning":"황홀감; 극도의 기쁨","partOfSpeech":"n.","example":"She felt pure ecstasy when her favorite band took the stage.","exampleTranslation":"그녀는 좋아하는 밴드가 무대에 오르자 순수한 황홀감을 느꼈다.","level":35,"category":"빈도 학습"},{"id":14287,"term":"efficacy","meaning":"효능; 효과","partOfSpeech":"n.","example":"Researchers tested the efficacy of the new vaccine in clinical trials.","exampleTranslation":"연구자들은 임상시험에서 새 백신의 효능을 검증했다.","level":35,"category":"빈도 학습"},{"id":14288,"term":"elastic","meaning":"탄력 있는; 신축성 있는","partOfSpeech":"adj.","example":"The elastic band stretched easily around the large bundle of papers.","exampleTranslation":"탄력 있는 밴드가 두꺼운 서류 묶음 주위로 쉽게 늘어났다.","level":35,"category":"빈도 학습"},{"id":14289,"term":"electorate","meaning":"유권자; 선거구민","partOfSpeech":"n.","example":"The electorate will decide who leads the country in next month's vote.","exampleTranslation":"유권자들이 다음 달 투표에서 국가를 이끌 사람을 결정할 것이다.","level":35,"category":"빈도 학습"},{"id":14290,"term":"elf","meaning":"요정; 엘프","partOfSpeech":"n.","example":"The child dressed up as an elf for the holiday play at school.","exampleTranslation":"아이는 학교 연극에서 요정 복장을 하고 등장했다.","level":35,"category":"빈도 학습"},{"id":14291,"term":"elicit","meaning":"이끌어 내다; 유발하다","partOfSpeech":"v.","example":"The teacher used open-ended questions to elicit creative answers from students.","exampleTranslation":"선생님은 개방형 질문을 사용해 학생들로부터 창의적인 답변을 이끌어 냈다.","level":35,"category":"빈도 학습"},{"id":14292,"term":"elusive","meaning":"파악하기 어려운; 좀처럼 잡히지 않는","partOfSpeech":"adj.","example":"The solution to that math problem was elusive even for experienced teachers.","exampleTranslation":"그 수학 문제의 해답은 경험 많은 교사들에게도 파악하기 어려웠다.","level":35,"category":"빈도 학습"},{"id":14293,"term":"embark","meaning":"착수하다; 탑승하다","partOfSpeech":"v.","example":"The team decided to embark on a year-long research project together.","exampleTranslation":"팀은 함께 1년간의 연구 프로젝트에 착수하기로 결정했다.","level":35,"category":"빈도 학습"},{"id":14294,"term":"embed","meaning":"끼워 넣다; 심다","partOfSpeech":"v.","example":"You can embed a video directly into your website using a simple code snippet.","exampleTranslation":"간단한 코드 조각을 사용해 동영상을 웹사이트에 직접 끼워 넣을 수 있다.","level":35,"category":"빈도 학습"},{"id":14295,"term":"embroider","meaning":"자수를 놓다; 윤색하다","partOfSpeech":"v.","example":"She learned to embroider colorful flowers onto linen tablecloths.","exampleTranslation":"그녀는 아마포 식탁보에 알록달록한 꽃 자수를 놓는 법을 배웠다.","level":35,"category":"빈도 학습"},{"id":14296,"term":"embryo","meaning":"배아; 태아 초기","partOfSpeech":"n.","example":"Scientists study how an embryo develops during the first weeks after fertilization.","exampleTranslation":"과학자들은 수정 후 첫 몇 주 동안 배아가 어떻게 발달하는지 연구한다.","level":35,"category":"빈도 학습"},{"id":14297,"term":"emigrate","meaning":"이민을 가다; 해외로 이주하다","partOfSpeech":"v.","example":"Many families chose to emigrate to Canada in search of better opportunities.","exampleTranslation":"많은 가족이 더 나은 기회를 찾아 캐나다로 이민을 가기로 선택했다.","level":35,"category":"빈도 학습"},{"id":14298,"term":"empower","meaning":"권한을 주다; 역량을 강화하다","partOfSpeech":"v.","example":"Good leaders empower their team members to make independent decisions.","exampleTranslation":"훌륭한 리더는 팀원들이 독립적인 결정을 내릴 수 있도록 권한을 준다.","level":35,"category":"빈도 학습"},{"id":14299,"term":"encompass","meaning":"포함하다; 아우르다","partOfSpeech":"v.","example":"The new curriculum will encompass science, math, and technology skills.","exampleTranslation":"새 교육과정은 과학, 수학, 기술 역량을 모두 아우를 것이다.","level":35,"category":"빈도 학습"},{"id":14300,"term":"engrave","meaning":"새기다; 조각하다","partOfSpeech":"v.","example":"They decided to engrave their wedding date on the inside of each ring.","exampleTranslation":"그들은 반지 안쪽에 결혼 날짜를 새기기로 했다.","level":35,"category":"빈도 학습"},{"id":14301,"term":"enlist","meaning":"입대하다; 협력을 구하다","partOfSpeech":"v.","example":"He decided to enlist in the army right after finishing high school.","exampleTranslation":"그는 고등학교를 졸업하자마자 군에 입대하기로 결심했다.","level":35,"category":"빈도 학습"},{"id":14302,"term":"inquire","meaning":"문의하다; 조사하다","partOfSpeech":"v.","example":"Please inquire at the front desk if you need any additional information.","exampleTranslation":"추가 정보가 필요하시면 안내 데스크에 문의해 주세요.","level":36,"category":"빈도 학습"},{"id":14303,"term":"ensemble","meaning":"합주단; 앙상블","partOfSpeech":"n.","example":"The string ensemble performed a beautiful piece at the city concert hall.","exampleTranslation":"현악 합주단이 시립 콘서트홀에서 아름다운 곡을 연주했다.","level":35,"category":"빈도 학습"},{"id":14304,"term":"ensue","meaning":"뒤따르다; 결과로 일어나다","partOfSpeech":"v.","example":"A loud argument between the two coaches would ensue after every close call.","exampleTranslation":"아슬아슬한 판정이 있을 때마다 두 감독 사이에 격한 언쟁이 뒤따르곤 했다.","level":35,"category":"빈도 학습"},{"id":14305,"term":"entail","meaning":"수반하다; 필요로 하다","partOfSpeech":"v.","example":"Running a small business can entail long hours and significant personal sacrifice.","exampleTranslation":"소규모 사업을 운영하는 것은 긴 근무 시간과 상당한 개인적 희생을 수반할 수 있다.","level":35,"category":"빈도 학습"},{"id":14306,"term":"enzyme","meaning":"효소","partOfSpeech":"n.","example":"Each enzyme in the body speeds up a specific chemical reaction in the cells.","exampleTranslation":"체내의 각 효소는 세포 내 특정 화학 반응을 촉진한다.","level":35,"category":"빈도 학습"},{"id":14307,"term":"epic","meaning":"서사시; 웅장한","partOfSpeech":"n.","example":"Homer's Odyssey is a famous epic that tells of a long and dangerous journey home.","exampleTranslation":"호메로스의 오디세이는 길고 위험한 귀환 여정을 담은 유명한 서사시다.","level":35,"category":"빈도 학습"},{"id":14308,"term":"epidemic","meaning":"유행병; 전염병 확산","partOfSpeech":"n.","example":"Health officials worked quickly to contain the epidemic before it spread further.","exampleTranslation":"보건 당국은 유행병이 더 퍼지기 전에 억제하기 위해 신속히 움직였다.","level":35,"category":"빈도 학습"},{"id":14309,"term":"equilibrium","meaning":"균형; 평형 상태","partOfSpeech":"n.","example":"The economy gradually returned to equilibrium after the financial crisis ended.","exampleTranslation":"경제는 금융 위기가 끝난 후 서서히 균형을 되찾았다.","level":35,"category":"빈도 학습"},{"id":14310,"term":"erase","meaning":"지우다; 없애다","partOfSpeech":"v.","example":"Please erase the old notes from the whiteboard before the meeting starts.","exampleTranslation":"회의가 시작되기 전에 화이트보드에서 이전 메모를 지워 주세요.","level":35,"category":"빈도 학습"},{"id":14311,"term":"erode","meaning":"침식하다; 서서히 약화시키다","partOfSpeech":"v.","example":"Heavy rain can erode the soil on steep hillsides over time.","exampleTranslation":"폭우는 시간이 지나면서 가파른 언덕의 토양을 침식할 수 있다.","level":35,"category":"빈도 학습"},{"id":14312,"term":"erosion","meaning":"침식; 부식","partOfSpeech":"n.","example":"Coastal erosion is slowly washing away the sandy cliffs near the village.","exampleTranslation":"해안 침식이 마을 근처의 모래 절벽을 서서히 쓸어가고 있다.","level":35,"category":"빈도 학습"},{"id":14313,"term":"escalate","meaning":"확대되다; 격화시키다","partOfSpeech":"v.","example":"A small disagreement can escalate into a serious conflict if left unaddressed.","exampleTranslation":"작은 의견 충돌도 방치하면 심각한 갈등으로 확대될 수 있다.","level":35,"category":"빈도 학습"},{"id":14314,"term":"eternal","meaning":"영원한; 끝없는","partOfSpeech":"adj.","example":"Many poets write about the eternal nature of love and human longing.","exampleTranslation":"많은 시인이 사랑과 인간의 그리움이 지닌 영원한 속성에 대해 쓴다.","level":35,"category":"빈도 학습"},{"id":14315,"term":"evangelical","meaning":"복음주의적인; 복음 전도의","partOfSpeech":"adj.","example":"The evangelical community organized a large charity drive in their neighborhood.","exampleTranslation":"복음주의 공동체는 자신들의 동네에서 대규모 자선 캠페인을 조직했다.","level":35,"category":"빈도 학습"},{"id":14316,"term":"evaporate","meaning":"증발하다; 사라지다","partOfSpeech":"v.","example":"Puddles on the sidewalk evaporate quickly on a hot and sunny afternoon.","exampleTranslation":"보도의 물웅덩이는 덥고 맑은 오후에 빠르게 증발한다.","level":35,"category":"빈도 학습"},{"id":14317,"term":"ex","meaning":"전 연인; 전 배우자","partOfSpeech":"n.","example":"She ran into her ex at the coffee shop and felt a moment of awkwardness.","exampleTranslation":"그녀는 커피숍에서 전 연인과 마주쳐 잠깐 어색함을 느꼈다.","level":35,"category":"빈도 학습"},{"id":14318,"term":"exacerbate","meaning":"악화시키다; 심화시키다","partOfSpeech":"v.","example":"Lack of sleep can exacerbate feelings of stress and anxiety throughout the day.","exampleTranslation":"수면 부족은 하루 종일 스트레스와 불안감을 악화시킬 수 있다.","level":35,"category":"빈도 학습"},{"id":14319,"term":"expanse","meaning":"광활한 공간; 넓은 지역","partOfSpeech":"n.","example":"The hikers stood in awe before the vast expanse of the desert stretching ahead.","exampleTranslation":"등산객들은 앞에 펼쳐진 광활한 사막의 넓은 지역 앞에 경외감을 느끼며 섰다.","level":35,"category":"빈도 학습"},{"id":14320,"term":"expel","meaning":"퇴학시키다; 추방하다","partOfSpeech":"v.","example":"The school decided to expel the student for repeated acts of serious misconduct.","exampleTranslation":"학교는 반복적인 심각한 비행을 이유로 그 학생을 퇴학시키기로 결정했다.","level":35,"category":"빈도 학습"},{"id":14321,"term":"expire","meaning":"만료되다; 유효 기간이 끝나다","partOfSpeech":"v.","example":"Check that your passport does not expire before your scheduled travel date.","exampleTranslation":"예정된 여행 날짜 전에 여권이 만료되지 않는지 확인하세요.","level":35,"category":"빈도 학습"},{"id":14322,"term":"exquisite","meaning":"정교한; 매우 아름다운","partOfSpeech":"adj.","example":"The jeweler crafted an exquisite necklace with tiny hand-set gemstones.","exampleTranslation":"보석상은 작은 보석들을 손으로 하나하나 세팅한 정교한 목걸이를 만들었다.","level":35,"category":"빈도 학습"},{"id":14323,"term":"exterior","meaning":"외부; 외관","partOfSpeech":"n.","example":"Workers repainted the exterior of the old building to improve its appearance.","exampleTranslation":"작업자들은 낡은 건물의 외관을 개선하기 위해 외부를 다시 칠했다.","level":35,"category":"빈도 학습"},{"id":14324,"term":"extinct","meaning":"멸종된; 사라진","partOfSpeech":"adj.","example":"The dodo is an extinct bird that once lived on the island of Mauritius.","exampleTranslation":"도도새는 한때 모리셔스 섬에 살았던 멸종된 새다.","level":35,"category":"빈도 학습"},{"id":14325,"term":"fabulous","meaning":"멋진; 엄청난","partOfSpeech":"adj.","example":"The audience gave a fabulous response to the opening night performance.","exampleTranslation":"관객들은 개막 공연에 멋진 반응을 보여 주었다.","level":35,"category":"빈도 학습"},{"id":14326,"term":"facial","meaning":"얼굴의; 안면","partOfSpeech":"adj.","example":"The doctor studied her facial expressions to assess the pain level accurately.","exampleTranslation":"의사는 통증 수준을 정확히 평가하기 위해 그녀의 얼굴 표정을 살폈다.","level":35,"category":"빈도 학습"},{"id":14327,"term":"factual","meaning":"사실에 근거한; 사실적인","partOfSpeech":"adj.","example":"A good news report should be factual and free from personal bias.","exampleTranslation":"좋은 뉴스 보도는 사실에 근거하고 개인적인 편견이 없어야 한다.","level":35,"category":"빈도 학습"},{"id":14328,"term":"farewell","meaning":"작별 인사; 이별","partOfSpeech":"n.","example":"Colleagues gathered in the break room to say farewell to the retiring manager.","exampleTranslation":"동료들이 은퇴하는 관리자에게 작별 인사를 하기 위해 휴게실에 모였다.","level":35,"category":"빈도 학습"},{"id":14329,"term":"fasten","meaning":"고정하다; 잠그다","partOfSpeech":"v.","example":"Always fasten your seatbelt before the car starts moving on the road.","exampleTranslation":"차가 도로에서 움직이기 전에 항상 안전벨트를 고정하세요.","level":35,"category":"빈도 학습"},{"id":14330,"term":"fatigue","meaning":"피로; 피곤함","partOfSpeech":"n.","example":"Chronic fatigue can affect your ability to concentrate during the workday.","exampleTranslation":"만성 피로는 근무 중 집중력에 영향을 미칠 수 있다.","level":35,"category":"빈도 학습"},{"id":14331,"term":"feasible","meaning":"실현 가능한; 가능한","partOfSpeech":"adj.","example":"The engineer confirmed that the new design was technically feasible within budget.","exampleTranslation":"엔지니어는 새 설계가 예산 내에서 기술적으로 실현 가능하다고 확인했다.","level":35,"category":"빈도 학습"},{"id":14332,"term":"feast","meaning":"잔치; 성대한 식사","partOfSpeech":"n.","example":"The family prepared a feast with dozens of dishes for the holiday celebration.","exampleTranslation":"가족은 명절 기념을 위해 수십 가지 음식으로 잔치를 준비했다.","level":35,"category":"빈도 학습"},{"id":14333,"term":"fend","meaning":"막다; 스스로 해나가다","partOfSpeech":"v.","example":"Young adults must learn to fend for themselves when they move out of home.","exampleTranslation":"젊은 성인들은 독립할 때 스스로 해나가는 법을 배워야 한다.","level":35,"category":"빈도 학습"},{"id":14334,"term":"festive","meaning":"축제 분위기의; 명절의","partOfSpeech":"adj.","example":"The streets were decorated with colorful lights to create a festive atmosphere.","exampleTranslation":"거리는 축제 분위기를 연출하기 위해 형형색색의 조명으로 장식되었다.","level":35,"category":"빈도 학습"},{"id":14335,"term":"fiddle","meaning":"바이올린; 만지작거리다","partOfSpeech":"n.","example":"He played a lively tune on his fiddle at the country music festival.","exampleTranslation":"그는 컨트리 음악 축제에서 바이올린으로 경쾌한 곡을 연주했다.","level":35,"category":"빈도 학습"},{"id":14336,"term":"filth","meaning":"오물; 더러운 것; 음란물","partOfSpeech":"n.","example":"The workers cleaned up the filth that had accumulated in the old warehouse.","exampleTranslation":"작업자들은 낡은 창고에 쌓인 오물을 청소했습니다.","level":35,"category":"빈도 학습"},{"id":14337,"term":"fixture","meaning":"고정 장치; 비품; 정기 행사","partOfSpeech":"n.","example":"The plumber came to replace a broken fixture in the bathroom.","exampleTranslation":"배관공이 욕실의 고장난 비품을 교체하러 왔습니다.","level":35,"category":"빈도 학습"},{"id":14338,"term":"flake","meaning":"조각; 벗겨지다; 약속을 어기다","partOfSpeech":"n.","example":"A small flake of paint fell from the old wall when I touched it.","exampleTranslation":"내가 만지자 오래된 벽에서 페인트 조각이 떨어졌습니다.","level":35,"category":"빈도 학습"},{"id":14339,"term":"flare","meaning":"불꽃; 타오르다; 격화되다","partOfSpeech":"n.","example":"The rescue team used a flare to signal their location in the dark.","exampleTranslation":"구조대는 어둠 속에서 자신들의 위치를 알리기 위해 조명탄을 사용했습니다.","level":35,"category":"빈도 학습"},{"id":14340,"term":"flatter","meaning":"아첨하다; 돋보이게 하다","partOfSpeech":"v.","example":"He tried to flatter his boss with compliments, but she saw through it.","exampleTranslation":"그는 칭찬으로 상사에게 아첨하려 했지만 상사는 꿰뚫어 봤습니다.","level":35,"category":"빈도 학습"},{"id":14341,"term":"flop","meaning":"털썩 쓰러지다; 실패하다; 실패작","partOfSpeech":"v.","example":"After the long hike, he was so tired that he just had to flop onto the couch.","exampleTranslation":"긴 하이킹 후 그는 너무 지쳐서 소파에 털썩 쓰러졌습니다.","level":35,"category":"빈도 학습"},{"id":14342,"term":"fluctuate","meaning":"변동하다; 오르내리다","partOfSpeech":"v.","example":"Prices tend to fluctuate depending on supply and demand in the market.","exampleTranslation":"가격은 시장의 수요와 공급에 따라 변동하는 경향이 있습니다.","level":35,"category":"빈도 학습"},{"id":14343,"term":"flutter","meaning":"펄럭이다; 두근거리다; 설레임","partOfSpeech":"v.","example":"The flags began to flutter in the strong breeze outside the stadium.","exampleTranslation":"경기장 밖에서 강한 바람에 깃발들이 펄럭이기 시작했습니다.","level":35,"category":"빈도 학습"},{"id":14344,"term":"foam","meaning":"거품; 폼 소재","partOfSpeech":"n.","example":"She topped her coffee with a thick layer of warm foam.","exampleTranslation":"그녀는 커피 위에 따뜻한 거품을 두툼하게 올렸습니다.","level":35,"category":"빈도 학습"},{"id":14345,"term":"foil","meaning":"막다; 알루미늄 호일; 대조물","partOfSpeech":"v.","example":"The security guard was able to foil the attempted theft in the store.","exampleTranslation":"경비원이 매장에서 시도된 절도를 막을 수 있었습니다.","level":35,"category":"빈도 학습"},{"id":14346,"term":"foliage","meaning":"잎사귀; 나뭇잎","partOfSpeech":"n.","example":"The autumn foliage turned brilliant shades of red and orange in October.","exampleTranslation":"10월에 가을 나뭇잎이 빨간색과 주황색의 화려한 색조로 물들었습니다.","level":36,"category":"빈도 학습"},{"id":14347,"term":"formidable","meaning":"강력한; 만만치 않은; 무서운","partOfSpeech":"adj.","example":"The team faced a formidable opponent in the championship finals.","exampleTranslation":"팀은 챔피언십 결승에서 강력한 상대를 만났습니다.","level":36,"category":"빈도 학습"},{"id":14348,"term":"forthcoming","meaning":"곧 나올; 솔직한; 기꺼이 도와주는","partOfSpeech":"adj.","example":"Details about the forthcoming product launch will be announced next week.","exampleTranslation":"곧 있을 제품 출시에 관한 세부 사항은 다음 주에 발표될 예정입니다.","level":36,"category":"빈도 학습"},{"id":14349,"term":"fountain","meaning":"분수; 샘","partOfSpeech":"n.","example":"Children threw coins into the fountain and made a wish.","exampleTranslation":"아이들은 분수에 동전을 던지며 소원을 빌었습니다.","level":36,"category":"빈도 학습"},{"id":14350,"term":"fragrant","meaning":"향기로운; 향긋한","partOfSpeech":"adj.","example":"The garden was filled with fragrant roses in full bloom.","exampleTranslation":"정원은 활짝 핀 향기로운 장미로 가득했습니다.","level":36,"category":"빈도 학습"},{"id":14351,"term":"frantic","meaning":"미칠 듯이 바쁜; 필사적인","partOfSpeech":"adj.","example":"She made a frantic search through her bag for the missing keys.","exampleTranslation":"그녀는 없어진 열쇠를 찾기 위해 가방을 미칠 듯이 뒤졌습니다.","level":36,"category":"빈도 학습"},{"id":14352,"term":"freight","meaning":"화물; 화물 운송","partOfSpeech":"n.","example":"The freight arrived at the warehouse two days later than expected.","exampleTranslation":"화물은 예상보다 이틀 늦게 창고에 도착했습니다.","level":36,"category":"빈도 학습"},{"id":14353,"term":"fume","meaning":"연기; 가스; 화가 나다","partOfSpeech":"n.","example":"Workers were warned not to breathe in the toxic fume from the chemicals.","exampleTranslation":"작업자들은 화학약품에서 나오는 유독 가스를 들이마시지 말라는 경고를 받았습니다.","level":36,"category":"빈도 학습"},{"id":14354,"term":"fungus","meaning":"균류; 곰팡이","partOfSpeech":"n.","example":"A type of fungus was growing on the damp wall of the basement.","exampleTranslation":"지하실의 습한 벽에 곰팡이의 일종이 자라고 있었습니다.","level":36,"category":"빈도 학습"},{"id":14355,"term":"fury","meaning":"격노; 맹렬함","partOfSpeech":"n.","example":"He struggled to contain his fury after hearing the unfair decision.","exampleTranslation":"그는 불공평한 결정을 듣고 분노를 억누르려 애썼습니다.","level":36,"category":"빈도 학습"},{"id":14356,"term":"fuss","meaning":"야단법석; 쓸데없이 걱정하다","partOfSpeech":"n.","example":"He made such a fuss about the small delay that everyone felt uncomfortable.","exampleTranslation":"그는 사소한 지연에 대해 야단법석을 떨어 모두가 불편해했습니다.","level":36,"category":"빈도 학습"},{"id":14357,"term":"garment","meaning":"의복; 옷","partOfSpeech":"n.","example":"Each garment in the collection was handmade by local artisans.","exampleTranslation":"컬렉션의 각 의복은 지역 장인들이 손으로 만들었습니다.","level":36,"category":"빈도 학습"},{"id":14358,"term":"gel","meaning":"젤; 굳어지다; 잘 맞다","partOfSpeech":"n.","example":"He applied a small amount of gel to keep his hair in place.","exampleTranslation":"그는 머리를 정돈하기 위해 소량의 젤을 발랐습니다.","level":36,"category":"빈도 학습"},{"id":14359,"term":"generator","meaning":"발전기; 생성 장치","partOfSpeech":"n.","example":"The hospital has a backup generator in case of a power outage.","exampleTranslation":"병원에는 정전에 대비한 예비 발전기가 있습니다.","level":36,"category":"빈도 학습"},{"id":14360,"term":"gig","meaning":"공연; 단기 일자리","partOfSpeech":"n.","example":"The band played their first gig at a small club downtown.","exampleTranslation":"그 밴드는 시내의 작은 클럽에서 첫 공연을 했습니다.","level":36,"category":"빈도 학습"},{"id":14361,"term":"giggle","meaning":"킥킥 웃다; 낄낄거림","partOfSpeech":"v.","example":"The children began to giggle when the clown made a funny face.","exampleTranslation":"광대가 웃긴 표정을 짓자 아이들이 킥킥 웃기 시작했습니다.","level":36,"category":"빈도 학습"},{"id":14362,"term":"ginger","meaning":"생강; 붉은 머리색","partOfSpeech":"n.","example":"She added fresh ginger to the soup to give it a warm, spicy flavor.","exampleTranslation":"그녀는 국에 따뜻하고 매콤한 맛을 더하기 위해 신선한 생강을 넣었습니다.","level":36,"category":"빈도 학습"},{"id":14363,"term":"glaze","meaning":"유약; 유리를 끼우다; 눈이 흐려지다","partOfSpeech":"n.","example":"The baker brushed a sweet glaze over the freshly baked pastries.","exampleTranslation":"제빵사는 갓 구운 페이스트리에 달콤한 유약을 발랐습니다.","level":36,"category":"빈도 학습"},{"id":14364,"term":"glitter","meaning":"반짝이다; 반짝이는 장식 가루","partOfSpeech":"v.","example":"The children used glitter to decorate their handmade greeting cards.","exampleTranslation":"아이들은 손으로 만든 인사 카드를 꾸미기 위해 반짝이를 사용했습니다.","level":36,"category":"빈도 학습"},{"id":14365,"term":"globe","meaning":"지구; 구체; 세계","partOfSpeech":"n.","example":"She spun the globe and pointed to where she wanted to travel next.","exampleTranslation":"그녀는 지구본을 돌려 다음에 여행하고 싶은 곳을 가리켰습니다.","level":36,"category":"빈도 학습"},{"id":14366,"term":"goose","meaning":"거위","partOfSpeech":"n.","example":"A goose wandered onto the path and blocked our way in the park.","exampleTranslation":"공원에서 거위 한 마리가 길로 들어와 우리 앞을 가로막았습니다.","level":36,"category":"빈도 학습"},{"id":14367,"term":"gown","meaning":"가운; 드레스; 예복","partOfSpeech":"n.","example":"She wore an elegant gown to the annual charity dinner.","exampleTranslation":"그녀는 연례 자선 만찬에 우아한 드레스를 입었습니다.","level":36,"category":"빈도 학습"},{"id":14368,"term":"gram","meaning":"그램","partOfSpeech":"n.","example":"The recipe calls for exactly fifty gram of butter.","exampleTranslation":"그 레시피는 정확히 버터 50그램을 필요로 합니다.","level":36,"category":"빈도 학습"},{"id":14369,"term":"grape","meaning":"포도","partOfSpeech":"n.","example":"She bought a bunch of grape at the farmers market on Saturday.","exampleTranslation":"그녀는 토요일에 농산물 직판장에서 포도 한 송이를 샀습니다.","level":36,"category":"빈도 학습"},{"id":14370,"term":"grate","meaning":"갈다; 삐걱거리다; 화나게 하다","partOfSpeech":"v.","example":"Could you grate some cheese on top of the pasta, please?","exampleTranslation":"파스타 위에 치즈를 좀 갈아 주시겠어요?","level":36,"category":"빈도 학습"},{"id":14371,"term":"gratitude","meaning":"감사; 고마움","partOfSpeech":"n.","example":"She expressed her gratitude by writing a heartfelt thank-you note.","exampleTranslation":"그녀는 진심 어린 감사 편지를 써서 감사함을 표현했습니다.","level":36,"category":"빈도 학습"},{"id":14372,"term":"grit","meaning":"모래; 끈기; 이를 악물다","partOfSpeech":"n.","example":"It takes real grit to keep training every day despite the pain.","exampleTranslation":"통증에도 불구하고 매일 훈련을 계속하려면 진정한 끈기가 필요합니다.","level":36,"category":"빈도 학습"},{"id":14373,"term":"groan","meaning":"신음하다; 불평하다; 신음소리","partOfSpeech":"v.","example":"He let out a loud groan when he realized he had missed the last bus.","exampleTranslation":"그는 마지막 버스를 놓쳤다는 것을 알았을 때 크게 신음했습니다.","level":36,"category":"빈도 학습"},{"id":14374,"term":"groom","meaning":"손질하다; 신랑; 마부","partOfSpeech":"v.","example":"She took her dog to the pet salon to groom it before the competition.","exampleTranslation":"그녀는 대회 전에 개를 손질하기 위해 애완동물 미용실에 데려갔습니다.","level":36,"category":"빈도 학습"},{"id":14375,"term":"grove","meaning":"작은 숲; 과수원","partOfSpeech":"n.","example":"We had a picnic in a shady grove near the edge of the forest.","exampleTranslation":"우리는 숲 가장자리 근처의 그늘진 작은 숲에서 소풍을 즐겼습니다.","level":36,"category":"빈도 학습"},{"id":14376,"term":"growl","meaning":"으르렁거리다; 으르렁거리는 소리","partOfSpeech":"v.","example":"The dog began to growl when a stranger approached the front gate.","exampleTranslation":"낯선 사람이 정문에 가까이 오자 개가 으르렁거리기 시작했습니다.","level":36,"category":"빈도 학습"},{"id":14377,"term":"grunt","meaning":"꿀꿀 소리; 투덜거리다","partOfSpeech":"v.","example":"He gave a short grunt in response and went back to reading his book.","exampleTranslation":"그는 짧게 투덜거리며 대답하고 다시 책 읽기로 돌아갔습니다.","level":36,"category":"빈도 학습"},{"id":14378,"term":"guild","meaning":"조합; 길드","partOfSpeech":"n.","example":"The local guild of craftsmen held its annual meeting in the town hall.","exampleTranslation":"지역 장인 조합은 시청에서 연례 회의를 열었습니다.","level":36,"category":"빈도 학습"},{"id":14379,"term":"gum","meaning":"잇몸; 껌","partOfSpeech":"n.","example":"The dentist advised her to brush her gum carefully to prevent disease.","exampleTranslation":"치과 의사는 질병을 예방하기 위해 잇몸을 꼼꼼히 닦으라고 조언했습니다.","level":36,"category":"빈도 학습"},{"id":14380,"term":"gymnasium","meaning":"체육관","partOfSpeech":"n.","example":"The school built a new gymnasium for physical education classes.","exampleTranslation":"학교는 체육 수업을 위해 새 체육관을 지었습니다.","level":36,"category":"빈도 학습"},{"id":14381,"term":"hack","meaning":"해킹하다; 자르다; 임시방편","partOfSpeech":"v.","example":"Someone tried to hack into the company's computer system last night.","exampleTranslation":"누군가 어젯밤 회사의 컴퓨터 시스템에 해킹을 시도했습니다.","level":36,"category":"빈도 학습"},{"id":14382,"term":"hail","meaning":"우박; 환영하다; 부르다","partOfSpeech":"n.","example":"The hail was so heavy that it left dents on several parked cars.","exampleTranslation":"우박이 너무 강해 주차된 여러 차량에 흠집을 남겼습니다.","level":36,"category":"빈도 학습"},{"id":14383,"term":"ham","meaning":"햄; 허벅지","partOfSpeech":"n.","example":"She made a sandwich with sliced ham and fresh vegetables for lunch.","exampleTranslation":"그녀는 점심으로 얇게 썬 햄과 신선한 채소로 샌드위치를 만들었습니다.","level":36,"category":"빈도 학습"},{"id":14384,"term":"hamburger","meaning":"햄버거","partOfSpeech":"n.","example":"He ordered a hamburger and a large soda at the fast food counter.","exampleTranslation":"그는 패스트푸드 카운터에서 햄버거와 큰 사이즈 음료를 주문했습니다.","level":36,"category":"빈도 학습"},{"id":14385,"term":"handkerchief","meaning":"손수건","partOfSpeech":"n.","example":"She pulled out a handkerchief from her pocket to wipe her tears.","exampleTranslation":"그녀는 눈물을 닦기 위해 주머니에서 손수건을 꺼냈습니다.","level":36,"category":"빈도 학습"},{"id":14386,"term":"harness","meaning":"활용하다; 마구(馬具); 안전 벨트","partOfSpeech":"v.","example":"We need to harness solar energy to reduce our electricity bills.","exampleTranslation":"전기 요금을 줄이기 위해 태양 에너지를 활용해야 합니다.","level":36,"category":"빈도 학습"},{"id":14387,"term":"hatred","meaning":"증오; 혐오","partOfSpeech":"n.","example":"The campaign aimed to reduce hatred and promote mutual respect.","exampleTranslation":"그 캠페인은 증오를 줄이고 상호 존중을 촉진하는 것을 목표로 했습니다.","level":36,"category":"빈도 학습"},{"id":14388,"term":"hawk","meaning":"매; 강경파","partOfSpeech":"n.","example":"A hawk circled high above the field looking for prey.","exampleTranslation":"매 한 마리가 먹이를 찾아 들판 위 높이 선회했습니다.","level":36,"category":"빈도 학습"},{"id":14389,"term":"hay","meaning":"건초; 마른 풀","partOfSpeech":"n.","example":"The farmer stored hay in the barn to feed the animals in winter.","exampleTranslation":"농부는 겨울에 동물들에게 먹이를 주기 위해 헛간에 건초를 저장했습니다.","level":36,"category":"빈도 학습"},{"id":14390,"term":"heave","meaning":"힘껏 들어올리다; 내던지다","partOfSpeech":"v.","example":"The workers had to heave the heavy crate onto the truck.","exampleTranslation":"작업자들은 무거운 상자를 트럭 위로 힘껏 들어올려야 했습니다.","level":36,"category":"빈도 학습"},{"id":14391,"term":"heighten","meaning":"높이다; 강화하다","partOfSpeech":"v.","example":"The news report helped heighten public awareness of the issue.","exampleTranslation":"그 뉴스 보도는 그 문제에 대한 대중의 인식을 높이는 데 도움이 되었습니다.","level":36,"category":"빈도 학습"},{"id":14392,"term":"hemisphere","meaning":"반구; 반구체","partOfSpeech":"n.","example":"Australia is located in the southern hemisphere of the Earth.","exampleTranslation":"호주는 지구의 남반구에 위치해 있습니다.","level":36,"category":"빈도 학습"},{"id":14393,"term":"hen","meaning":"암탉","partOfSpeech":"n.","example":"The hen laid three eggs in the nest this morning.","exampleTranslation":"그 암탉은 오늘 아침 둥지에 알을 세 개 낳았습니다.","level":36,"category":"빈도 학습"},{"id":14394,"term":"herald","meaning":"예고하다; 전령","partOfSpeech":"v.","example":"The blooming flowers herald the arrival of spring.","exampleTranslation":"꽃이 피는 것은 봄의 도래를 예고합니다.","level":36,"category":"빈도 학습"},{"id":14395,"term":"heroin","meaning":"헤로인(마약)","partOfSpeech":"n.","example":"The police seized a large quantity of heroin at the border.","exampleTranslation":"경찰은 국경에서 대량의 헤로인을 압수했습니다.","level":36,"category":"빈도 학습"},{"id":14396,"term":"heterosexual","meaning":"이성애자; 이성애의","partOfSpeech":"adj.","example":"The study included both heterosexual and same-sex couples.","exampleTranslation":"그 연구에는 이성애 커플과 동성 커플이 모두 포함되었습니다.","level":36,"category":"빈도 학습"},{"id":14397,"term":"highland","meaning":"고지대; 고원 지방","partOfSpeech":"n.","example":"The highland region is known for its cool climate and scenic views.","exampleTranslation":"그 고지대는 시원한 기후와 아름다운 경치로 유명합니다.","level":36,"category":"빈도 학습"},{"id":14398,"term":"hike","meaning":"하이킹하다; 가격을 올리다; 도보 여행","partOfSpeech":"v.","example":"We plan to hike up the mountain trail early tomorrow morning.","exampleTranslation":"우리는 내일 아침 일찍 산길을 하이킹할 계획입니다.","level":36,"category":"빈도 학습"},{"id":14399,"term":"hinder","meaning":"방해하다; 저해하다","partOfSpeech":"v.","example":"Bad weather can hinder rescue operations in the mountains.","exampleTranslation":"악천후는 산악 구조 작업을 방해할 수 있습니다.","level":36,"category":"빈도 학습"},{"id":14400,"term":"hinge","meaning":"경첩; ~에 달려 있다","partOfSpeech":"n.","example":"The gate would not close properly because one hinge was broken.","exampleTranslation":"경첩 하나가 부러져 있어 문이 제대로 닫히지 않았습니다.","level":36,"category":"빈도 학습"},{"id":14401,"term":"hiss","meaning":"쉿 소리를 내다; 쉿 소리","partOfSpeech":"v.","example":"The cat began to hiss when the dog came too close.","exampleTranslation":"강아지가 너무 가까이 다가오자 고양이가 쉿 소리를 내기 시작했습니다.","level":36,"category":"빈도 학습"},{"id":14402,"term":"hockey","meaning":"하키","partOfSpeech":"n.","example":"My son joined the school hockey team and practices every afternoon.","exampleTranslation":"제 아들은 학교 하키 팀에 들어가 매일 오후 연습합니다.","level":36,"category":"빈도 학습"},{"id":14403,"term":"holly","meaning":"호랑가시나무","partOfSpeech":"n.","example":"They hung a wreath of holly on the front door for the holidays.","exampleTranslation":"그들은 명절을 맞아 현관문에 호랑가시나무 화환을 걸었습니다.","level":36,"category":"빈도 학습"},{"id":14404,"term":"horrified","meaning":"소름 끼치는; 극도로 충격받은","partOfSpeech":"adj.","example":"She was horrified to find that her wallet had been stolen.","exampleTranslation":"그녀는 지갑이 도둑맞은 것을 알고 극도로 충격을 받았습니다.","level":36,"category":"빈도 학습"},{"id":14405,"term":"hover","meaning":"맴돌다; 공중에 떠 있다","partOfSpeech":"v.","example":"A helicopter began to hover over the accident scene.","exampleTranslation":"헬리콥터 한 대가 사고 현장 위를 맴돌기 시작했습니다.","level":36,"category":"빈도 학습"},{"id":14406,"term":"howl","meaning":"울부짖다; 울부짖는 소리","partOfSpeech":"v.","example":"The dog would howl every night when it heard distant sirens.","exampleTranslation":"그 개는 멀리서 사이렌 소리가 들릴 때마다 매일 밤 울부짖었습니다.","level":36,"category":"빈도 학습"},{"id":14407,"term":"hum","meaning":"흥얼거리다; 웅웅 소리를 내다","partOfSpeech":"v.","example":"She would hum her favorite song while cooking in the kitchen.","exampleTranslation":"그녀는 부엌에서 요리하는 동안 좋아하는 노래를 흥얼거리곤 했습니다.","level":36,"category":"빈도 학습"},{"id":14408,"term":"humanitarian","meaning":"인도주의적인; 인도주의자","partOfSpeech":"adj.","example":"Several organizations sent humanitarian aid to the flood-affected region.","exampleTranslation":"여러 단체들이 홍수 피해 지역에 인도주의적 지원을 보냈습니다.","level":36,"category":"빈도 학습"},{"id":14409,"term":"hurdle","meaning":"장애물; 허들","partOfSpeech":"n.","example":"Getting funding was the biggest hurdle for the young startup.","exampleTranslation":"자금 조달이 그 젊은 스타트업에게 가장 큰 장애물이었습니다.","level":36,"category":"빈도 학습"},{"id":14410,"term":"hurl","meaning":"세게 던지다; 내던지다","partOfSpeech":"v.","example":"In anger, he tried to hurl the ball against the wall.","exampleTranslation":"화가 난 그는 공을 벽에 세게 던지려 했습니다.","level":36,"category":"빈도 학습"},{"id":14411,"term":"icon","meaning":"아이콘; 우상; 상징","partOfSpeech":"n.","example":"She became a fashion icon admired by people all over the world.","exampleTranslation":"그녀는 전 세계 사람들이 흠모하는 패션 아이콘이 되었습니다.","level":36,"category":"빈도 학습"},{"id":14412,"term":"id","meaning":"신분증; 이드(정신분석의 원초아)","partOfSpeech":"n.","example":"You will need to show a valid id to enter the venue.","exampleTranslation":"행사장에 입장하려면 유효한 신분증을 제시해야 합니다.","level":36,"category":"빈도 학습"},{"id":14413,"term":"ignite","meaning":"점화하다; 불을 붙이다; 촉발하다","partOfSpeech":"v.","example":"A single spark can ignite dry leaves and start a wildfire.","exampleTranslation":"작은 불꽃 하나가 마른 낙엽에 불을 붙여 산불을 일으킬 수 있습니다.","level":36,"category":"빈도 학습"},{"id":14414,"term":"ignorance","meaning":"무지; 모름","partOfSpeech":"n.","example":"His ignorance of local customs caused some awkward situations.","exampleTranslation":"지역 관습에 대한 그의 무지가 몇 가지 어색한 상황을 만들었습니다.","level":36,"category":"빈도 학습"},{"id":14415,"term":"immerse","meaning":"몰두하게 하다; 담그다","partOfSpeech":"v.","example":"The best way to learn a language is to immerse yourself in the culture.","exampleTranslation":"언어를 배우는 가장 좋은 방법은 그 문화에 몰두하는 것입니다.","level":36,"category":"빈도 학습"},{"id":14416,"term":"imminent","meaning":"임박한; 곧 닥칠","partOfSpeech":"adj.","example":"The weather service warned of imminent flooding along the river.","exampleTranslation":"기상청은 강을 따라 홍수가 임박했다고 경고했습니다.","level":36,"category":"빈도 학습"},{"id":14417,"term":"imperative","meaning":"필수적인; 명령적인; 명령법","partOfSpeech":"adj.","example":"It is imperative that you back up your data before the system update.","exampleTranslation":"시스템 업데이트 전에 데이터를 백업하는 것이 필수적입니다.","level":36,"category":"빈도 학습"},{"id":14418,"term":"implant","meaning":"이식하다; 심다; 이식물","partOfSpeech":"v.","example":"The surgeon will implant a small device to monitor the patient's heart.","exampleTranslation":"외과 의사가 환자의 심장을 모니터링하기 위해 작은 장치를 이식할 것입니다.","level":36,"category":"빈도 학습"},{"id":14419,"term":"improvise","meaning":"즉흥적으로 하다; 임기응변하다","partOfSpeech":"v.","example":"The chef had to improvise when he ran out of key ingredients.","exampleTranslation":"주요 재료가 떨어지자 요리사는 즉흥적으로 대처해야 했습니다.","level":36,"category":"빈도 학습"},{"id":14420,"term":"incidental","meaning":"부수적인; 우연한","partOfSpeech":"adj.","example":"The meeting was brief and any personal talk was purely incidental.","exampleTranslation":"회의는 짧았고 개인적인 대화는 순전히 부수적인 것이었습니다.","level":36,"category":"빈도 학습"},{"id":14421,"term":"incumbent","meaning":"현직의; 현직자","partOfSpeech":"adj.","example":"The incumbent mayor is running for re-election next month.","exampleTranslation":"현직 시장이 다음 달 재선에 출마합니다.","level":36,"category":"빈도 학습"},{"id":14422,"term":"incur","meaning":"(손실·비용 등을) 초래하다; 입다","partOfSpeech":"v.","example":"If you cancel the booking now, you will incur a cancellation fee.","exampleTranslation":"지금 예약을 취소하면 취소 수수료가 발생합니다.","level":36,"category":"빈도 학습"},{"id":14423,"term":"indict","meaning":"기소하다; 고발하다","partOfSpeech":"v.","example":"The grand jury decided to indict the executive on fraud charges.","exampleTranslation":"대배심은 사기 혐의로 그 임원을 기소하기로 결정했습니다.","level":36,"category":"빈도 학습"},{"id":14424,"term":"inferior","meaning":"열등한; 하급의; 하급자","partOfSpeech":"adj.","example":"They complained that the replacement parts were inferior in quality.","exampleTranslation":"그들은 교체 부품의 품질이 열등하다고 불평했습니다.","level":36,"category":"빈도 학습"},{"id":14425,"term":"inflict","meaning":"(고통·피해 등을) 가하다; 끼치다","partOfSpeech":"v.","example":"The storm managed to inflict serious damage on the coastal town.","exampleTranslation":"폭풍은 해안 마을에 심각한 피해를 입혔습니다.","level":36,"category":"빈도 학습"},{"id":14426,"term":"influenza","meaning":"독감; 인플루엔자","partOfSpeech":"n.","example":"The doctor advised everyone to get vaccinated against influenza before winter.","exampleTranslation":"의사는 겨울이 오기 전에 모든 사람이 독감 예방접종을 받으라고 권고했습니다.","level":36,"category":"빈도 학습"},{"id":14427,"term":"infuse","meaning":"불어넣다; 우려내다","partOfSpeech":"v.","example":"The new director tried to infuse fresh energy into the team.","exampleTranslation":"새 감독은 팀에 새로운 활력을 불어넣으려 했습니다.","level":36,"category":"빈도 학습"},{"id":14428,"term":"inhale","meaning":"들이마시다; 흡입하다","partOfSpeech":"v.","example":"Take a moment to slowly inhale and exhale to calm yourself down.","exampleTranslation":"진정하기 위해 잠시 천천히 들이마시고 내쉬어 보세요.","level":36,"category":"빈도 학습"},{"id":14429,"term":"inland","meaning":"내륙의; 내륙으로","partOfSpeech":"adj.","example":"After the flood warning, many coastal residents moved inland.","exampleTranslation":"홍수 경보 이후 많은 해안 주민들이 내륙으로 이동했습니다.","level":36,"category":"빈도 학습"},{"id":14430,"term":"inmate","meaning":"수감자; 시설 입소자","partOfSpeech":"n.","example":"Each inmate is allowed one phone call per week to contact family.","exampleTranslation":"각 수감자는 가족에게 연락하기 위해 일주일에 한 번 전화 통화가 허용됩니다.","level":36,"category":"빈도 학습"},{"id":14431,"term":"innings","meaning":"(크리켓·야구의) 이닝","partOfSpeech":"n.","example":"The batter hit a home run in the final innings of the game.","exampleTranslation":"타자는 경기 마지막 이닝에서 홈런을 쳤습니다.","level":36,"category":"빈도 학습"},{"id":14432,"term":"innocence","meaning":"무죄; 순수함; 결백","partOfSpeech":"n.","example":"New evidence was presented in court to prove his innocence.","exampleTranslation":"그의 무죄를 증명하기 위한 새로운 증거가 법정에서 제출되었습니다.","level":36,"category":"빈도 학습"},{"id":14433,"term":"intake","meaning":"섭취량; 흡입; 받아들임","partOfSpeech":"n.","example":"The doctor recommended reducing your daily intake of salt and sugar.","exampleTranslation":"의사는 소금과 설탕의 일일 섭취량을 줄이라고 권고했습니다.","level":36,"category":"빈도 학습"},{"id":14434,"term":"intelligible","meaning":"이해할 수 있는; 명료한","partOfSpeech":"adj.","example":"Please speak more slowly so your explanation is intelligible to everyone.","exampleTranslation":"모든 사람이 이해할 수 있도록 더 천천히 말해 주세요.","level":36,"category":"빈도 학습"},{"id":14435,"term":"intercept","meaning":"가로채다; 차단하다","partOfSpeech":"v.","example":"The defender managed to intercept the pass and stop the attack.","exampleTranslation":"수비수가 패스를 가로채 공격을 막아냈습니다.","level":36,"category":"빈도 학습"},{"id":14436,"term":"intercourse","meaning":"교류; 성교","partOfSpeech":"n.","example":"Social intercourse between the two communities improved after the festival.","exampleTranslation":"축제 이후 두 공동체 사이의 사회적 교류가 개선되었습니다.","level":36,"category":"빈도 학습"},{"id":14437,"term":"intermediate","meaning":"중간의; 중급의","partOfSpeech":"adj.","example":"She signed up for an intermediate cooking class to improve her skills.","exampleTranslation":"그녀는 실력을 향상시키기 위해 중급 요리 수업에 등록했습니다.","level":36,"category":"빈도 학습"},{"id":14438,"term":"interrogate","meaning":"심문하다; 캐묻다","partOfSpeech":"v.","example":"The detective needed to interrogate the suspect for several hours.","exampleTranslation":"형사는 용의자를 몇 시간 동안 심문해야 했습니다.","level":36,"category":"빈도 학습"},{"id":14439,"term":"intersect","meaning":"교차하다; 가로지르다","partOfSpeech":"v.","example":"The two roads intersect right in front of the old market.","exampleTranslation":"두 도로는 오래된 시장 바로 앞에서 교차합니다.","level":36,"category":"빈도 학습"},{"id":14440,"term":"intestine","meaning":"장; 창자","partOfSpeech":"n.","example":"The doctor explained that the intestine plays a key role in digestion.","exampleTranslation":"의사는 장이 소화에 핵심적인 역할을 한다고 설명했습니다.","level":36,"category":"빈도 학습"},{"id":14441,"term":"intrinsic","meaning":"본질적인; 내재적인","partOfSpeech":"adj.","example":"Learning has an intrinsic value that goes beyond grades or rewards.","exampleTranslation":"학습은 성적이나 보상을 넘어서는 본질적인 가치를 가지고 있습니다.","level":36,"category":"빈도 학습"},{"id":14442,"term":"intrude","meaning":"침입하다; 방해하다","partOfSpeech":"v.","example":"I am sorry to intrude, but could you help me find the exit?","exampleTranslation":"방해해서 죄송하지만, 출구를 찾는 것을 도와주실 수 있나요?","level":36,"category":"빈도 학습"},{"id":14443,"term":"inventory","meaning":"재고; 목록","partOfSpeech":"n.","example":"The manager checked the inventory before placing a new order.","exampleTranslation":"관리자는 새 주문을 넣기 전에 재고를 확인했습니다.","level":36,"category":"빈도 학습"},{"id":14444,"term":"ion","meaning":"이온","partOfSpeech":"n.","example":"The chemistry teacher explained how each ion carries an electric charge.","exampleTranslation":"화학 선생님은 각 이온이 어떻게 전하를 띠는지 설명했습니다.","level":36,"category":"빈도 학습"},{"id":14445,"term":"ivory","meaning":"상아; 상아색","partOfSpeech":"n.","example":"The museum displayed an ancient carving made of ivory.","exampleTranslation":"박물관은 상아로 만들어진 고대 조각품을 전시했습니다.","level":36,"category":"빈도 학습"},{"id":14446,"term":"jealous","meaning":"질투하는; 시기하는","partOfSpeech":"adj.","example":"He felt jealous when his friend got a promotion before him.","exampleTranslation":"그는 친구가 자신보다 먼저 승진을 받았을 때 질투를 느꼈습니다.","level":36,"category":"빈도 학습"},{"id":14447,"term":"jeopardy","meaning":"위험; 위태로움","partOfSpeech":"n.","example":"Poor planning put the entire project in jeopardy.","exampleTranslation":"부실한 계획이 전체 프로젝트를 위험에 빠뜨렸습니다.","level":36,"category":"빈도 학습"},{"id":14448,"term":"jewel","meaning":"보석; 귀중품","partOfSpeech":"n.","example":"She wore a jewel on her necklace that had belonged to her grandmother.","exampleTranslation":"그녀는 할머니의 것이었던 보석이 달린 목걸이를 했습니다.","level":36,"category":"빈도 학습"},{"id":14449,"term":"jockey","meaning":"기수; 조종하다","partOfSpeech":"n.","example":"The jockey guided his horse carefully around the tight corner.","exampleTranslation":"기수는 좁은 코너를 조심스럽게 돌며 말을 이끌었습니다.","level":36,"category":"빈도 학습"},{"id":14450,"term":"jog","meaning":"조깅하다; 가볍게 뛰다","partOfSpeech":"v.","example":"I like to jog around the park every morning before breakfast.","exampleTranslation":"저는 아침 식사 전에 매일 공원을 조깅하는 것을 좋아합니다.","level":36,"category":"빈도 학습"},{"id":14451,"term":"journalism","meaning":"저널리즘; 언론","partOfSpeech":"n.","example":"She chose journalism as her career because she wanted to tell important stories.","exampleTranslation":"그녀는 중요한 이야기를 전하고 싶었기 때문에 저널리즘을 직업으로 선택했습니다.","level":36,"category":"빈도 학습"},{"id":14452,"term":"judiciary","meaning":"사법부; 재판 제도","partOfSpeech":"n.","example":"An independent judiciary is essential for a fair and just society.","exampleTranslation":"독립적인 사법부는 공정하고 정의로운 사회를 위해 필수적입니다.","level":37,"category":"빈도 학습"},{"id":14453,"term":"junction","meaning":"교차로; 합류점","partOfSpeech":"n.","example":"Turn left at the junction and you will see the hospital on your right.","exampleTranslation":"교차로에서 좌회전하면 오른쪽에 병원이 보일 것입니다.","level":37,"category":"빈도 학습"},{"id":14454,"term":"junk","meaning":"쓰레기; 잡동사니","partOfSpeech":"n.","example":"The garage was full of junk that nobody had touched in years.","exampleTranslation":"차고에는 몇 년 동안 아무도 손대지 않은 잡동사니로 가득했습니다.","level":37,"category":"빈도 학습"},{"id":14455,"term":"kidney","meaning":"신장; 콩팥","partOfSpeech":"n.","example":"Drinking plenty of water helps keep your kidney functioning properly.","exampleTranslation":"물을 충분히 마시면 신장이 제대로 기능하는 데 도움이 됩니다.","level":37,"category":"빈도 학습"},{"id":14456,"term":"knight","meaning":"기사; 나이트(체스)","partOfSpeech":"n.","example":"The king rewarded the loyal knight with land and gold.","exampleTranslation":"왕은 충성스러운 기사에게 땅과 금을 하사했습니다.","level":37,"category":"빈도 학습"},{"id":14457,"term":"lad","meaning":"소년; 젊은이","partOfSpeech":"n.","example":"The old man remembered being a lad growing up in the countryside.","exampleTranslation":"그 노인은 시골에서 소년으로 자랐던 때를 기억했습니다.","level":37,"category":"빈도 학습"},{"id":14458,"term":"laden","meaning":"가득 실은; 부담을 진","partOfSpeech":"adj.","example":"The truck was laden with boxes of fresh produce from the farm.","exampleTranslation":"트럭에는 농장에서 온 신선한 농산물 상자들이 가득 실려 있었습니다.","level":37,"category":"빈도 학습"},{"id":14459,"term":"lag","meaning":"뒤처지다; 지연","partOfSpeech":"v.","example":"My internet connection tends to lag during busy hours.","exampleTranslation":"제 인터넷 연결은 혼잡한 시간대에 자주 지연되는 경향이 있습니다.","level":37,"category":"빈도 학습"},{"id":14460,"term":"lament","meaning":"슬퍼하다; 애도하다","partOfSpeech":"v.","example":"Many residents began to lament the loss of the old community center.","exampleTranslation":"많은 주민들이 오래된 지역 센터의 철거를 슬퍼하기 시작했습니다.","level":37,"category":"빈도 학습"},{"id":14461,"term":"landmark","meaning":"랜드마크; 중요한 지점","partOfSpeech":"n.","example":"The old clock tower is the most famous landmark in our town.","exampleTranslation":"오래된 시계탑은 우리 마을에서 가장 유명한 랜드마크입니다.","level":37,"category":"빈도 학습"},{"id":14462,"term":"lapse","meaning":"실수; (시간이) 경과하다","partOfSpeech":"n.","example":"After a brief lapse in concentration, she quickly refocused on the task.","exampleTranslation":"잠깐 집중력이 흐트러진 후 그녀는 빠르게 과제에 다시 집중했습니다.","level":37,"category":"빈도 학습"},{"id":14463,"term":"larva","meaning":"유충; 애벌레","partOfSpeech":"n.","example":"The larva of a butterfly is commonly known as a caterpillar.","exampleTranslation":"나비의 유충은 일반적으로 애벌레라고 알려져 있습니다.","level":37,"category":"빈도 학습"},{"id":14464,"term":"lash","meaning":"채찍질하다; 속눈썹","partOfSpeech":"v.","example":"Heavy rain began to lash against the windows during the storm.","exampleTranslation":"폭풍 중에 폭우가 창문을 세차게 때리기 시작했습니다.","level":37,"category":"빈도 학습"},{"id":14465,"term":"lateral","meaning":"옆의; 측면의","partOfSpeech":"adj.","example":"The doctor noted some lateral movement in the patient's injured knee.","exampleTranslation":"의사는 환자의 부상당한 무릎에서 측면 움직임이 있다고 언급했습니다.","level":37,"category":"빈도 학습"},{"id":14466,"term":"lavish","meaning":"사치스러운; 풍성한","partOfSpeech":"adj.","example":"They threw a lavish party to celebrate the company's twentieth anniversary.","exampleTranslation":"그들은 회사의 20주년을 기념하기 위해 사치스러운 파티를 열었습니다.","level":37,"category":"빈도 학습"},{"id":14467,"term":"leaflet","meaning":"전단지; 소책자","partOfSpeech":"n.","example":"A volunteer handed me a leaflet about the neighborhood cleanup event.","exampleTranslation":"자원봉사자가 지역 청소 행사에 관한 전단지를 건네주었습니다.","level":37,"category":"빈도 학습"},{"id":14468,"term":"leash","meaning":"목줄; 끈","partOfSpeech":"n.","example":"Please keep your dog on a leash when walking in the public park.","exampleTranslation":"공공 공원에서 산책할 때는 개를 목줄에 매어 두세요.","level":37,"category":"빈도 학습"},{"id":14469,"term":"legion","meaning":"군단; 다수","partOfSpeech":"n.","example":"The singer has a legion of devoted fans around the world.","exampleTranslation":"그 가수는 전 세계에 수많은 열성 팬을 보유하고 있습니다.","level":37,"category":"빈도 학습"},{"id":14470,"term":"lesion","meaning":"병변; 상처","partOfSpeech":"n.","example":"The doctor found a small lesion on the patient's skin during the exam.","exampleTranslation":"의사는 진찰 중 환자의 피부에서 작은 병변을 발견했습니다.","level":37,"category":"빈도 학습"},{"id":14471,"term":"lethal","meaning":"치명적인; 치사의","partOfSpeech":"adj.","example":"The scientist warned that the chemical could be lethal in large doses.","exampleTranslation":"과학자는 그 화학물질이 대량으로 복용하면 치명적일 수 있다고 경고했습니다.","level":37,"category":"빈도 학습"},{"id":14472,"term":"liaison","meaning":"연락 담당자; 연계","partOfSpeech":"n.","example":"She was appointed as liaison between the school and the local government.","exampleTranslation":"그녀는 학교와 지방 정부 사이의 연락 담당자로 임명되었습니다.","level":37,"category":"빈도 학습"},{"id":14473,"term":"lightning","meaning":"번개; 번개 같은","partOfSpeech":"n.","example":"We saw a flash of lightning just before we heard the thunder.","exampleTranslation":"천둥소리가 들리기 직전에 번개가 번쩍이는 것을 보았습니다.","level":37,"category":"빈도 학습"},{"id":14474,"term":"lime","meaning":"라임; 석회","partOfSpeech":"n.","example":"She squeezed a lime over the fish tacos to add a fresh flavor.","exampleTranslation":"그녀는 신선한 맛을 더하기 위해 생선 타코 위에 라임을 짜 넣었습니다.","level":37,"category":"빈도 학습"},{"id":14475,"term":"limp","meaning":"절뚝거리다; 축 늘어진","partOfSpeech":"v.","example":"After the accident he had to limp slowly to the nearest bench.","exampleTranslation":"사고 후 그는 가장 가까운 벤치까지 천천히 절뚝거려야 했습니다.","level":37,"category":"빈도 학습"},{"id":14476,"term":"linen","meaning":"린넨; 삼베","partOfSpeech":"n.","example":"The hotel changed the linen on the beds every morning.","exampleTranslation":"호텔은 매일 아침 침대의 린넨을 교체했습니다.","level":37,"category":"빈도 학습"},{"id":14477,"term":"lining","meaning":"안감; 내부 표면","partOfSpeech":"n.","example":"The coat has a soft lining inside that keeps you warm in winter.","exampleTranslation":"그 코트는 안에 부드러운 안감이 있어 겨울에 따뜻하게 해줍니다.","level":37,"category":"빈도 학습"},{"id":14478,"term":"liquor","meaning":"독주; 증류주","partOfSpeech":"n.","example":"The bar offered a wide selection of liquor from around the world.","exampleTranslation":"그 바는 전 세계의 다양한 독주를 제공했습니다.","level":37,"category":"빈도 학습"},{"id":14479,"term":"litigate","meaning":"소송을 제기하다; 법정에서 다투다","partOfSpeech":"v.","example":"The company decided to litigate the contract dispute in court.","exampleTranslation":"그 회사는 계약 분쟁을 법원에서 소송으로 해결하기로 결정했습니다.","level":37,"category":"빈도 학습"},{"id":14480,"term":"litter","meaning":"쓰레기를 버리다; 쓰레기","partOfSpeech":"v.","example":"It is against the law to litter in public spaces in this city.","exampleTranslation":"이 도시에서는 공공장소에 쓰레기를 버리는 것이 법으로 금지되어 있습니다.","level":37,"category":"빈도 학습"},{"id":14481,"term":"logo","meaning":"로고; 상징 마크","partOfSpeech":"n.","example":"The designer created a simple but memorable logo for the new brand.","exampleTranslation":"디자이너는 새 브랜드를 위해 단순하지만 기억에 남는 로고를 만들었습니다.","level":37,"category":"빈도 학습"},{"id":14482,"term":"loot","meaning":"약탈하다; 전리품","partOfSpeech":"v.","example":"Criminals tried to loot several stores during the blackout.","exampleTranslation":"범인들은 정전 중에 여러 가게를 약탈하려고 했습니다.","level":37,"category":"빈도 학습"},{"id":14483,"term":"lure","meaning":"유혹하다; 미끼","partOfSpeech":"v.","example":"The advertisement was designed to lure customers with special discounts.","exampleTranslation":"그 광고는 특별 할인으로 고객을 유혹하기 위해 설계되었습니다.","level":37,"category":"빈도 학습"},{"id":14484,"term":"lurk","meaning":"숨어서 기다리다; 잠복하다","partOfSpeech":"v.","example":"A stray cat seemed to lurk behind the bushes in the garden.","exampleTranslation":"길고양이 한 마리가 정원 덤불 뒤에 숨어 있는 것 같았습니다.","level":37,"category":"빈도 학습"},{"id":14485,"term":"lust","meaning":"욕망; 강렬한 욕구","partOfSpeech":"n.","example":"His lust for power eventually led to his downfall.","exampleTranslation":"권력에 대한 그의 욕망이 결국 그의 몰락으로 이어졌습니다.","level":37,"category":"빈도 학습"},{"id":14486,"term":"madam","meaning":"부인; 여사; 아주머니(여성에 대한 경칭)","partOfSpeech":"n.","example":"Excuse me, madam, I think you dropped your wallet.","exampleTranslation":"실례합니다, 부인, 지갑을 떨어뜨리신 것 같아요.","level":37,"category":"빈도 학습"},{"id":14487,"term":"magistrate","meaning":"치안 판사; 지방 행정관","partOfSpeech":"n.","example":"The magistrate reviewed the case and issued a fine to the defendant.","exampleTranslation":"치안 판사는 사건을 검토하고 피고인에게 벌금을 부과했습니다.","level":37,"category":"빈도 학습"},{"id":14488,"term":"maid","meaning":"가정부; 하녀","partOfSpeech":"n.","example":"The hotel maid knocked on the door before entering to clean the room.","exampleTranslation":"호텔 객실 청소 직원은 방을 청소하러 들어가기 전에 문을 두드렸습니다.","level":37,"category":"빈도 학습"},{"id":14489,"term":"majesty","meaning":"장엄함; 웅장함; 폐하","partOfSpeech":"n.","example":"The majesty of the mountain landscape left us completely speechless.","exampleTranslation":"산 풍경의 장엄함에 우리는 완전히 말을 잃었습니다.","level":37,"category":"빈도 학습"},{"id":14490,"term":"mall","meaning":"쇼핑몰; 쇼핑센터","partOfSpeech":"n.","example":"We spent the whole afternoon at the mall looking for new shoes.","exampleTranslation":"우리는 새 신발을 찾아 오후 내내 쇼핑몰에서 시간을 보냈습니다.","level":37,"category":"빈도 학습"},{"id":14491,"term":"mandatory","meaning":"의무적인; 강제적인","partOfSpeech":"adj.","example":"Attendance at the safety training session is mandatory for all new staff.","exampleTranslation":"안전 교육 참석은 모든 신입 직원에게 의무 사항입니다.","level":37,"category":"빈도 학습"},{"id":14492,"term":"mankind","meaning":"인류; 인간","partOfSpeech":"n.","example":"This discovery could change the way mankind understands the universe.","exampleTranslation":"이 발견은 인류가 우주를 이해하는 방식을 바꿀 수도 있습니다.","level":37,"category":"빈도 학습"},{"id":14493,"term":"manor","meaning":"영지; 저택; 장원","partOfSpeech":"n.","example":"The old manor on the hill has been converted into a boutique hotel.","exampleTranslation":"언덕 위의 오래된 저택은 부티크 호텔로 개조되었습니다.","level":37,"category":"빈도 학습"},{"id":14494,"term":"mansion","meaning":"저택; 대저택","partOfSpeech":"n.","example":"The wealthy businessman lived in a mansion surrounded by a large garden.","exampleTranslation":"그 부유한 사업가는 넓은 정원에 둘러싸인 저택에 살았습니다.","level":37,"category":"빈도 학습"},{"id":14495,"term":"marathon","meaning":"마라톤; 장시간의 행사","partOfSpeech":"n.","example":"She trained for six months before running her first marathon.","exampleTranslation":"그녀는 첫 마라톤을 뛰기 전에 6개월 동안 훈련했습니다.","level":37,"category":"빈도 학습"},{"id":14496,"term":"marines","meaning":"해병대; 해병","partOfSpeech":"n.","example":"The marines were deployed to assist with the humanitarian mission abroad.","exampleTranslation":"해병대는 해외 인도주의 임무를 지원하기 위해 파견되었습니다.","level":37,"category":"빈도 학습"},{"id":14497,"term":"marital","meaning":"결혼의; 부부의","partOfSpeech":"adj.","example":"The couple sought counseling to resolve their marital difficulties.","exampleTranslation":"그 부부는 결혼 생활의 어려움을 해결하기 위해 상담을 받았습니다.","level":37,"category":"빈도 학습"},{"id":14498,"term":"marsh","meaning":"습지; 늪","partOfSpeech":"n.","example":"Many birds nest in the marsh at the edge of the nature reserve.","exampleTranslation":"많은 새들이 자연 보호 구역 가장자리의 습지에 둥지를 틉니다.","level":37,"category":"빈도 학습"},{"id":14499,"term":"marshal","meaning":"원수; 사법관; 정리하다","partOfSpeech":"n.","example":"The marshal directed traffic near the parade route throughout the event.","exampleTranslation":"사법관은 행사 내내 퍼레이드 경로 근처에서 교통을 정리했습니다.","level":37,"category":"빈도 학습"},{"id":14500,"term":"martyr","meaning":"순교자; 희생자","partOfSpeech":"n.","example":"He became a martyr in his community after standing up for equal rights.","exampleTranslation":"그는 평등권을 위해 목소리를 높인 후 지역 사회의 순교자가 되었습니다.","level":37,"category":"빈도 학습"},{"id":14501,"term":"masculine","meaning":"남성적인; 남자다운","partOfSpeech":"adj.","example":"The deep, masculine voice on the radio instantly caught my attention.","exampleTranslation":"라디오에서 들리는 낮고 남성적인 목소리가 즉시 내 주의를 끌었습니다.","level":37,"category":"빈도 학습"},{"id":14502,"term":"massacre","meaning":"학살; 대량 살육","partOfSpeech":"n.","example":"The massacre was condemned by governments around the world.","exampleTranslation":"그 학살은 전 세계 각국 정부로부터 비난을 받았습니다.","level":37,"category":"빈도 학습"},{"id":14503,"term":"massage","meaning":"마사지; 안마","partOfSpeech":"n.","example":"After a long day of hiking, she booked a massage to relax her muscles.","exampleTranslation":"긴 하이킹을 마친 후 그녀는 근육을 풀기 위해 마사지를 예약했습니다.","level":37,"category":"빈도 학습"},{"id":14504,"term":"maternal","meaning":"어머니의; 모성의","partOfSpeech":"adj.","example":"She had a warm, maternal instinct that made all the children feel safe.","exampleTranslation":"그녀는 따뜻한 모성 본능을 지니고 있어 아이들 모두가 안심하게 느꼈습니다.","level":37,"category":"빈도 학습"},{"id":14505,"term":"mattress","meaning":"매트리스; 침대 스프링","partOfSpeech":"n.","example":"We bought a new mattress because the old one was causing back pain.","exampleTranslation":"오래된 매트리스가 허리 통증을 유발해서 새 매트리스를 구입했습니다.","level":37,"category":"빈도 학습"},{"id":14506,"term":"meadow","meaning":"초원; 들판","partOfSpeech":"n.","example":"The children ran freely through the wide meadow behind the farmhouse.","exampleTranslation":"아이들은 농가 뒤편의 넓은 초원을 자유롭게 뛰어다녔습니다.","level":37,"category":"빈도 학습"},{"id":14507,"term":"median","meaning":"중앙값; 중간의","partOfSpeech":"n.","example":"The median household income in this city rose slightly last year.","exampleTranslation":"이 도시의 가구 중위 소득은 지난해 소폭 상승했습니다.","level":37,"category":"빈도 학습"},{"id":14508,"term":"medication","meaning":"약; 약물 치료","partOfSpeech":"n.","example":"The doctor prescribed medication to help manage her high blood pressure.","exampleTranslation":"의사는 그녀의 고혈압을 관리하는 데 도움이 되는 약을 처방했습니다.","level":37,"category":"빈도 학습"},{"id":14509,"term":"meditate","meaning":"명상하다; 심사숙고하다","partOfSpeech":"v.","example":"She likes to meditate for ten minutes each morning before breakfast.","exampleTranslation":"그녀는 매일 아침 식사 전에 10분간 명상하는 것을 좋아합니다.","level":37,"category":"빈도 학습"},{"id":14510,"term":"membrane","meaning":"막; 얇은 층","partOfSpeech":"n.","example":"A thin membrane separates the two chambers inside the cell.","exampleTranslation":"얇은 막이 세포 안의 두 공간을 분리하고 있습니다.","level":37,"category":"빈도 학습"},{"id":14511,"term":"memo","meaning":"메모; 업무 전달 문서","partOfSpeech":"n.","example":"The manager sent a memo to remind everyone about the upcoming deadline.","exampleTranslation":"관리자는 다가오는 마감일을 모두에게 상기시키기 위해 메모를 보냈습니다.","level":37,"category":"빈도 학습"},{"id":14512,"term":"memoir","meaning":"회고록; 자서전","partOfSpeech":"n.","example":"The retired athlete wrote a memoir about the challenges of her career.","exampleTranslation":"은퇴한 운동선수는 자신의 커리어에서 겪은 어려움에 대한 회고록을 썼습니다.","level":37,"category":"빈도 학습"},{"id":14513,"term":"memorable","meaning":"기억에 남는; 인상적인","partOfSpeech":"adj.","example":"The trip to Japan was one of the most memorable experiences of my life.","exampleTranslation":"일본 여행은 내 인생에서 가장 기억에 남는 경험 중 하나였습니다.","level":37,"category":"빈도 학습"},{"id":14514,"term":"menace","meaning":"위협; 위험 요소","partOfSpeech":"n.","example":"The icy road was a real menace to drivers during the winter storm.","exampleTranslation":"얼어붙은 도로는 겨울 폭풍 동안 운전자들에게 실제 위협이었습니다.","level":37,"category":"빈도 학습"},{"id":14515,"term":"messenger","meaning":"전령; 메신저; 심부름꾼","partOfSpeech":"n.","example":"A messenger arrived at the office with an urgent package for the director.","exampleTranslation":"전령이 이사를 위한 긴급 소포를 가지고 사무실에 도착했습니다.","level":37,"category":"빈도 학습"},{"id":14516,"term":"microphone","meaning":"마이크; 마이크로폰","partOfSpeech":"n.","example":"Please speak closer to the microphone so everyone in the room can hear you.","exampleTranslation":"방 안의 모든 사람이 들을 수 있도록 마이크에 더 가까이 말씀해 주세요.","level":37,"category":"빈도 학습"},{"id":14517,"term":"microscope","meaning":"현미경","partOfSpeech":"n.","example":"The student used a microscope to observe the cells on the slide.","exampleTranslation":"학생은 슬라이드의 세포를 관찰하기 위해 현미경을 사용했습니다.","level":37,"category":"빈도 학습"},{"id":14518,"term":"midst","meaning":"한가운데; 중간","partOfSpeech":"n.","example":"We were in the midst of dinner when the power suddenly went out.","exampleTranslation":"우리는 저녁을 먹는 한가운데에 갑자기 전기가 나갔습니다.","level":37,"category":"빈도 학습"},{"id":14519,"term":"migrant","meaning":"이주민; 이주 노동자","partOfSpeech":"n.","example":"The organization provides housing support for every migrant in the program.","exampleTranslation":"그 단체는 프로그램에 참여하는 모든 이주민에게 주거 지원을 제공합니다.","level":37,"category":"빈도 학습"},{"id":14520,"term":"militia","meaning":"민병대; 시민군","partOfSpeech":"n.","example":"A local militia was formed to protect the village from outside threats.","exampleTranslation":"외부 위협으로부터 마을을 보호하기 위해 지역 민병대가 결성되었습니다.","level":37,"category":"빈도 학습"},{"id":14521,"term":"millennium","meaning":"천 년; 밀레니엄","partOfSpeech":"n.","example":"People around the world celebrated the start of the new millennium together.","exampleTranslation":"전 세계 사람들이 함께 새 천 년의 시작을 축하했습니다.","level":37,"category":"빈도 학습"},{"id":14522,"term":"milliliter","meaning":"밀리리터(mL)","partOfSpeech":"n.","example":"The nurse drew exactly one milliliter of vaccine into the syringe.","exampleTranslation":"간호사는 주사기에 정확히 1밀리리터의 백신을 뽑았습니다.","level":37,"category":"빈도 학습"},{"id":14523,"term":"mimic","meaning":"흉내 내다; 모방하다","partOfSpeech":"v.","example":"The comedian could mimic the voices of famous politicians perfectly.","exampleTranslation":"그 코미디언은 유명 정치인들의 목소리를 완벽하게 흉내 낼 수 있었습니다.","level":37,"category":"빈도 학습"},{"id":14524,"term":"miniature","meaning":"소형의; 축소 모형","partOfSpeech":"adj.","example":"The gift shop sold miniature replicas of famous landmarks.","exampleTranslation":"그 기념품 가게는 유명 명소의 소형 복제품을 판매했습니다.","level":37,"category":"빈도 학습"},{"id":14525,"term":"mint","meaning":"박하; 민트; 조폐국","partOfSpeech":"n.","example":"She added a few leaves of mint to her lemonade for a fresh taste.","exampleTranslation":"그녀는 상쾌한 맛을 위해 레모네이드에 민트 잎을 몇 장 넣었습니다.","level":37,"category":"빈도 학습"},{"id":14526,"term":"misery","meaning":"비참함; 고통; 불행","partOfSpeech":"n.","example":"The long rainy season added to the misery of the flood victims.","exampleTranslation":"긴 우기가 홍수 피해자들의 비참함을 더했습니다.","level":37,"category":"빈도 학습"},{"id":14527,"term":"mistress","meaning":"여주인; 안주인; (비공식) 정부","partOfSpeech":"n.","example":"The mistress of the household greeted each guest at the front door.","exampleTranslation":"집안의 안주인은 현관에서 손님 한 명 한 명을 맞이했습니다.","level":37,"category":"빈도 학습"},{"id":14528,"term":"mitigate","meaning":"완화하다; 경감시키다","partOfSpeech":"v.","example":"Tree planting can help mitigate the effects of urban heat in summer.","exampleTranslation":"나무 심기는 여름철 도심 열기의 영향을 완화하는 데 도움이 될 수 있습니다.","level":37,"category":"빈도 학습"},{"id":14529,"term":"moan","meaning":"신음하다; 불평하다; 신음 소리","partOfSpeech":"v.","example":"He began to moan about his knee pain after the long walk.","exampleTranslation":"긴 산책 후 그는 무릎 통증에 대해 신음하기 시작했습니다.","level":37,"category":"빈도 학습"},{"id":14530,"term":"mob","meaning":"군중; 폭도; 떼를 지어 몰려들다","partOfSpeech":"n.","example":"An angry mob gathered outside the courthouse waiting for the verdict.","exampleTranslation":"분노한 군중이 판결을 기다리며 법원 밖에 모였습니다.","level":37,"category":"빈도 학습"},{"id":14531,"term":"modem","meaning":"모뎀; 통신 장치","partOfSpeech":"n.","example":"I had to restart the modem to get the internet connection working again.","exampleTranslation":"인터넷 연결을 다시 작동시키기 위해 모뎀을 재시작해야 했습니다.","level":37,"category":"빈도 학습"},{"id":14532,"term":"moist","meaning":"축축한; 촉촉한","partOfSpeech":"adj.","example":"The moist soil in the garden is perfect for planting vegetables.","exampleTranslation":"정원의 촉촉한 흙은 채소를 심기에 안성맞춤입니다.","level":37,"category":"빈도 학습"},{"id":14533,"term":"monastery","meaning":"수도원","partOfSpeech":"n.","example":"Tourists visited the ancient monastery perched on top of the cliff.","exampleTranslation":"관광객들은 절벽 위에 자리 잡은 오래된 수도원을 방문했습니다.","level":37,"category":"빈도 학습"},{"id":14534,"term":"monk","meaning":"수도사; 승려","partOfSpeech":"n.","example":"The monk woke up before dawn every day to pray and meditate.","exampleTranslation":"그 수도사는 기도하고 명상하기 위해 매일 새벽 전에 일어났습니다.","level":37,"category":"빈도 학습"},{"id":14535,"term":"moor","meaning":"황야; 늪지대; 배를 묶다","partOfSpeech":"n.","example":"They hiked across the open moor as fog slowly rolled in from the hills.","exampleTranslation":"안개가 언덕에서 서서히 밀려들어 오는 동안 그들은 탁 트인 황야를 가로질러 하이킹했습니다.","level":37,"category":"빈도 학습"},{"id":14536,"term":"morale","meaning":"사기; 의욕; 투지","partOfSpeech":"n.","example":"The manager tried to boost team morale by celebrating small wins.","exampleTranslation":"관리자는 작은 성과를 축하함으로써 팀의 사기를 높이려 했습니다.","level":37,"category":"빈도 학습"},{"id":14537,"term":"mortar","meaning":"모르타르(시멘트); 절구","partOfSpeech":"n.","example":"The bricklayer mixed mortar to hold the stones together.","exampleTranslation":"벽돌공은 돌을 붙이기 위해 모르타르를 섞었습니다.","level":37,"category":"빈도 학습"},{"id":14538,"term":"mosaic","meaning":"모자이크; 조각 그림","partOfSpeech":"n.","example":"The floor was decorated with a beautiful mosaic made of colorful tiles.","exampleTranslation":"바닥은 알록달록한 타일로 만든 아름다운 모자이크로 장식되어 있었습니다.","level":37,"category":"빈도 학습"},{"id":14539,"term":"mosquito","meaning":"모기","partOfSpeech":"n.","example":"She got a mosquito bite on her arm while sitting outside.","exampleTranslation":"그녀는 바깥에 앉아 있다가 팔에 모기에 물렸습니다.","level":37,"category":"빈도 학습"},{"id":14540,"term":"motif","meaning":"주제; 모티프; 반복 무늬","partOfSpeech":"n.","example":"The floral motif appeared throughout the entire design of the wallpaper.","exampleTranslation":"꽃 모티프가 벽지 전체 디자인에 걸쳐 반복적으로 등장했습니다.","level":37,"category":"빈도 학습"},{"id":14541,"term":"moulding","meaning":"몰딩; 장식 테두리","partOfSpeech":"n.","example":"The carpenter installed decorative moulding along the ceiling of the room.","exampleTranslation":"목수는 방 천장을 따라 장식 몰딩을 설치했습니다.","level":37,"category":"빈도 학습"},{"id":14542,"term":"mound","meaning":"흙더미; 언덕; 쌓아 올리다","partOfSpeech":"n.","example":"The children built a mound of sand at the edge of the beach.","exampleTranslation":"아이들은 해변 가장자리에 모래 더미를 쌓았습니다.","level":37,"category":"빈도 학습"},{"id":14543,"term":"moustache","meaning":"콧수염","partOfSpeech":"n.","example":"He grew a moustache over the summer and looked quite different.","exampleTranslation":"그는 여름 동안 콧수염을 길렀고 꽤 다르게 보였습니다.","level":37,"category":"빈도 학습"},{"id":14544,"term":"mucus","meaning":"점액; 콧물","partOfSpeech":"n.","example":"The doctor explained that mucus helps protect the lining of your nose.","exampleTranslation":"의사는 점액이 코 안쪽 막을 보호하는 데 도움이 된다고 설명했습니다.","level":37,"category":"빈도 학습"},{"id":14545,"term":"mug","meaning":"머그잔; 강도질하다","partOfSpeech":"n.","example":"She wrapped her hands around a warm mug of coffee on a cold morning.","exampleTranslation":"그녀는 추운 아침에 따뜻한 커피 머그잔을 두 손으로 감쌌습니다.","level":37,"category":"빈도 학습"},{"id":14546,"term":"multimedia","meaning":"멀티미디어; 복합 매체","partOfSpeech":"n.","example":"The teacher created a multimedia presentation to make the lesson more engaging.","exampleTranslation":"선생님은 수업을 더 흥미롭게 만들기 위해 멀티미디어 발표 자료를 만들었습니다.","level":37,"category":"빈도 학습"},{"id":14547,"term":"multinational","meaning":"다국적의; 다국적 기업","partOfSpeech":"adj.","example":"She got a job offer from a large multinational company based in New York.","exampleTranslation":"그녀는 뉴욕에 본사를 둔 대형 다국적 기업에서 일자리 제안을 받았습니다.","level":37,"category":"빈도 학습"},{"id":14548,"term":"muse","meaning":"뮤즈(영감의 원천); 골똘히 생각하다","partOfSpeech":"n.","example":"The artist said nature was his greatest muse for all his paintings.","exampleTranslation":"그 화가는 자연이 자신의 모든 그림에 가장 큰 영감의 원천이라고 말했습니다.","level":37,"category":"빈도 학습"},{"id":14549,"term":"mutate","meaning":"변이하다; 돌연변이가 되다","partOfSpeech":"v.","example":"Scientists are studying how the virus can mutate and spread more quickly.","exampleTranslation":"과학자들은 바이러스가 어떻게 변이하여 더 빠르게 퍼질 수 있는지 연구하고 있습니다.","level":37,"category":"빈도 학습"},{"id":14550,"term":"mute","meaning":"무음의; 말을 못 하는; 음소거하다","partOfSpeech":"adj.","example":"She pressed the mute button so no one could hear the background noise.","exampleTranslation":"그녀는 배경 소음이 들리지 않도록 음소거 버튼을 눌렀습니다.","level":37,"category":"빈도 학습"},{"id":14551,"term":"mystic","meaning":"신비로운; 신비주의자","partOfSpeech":"adj.","example":"The old temple had a mystic atmosphere that made visitors feel calm.","exampleTranslation":"그 오래된 사원은 방문객들을 평온하게 만드는 신비로운 분위기를 풍겼습니다.","level":37,"category":"빈도 학습"},{"id":14552,"term":"naive","meaning":"순진한; 세상 물정 모르는","partOfSpeech":"adj.","example":"It was naive of him to trust a stranger with all his personal information.","exampleTranslation":"모르는 사람에게 개인 정보를 모두 믿고 맡긴 것은 순진한 행동이었습니다.","level":37,"category":"빈도 학습"},{"id":14553,"term":"nationality","meaning":"국적; 민족","partOfSpeech":"n.","example":"The form asked for her name, age, and nationality.","exampleTranslation":"양식에는 이름, 나이, 국적을 기입하도록 되어 있었습니다.","level":37,"category":"빈도 학습"},{"id":14554,"term":"negligent","meaning":"부주의한; 태만한","partOfSpeech":"adj.","example":"The driver was found negligent for not checking his mirrors before turning.","exampleTranslation":"그 운전자는 회전 전에 거울을 확인하지 않은 것에 대해 부주의한 것으로 판명되었습니다.","level":37,"category":"빈도 학습"},{"id":14555,"term":"nephew","meaning":"조카(남자)","partOfSpeech":"n.","example":"She bought a birthday gift for her nephew who just turned five.","exampleTranslation":"그녀는 막 다섯 살이 된 조카를 위해 생일 선물을 샀습니다.","level":37,"category":"빈도 학습"},{"id":14556,"term":"niche","meaning":"틈새(시장); 적소; 전문 분야","partOfSpeech":"n.","example":"The small bakery found its niche by selling only gluten-free products.","exampleTranslation":"그 작은 베이커리는 글루텐 프리 제품만 판매함으로써 틈새시장을 찾았습니다.","level":37,"category":"빈도 학습"},{"id":14557,"term":"nickname","meaning":"별명; 애칭","partOfSpeech":"n.","example":"His friends gave him the nickname 'Sunny' because he always smiled.","exampleTranslation":"그의 친구들은 항상 웃는다는 이유로 그에게 '써니'라는 별명을 붙여주었습니다.","level":37,"category":"빈도 학습"},{"id":14558,"term":"nitrogen","meaning":"질소","partOfSpeech":"n.","example":"About 78 percent of the air we breathe is made up of nitrogen.","exampleTranslation":"우리가 호흡하는 공기의 약 78퍼센트는 질소로 이루어져 있습니다.","level":38,"category":"빈도 학습"},{"id":14559,"term":"node","meaning":"마디; 결절; (네트워크) 노드","partOfSpeech":"n.","example":"Each node in the network must be connected to at least one other node.","exampleTranslation":"네트워크의 각 노드는 적어도 하나의 다른 노드와 연결되어야 합니다.","level":38,"category":"빈도 학습"},{"id":14560,"term":"nominal","meaning":"명목상의; 아주 적은","partOfSpeech":"adj.","example":"There is a nominal fee to enter the community garden on weekends.","exampleTranslation":"주말에 커뮤니티 정원에 입장하려면 명목상의 요금이 있습니다.","level":38,"category":"빈도 학습"},{"id":14561,"term":"nominee","meaning":"후보자; 지명된 사람","partOfSpeech":"n.","example":"The award nominee gave a short speech before the winner was announced.","exampleTranslation":"수상 후보자는 수상자가 발표되기 전에 짧은 연설을 했습니다.","level":38,"category":"빈도 학습"},{"id":14562,"term":"nucleus","meaning":"핵; 중심","partOfSpeech":"n.","example":"The science teacher explained that every cell has a nucleus at its center.","exampleTranslation":"과학 선생님은 모든 세포의 중심에 핵이 있다고 설명했습니다.","level":38,"category":"빈도 학습"},{"id":14563,"term":"nuisance","meaning":"골칫거리; 성가신 것","partOfSpeech":"n.","example":"The loud construction noise next door was a real nuisance every morning.","exampleTranslation":"옆집의 시끄러운 공사 소음은 매일 아침 진짜 골칫거리였습니다.","level":38,"category":"빈도 학습"},{"id":14564,"term":"numb","meaning":"감각이 없는; 마비된","partOfSpeech":"adj.","example":"Her fingers went numb from holding the ice pack for too long.","exampleTranslation":"그녀의 손가락은 얼음팩을 너무 오래 잡고 있어서 감각이 없어졌습니다.","level":38,"category":"빈도 학습"},{"id":14565,"term":"numeric","meaning":"숫자의; 수치의","partOfSpeech":"adj.","example":"Please enter a numeric code to unlock your phone.","exampleTranslation":"전화기를 잠금 해제하려면 숫자 코드를 입력하세요.","level":38,"category":"빈도 학습"},{"id":14566,"term":"nun","meaning":"수녀","partOfSpeech":"n.","example":"The nun spent her mornings in prayer and her afternoons helping at the shelter.","exampleTranslation":"수녀는 오전에는 기도를 하고 오후에는 쉼터에서 봉사 활동을 했습니다.","level":38,"category":"빈도 학습"},{"id":14567,"term":"nurture","meaning":"키우다; 양육하다; 배양하다","partOfSpeech":"v.","example":"Good parents nurture their children by providing both love and guidance.","exampleTranslation":"좋은 부모는 사랑과 지도 모두를 제공하여 자녀를 키웁니다.","level":38,"category":"빈도 학습"},{"id":14568,"term":"nutrient","meaning":"영양소; 영양분","partOfSpeech":"n.","example":"Vegetables are packed with every essential nutrient your body needs.","exampleTranslation":"채소에는 몸에 필요한 모든 필수 영양소가 풍부하게 들어 있습니다.","level":38,"category":"빈도 학습"},{"id":14569,"term":"oath","meaning":"맹세; 선서","partOfSpeech":"n.","example":"The new judge took an oath to uphold the law fairly and honestly.","exampleTranslation":"새로운 판사는 법을 공정하고 정직하게 지키겠다는 선서를 했습니다.","level":38,"category":"빈도 학습"},{"id":14570,"term":"offspring","meaning":"자녀; 새끼; 후손","partOfSpeech":"n.","example":"The research looked at how parents pass their habits on to their offspring.","exampleTranslation":"연구는 부모가 어떻게 자신의 습관을 자녀에게 물려주는지를 살펴보았습니다.","level":38,"category":"빈도 학습"},{"id":14571,"term":"onset","meaning":"시작; 발병","partOfSpeech":"n.","example":"Doctors say early treatment is important at the onset of the disease.","exampleTranslation":"의사들은 질병의 발병 초기에 조기 치료가 중요하다고 말합니다.","level":38,"category":"빈도 학습"},{"id":14572,"term":"optimal","meaning":"최적의; 가장 좋은","partOfSpeech":"adj.","example":"We need to find the optimal time for the meeting so everyone can join.","exampleTranslation":"모든 사람이 참석할 수 있도록 회의를 위한 최적의 시간을 찾아야 합니다.","level":38,"category":"빈도 학습"},{"id":14573,"term":"optimism","meaning":"낙관주의; 낙천적 태도","partOfSpeech":"n.","example":"Her optimism kept the whole team motivated during the difficult project.","exampleTranslation":"그녀의 낙관주의는 힘든 프로젝트 기간 동안 팀 전체의 의욕을 유지시켜 주었습니다.","level":38,"category":"빈도 학습"},{"id":14574,"term":"orient","meaning":"방향을 잡다; 적응시키다","partOfSpeech":"v.","example":"It took a few days to orient myself in the new city after I moved.","exampleTranslation":"이사한 후 새로운 도시에서 방향을 잡는 데 며칠이 걸렸습니다.","level":38,"category":"빈도 학습"},{"id":14575,"term":"ornament","meaning":"장식품; 장식하다","partOfSpeech":"n.","example":"She hung a glass ornament on the Christmas tree by the window.","exampleTranslation":"그녀는 창가의 크리스마스 트리에 유리 장식품을 달았습니다.","level":38,"category":"빈도 학습"},{"id":14576,"term":"orphan","meaning":"고아; 고아가 되다","partOfSpeech":"n.","example":"The charity was founded to provide education for every orphan in the region.","exampleTranslation":"그 자선 단체는 지역의 모든 고아에게 교육을 제공하기 위해 설립되었습니다.","level":38,"category":"빈도 학습"},{"id":14577,"term":"outright","meaning":"완전히; 노골적인; 즉각적인","partOfSpeech":"adv.","example":"The committee rejected the proposal outright without any further discussion.","exampleTranslation":"위원회는 추가 논의 없이 제안을 즉각 거부했습니다.","level":38,"category":"빈도 학습"},{"id":14578,"term":"outset","meaning":"시작; 처음","partOfSpeech":"n.","example":"They agreed on the budget at the outset to avoid any confusion later.","exampleTranslation":"그들은 나중에 혼란을 피하기 위해 처음부터 예산에 동의했습니다.","level":38,"category":"빈도 학습"},{"id":14579,"term":"oval","meaning":"타원형; 타원의","partOfSpeech":"adj.","example":"The dining table had an oval shape that fit perfectly in the small room.","exampleTranslation":"식탁은 작은 방에 딱 맞는 타원형 모양이었습니다.","level":38,"category":"빈도 학습"},{"id":14580,"term":"override","meaning":"무시하다; 재정의하다; 우선시하다","partOfSpeech":"v.","example":"The manager can override the system's automatic decision in special cases.","exampleTranslation":"관리자는 특별한 경우에 시스템의 자동 결정을 무시할 수 있습니다.","level":38,"category":"빈도 학습"},{"id":14581,"term":"overt","meaning":"공공연한; 명백한","partOfSpeech":"adj.","example":"His overt enthusiasm for the project impressed everyone in the room.","exampleTranslation":"프로젝트에 대한 그의 공공연한 열정은 방 안의 모든 사람을 감동시켰습니다.","level":38,"category":"빈도 학습"},{"id":14582,"term":"overthrow","meaning":"타도하다; 전복시키다","partOfSpeech":"v.","example":"The protesters gathered in the capital to overthrow the corrupt government.","exampleTranslation":"시위대는 부패한 정부를 타도하기 위해 수도에 모였습니다.","level":38,"category":"빈도 학습"},{"id":14583,"term":"overview","meaning":"개요; 전반적인 설명","partOfSpeech":"n.","example":"The manager gave a quick overview of the project before the meeting started.","exampleTranslation":"관리자는 회의가 시작되기 전에 프로젝트에 대한 간략한 개요를 설명했습니다.","level":38,"category":"빈도 학습"},{"id":14584,"term":"pa","meaning":"아빠; 아버지(구어)","partOfSpeech":"n.","example":"She called her pa every Sunday evening to catch up on the week.","exampleTranslation":"그녀는 한 주를 이야기하기 위해 매주 일요일 저녁에 아빠에게 전화를 걸었습니다.","level":38,"category":"빈도 학습"},{"id":14585,"term":"pact","meaning":"협정; 조약; 약속","partOfSpeech":"n.","example":"The two friends made a pact to support each other no matter what happens.","exampleTranslation":"두 친구는 어떤 일이 있어도 서로를 지원하겠다는 협정을 맺었습니다.","level":38,"category":"빈도 학습"},{"id":14586,"term":"paddle","meaning":"노; 패들; 노를 젓다","partOfSpeech":"n.","example":"She grabbed a paddle and rowed the canoe across the lake.","exampleTranslation":"그녀는 패들을 잡고 카누를 저어 호수를 건넜습니다.","level":38,"category":"빈도 학습"},{"id":14587,"term":"pal","meaning":"친구; 동무","partOfSpeech":"n.","example":"He went to the game with his old pal from college.","exampleTranslation":"그는 대학 시절 오랜 친구와 함께 경기를 보러 갔습니다.","level":38,"category":"빈도 학습"},{"id":14588,"term":"pants","meaning":"바지","partOfSpeech":"n.","example":"He spilled coffee on his pants right before the meeting.","exampleTranslation":"그는 회의 직전에 바지에 커피를 쏟았습니다.","level":38,"category":"빈도 학습"},{"id":14589,"term":"papa","meaning":"아빠; 아버지","partOfSpeech":"n.","example":"The little girl ran to her papa as soon as he came home.","exampleTranslation":"어린 소녀는 아빠가 집에 오자마자 달려갔습니다.","level":38,"category":"빈도 학습"},{"id":14590,"term":"par","meaning":"기준; 동등; (골프) 파","partOfSpeech":"n.","example":"His work has been below par lately and his boss noticed.","exampleTranslation":"그의 업무 성과가 요즘 기준에 미치지 못해 상사가 알아챘습니다.","level":38,"category":"빈도 학습"},{"id":14591,"term":"paradigm","meaning":"패러다임; 전형적 사례","partOfSpeech":"n.","example":"The new technology created a paradigm shift in how we communicate.","exampleTranslation":"새로운 기술은 우리가 소통하는 방식에 패러다임의 전환을 가져왔습니다.","level":38,"category":"빈도 학습"},{"id":14592,"term":"paradise","meaning":"낙원; 천국","partOfSpeech":"n.","example":"The remote island felt like paradise with its clear water and white sand.","exampleTranslation":"그 외딴 섬은 맑은 물과 하얀 모래로 낙원처럼 느껴졌습니다.","level":38,"category":"빈도 학습"},{"id":14593,"term":"paralyse","meaning":"마비시키다; 무력하게 하다","partOfSpeech":"v.","example":"Fear can paralyse you if you let it take over your thoughts.","exampleTranslation":"두려움이 생각을 지배하게 내버려 두면 당신을 마비시킬 수 있습니다.","level":38,"category":"빈도 학습"},{"id":14594,"term":"parasite","meaning":"기생충; 기생하는 존재","partOfSpeech":"n.","example":"The vet found a parasite in the dog's intestines during the checkup.","exampleTranslation":"수의사가 검진 중 개의 장에서 기생충을 발견했습니다.","level":38,"category":"빈도 학습"},{"id":14595,"term":"parcel","meaning":"소포; 꾸러미","partOfSpeech":"n.","example":"A parcel arrived at my door this morning from an online store.","exampleTranslation":"오늘 아침 온라인 쇼핑몰에서 소포가 현관에 도착했습니다.","level":38,"category":"빈도 학습"},{"id":14596,"term":"partisan","meaning":"당파적인; 열렬한 지지자","partOfSpeech":"adj.","example":"The debate grew too partisan for either side to reach an agreement.","exampleTranslation":"토론이 너무 당파적으로 흘러 어느 쪽도 합의에 이르지 못했습니다.","level":38,"category":"빈도 학습"},{"id":14597,"term":"pasta","meaning":"파스타","partOfSpeech":"n.","example":"She made fresh pasta from scratch for the dinner party.","exampleTranslation":"그녀는 저녁 파티를 위해 파스타를 처음부터 직접 만들었습니다.","level":38,"category":"빈도 학습"},{"id":14598,"term":"paste","meaning":"반죽; 붙여 넣다","partOfSpeech":"n.","example":"She applied a thick paste of baking soda to clean the stain.","exampleTranslation":"그녀는 얼룩을 지우기 위해 베이킹소다 반죽을 두껍게 발랐습니다.","level":38,"category":"빈도 학습"},{"id":14599,"term":"pastel","meaning":"파스텔; 파스텔색의","partOfSpeech":"n.","example":"The nursery was painted in soft pastel colors to feel calming.","exampleTranslation":"어린이 방은 편안한 느낌을 주기 위해 부드러운 파스텔 색으로 칠해졌습니다.","level":38,"category":"빈도 학습"},{"id":14600,"term":"pastoral","meaning":"목가적인; 전원의; 목사의","partOfSpeech":"adj.","example":"The painting showed a peaceful pastoral scene with rolling hills and sheep.","exampleTranslation":"그 그림은 완만한 언덕과 양이 있는 평화로운 전원 풍경을 보여줬습니다.","level":38,"category":"빈도 학습"},{"id":14601,"term":"pastry","meaning":"패스트리; 밀가루 반죽 빵","partOfSpeech":"n.","example":"He picked up a warm pastry and a coffee from the bakery.","exampleTranslation":"그는 제과점에서 따뜻한 패스트리와 커피를 샀습니다.","level":38,"category":"빈도 학습"},{"id":14602,"term":"pasture","meaning":"목초지; 초원","partOfSpeech":"n.","example":"The cows were let out into the open pasture every morning.","exampleTranslation":"소들은 매일 아침 넓은 목초지로 내보내졌습니다.","level":38,"category":"빈도 학습"},{"id":14603,"term":"pathetic","meaning":"한심한; 불쌍한; 감동적인","partOfSpeech":"adj.","example":"It was pathetic to see him apologize and get ignored again.","exampleTranslation":"그가 사과했다가 또 무시당하는 것을 보는 것은 한심했습니다.","level":38,"category":"빈도 학습"},{"id":14604,"term":"patriarch","meaning":"가부장; 족장","partOfSpeech":"n.","example":"The patriarch of the family always led the holiday dinner traditions.","exampleTranslation":"그 가문의 가부장은 항상 명절 저녁 식사 전통을 이끌었습니다.","level":38,"category":"빈도 학습"},{"id":14605,"term":"pea","meaning":"완두콩","partOfSpeech":"n.","example":"She added a handful of pea to the vegetable soup for extra color.","exampleTranslation":"그녀는 색감을 더하기 위해 채소 수프에 완두콩 한 줌을 넣었습니다.","level":38,"category":"빈도 학습"},{"id":14606,"term":"peach","meaning":"복숭아","partOfSpeech":"n.","example":"She bit into a ripe peach and juice dripped down her chin.","exampleTranslation":"그녀는 잘 익은 복숭아를 한 입 베어 물었고 즙이 턱으로 흘러내렸습니다.","level":38,"category":"빈도 학습"},{"id":14607,"term":"pedal","meaning":"페달; 페달을 밟다","partOfSpeech":"n.","example":"He pushed the pedal harder to pick up speed on the hill.","exampleTranslation":"그는 언덕에서 속도를 높이려고 페달을 더 세게 밟았습니다.","level":38,"category":"빈도 학습"},{"id":14608,"term":"pedestrian","meaning":"보행자; 평범한","partOfSpeech":"n.","example":"A pedestrian was waiting at the crosswalk for the light to change.","exampleTranslation":"한 보행자가 신호가 바뀌길 기다리며 횡단보도에 서 있었습니다.","level":38,"category":"빈도 학습"},{"id":14609,"term":"pending","meaning":"보류 중인; 미결의","partOfSpeech":"adj.","example":"The payment is still pending and has not been processed yet.","exampleTranslation":"결제가 아직 보류 중이며 처리되지 않았습니다.","level":38,"category":"빈도 학습"},{"id":14610,"term":"peninsula","meaning":"반도","partOfSpeech":"n.","example":"The coastal town sits on a quiet peninsula surrounded by the sea.","exampleTranslation":"그 해안 마을은 바다로 둘러싸인 조용한 반도에 자리하고 있습니다.","level":38,"category":"빈도 학습"},{"id":14611,"term":"perch","meaning":"높은 자리; 앉다; 농어","partOfSpeech":"n.","example":"The cat found a perfect perch on top of the bookshelf.","exampleTranslation":"고양이는 책장 위에서 완벽한 자리를 찾았습니다.","level":38,"category":"빈도 학습"},{"id":14612,"term":"perfume","meaning":"향수; 향기","partOfSpeech":"n.","example":"She wore a light perfume that reminded him of spring flowers.","exampleTranslation":"그녀는 봄꽃을 연상시키는 가벼운 향수를 뿌렸습니다.","level":38,"category":"빈도 학습"},{"id":14613,"term":"peril","meaning":"위험; 위험에 빠뜨리다","partOfSpeech":"n.","example":"The hikers were unaware of the peril ahead on the unstable trail.","exampleTranslation":"등산객들은 불안정한 등산로 앞에 놓인 위험을 알지 못했습니다.","level":38,"category":"빈도 학습"},{"id":14614,"term":"persecute","meaning":"박해하다; 괴롭히다","partOfSpeech":"v.","example":"History shows that it is wrong to persecute people for their beliefs.","exampleTranslation":"역사는 신념 때문에 사람들을 박해하는 것이 잘못된 일임을 보여줍니다.","level":38,"category":"빈도 학습"},{"id":14615,"term":"persuasion","meaning":"설득; 신념","partOfSpeech":"n.","example":"It took a lot of persuasion to get him to try the new restaurant.","exampleTranslation":"그가 새 식당을 가보게 하려면 많은 설득이 필요했습니다.","level":38,"category":"빈도 학습"},{"id":14616,"term":"pest","meaning":"해충; 골칫거리","partOfSpeech":"n.","example":"A pest has been eating the leaves of her tomato plants in the garden.","exampleTranslation":"해충이 정원에 있는 그녀의 토마토 잎을 갉아먹고 있었습니다.","level":38,"category":"빈도 학습"},{"id":14617,"term":"pesticide","meaning":"살충제; 농약","partOfSpeech":"n.","example":"The farmer sprayed pesticide on the crops to protect them from insects.","exampleTranslation":"농부는 해충으로부터 작물을 보호하기 위해 살충제를 뿌렸습니다.","level":38,"category":"빈도 학습"},{"id":14618,"term":"petroleum","meaning":"석유","partOfSpeech":"n.","example":"Many countries depend on petroleum as their main source of energy.","exampleTranslation":"많은 나라들이 석유를 주요 에너지원으로 의존하고 있습니다.","level":38,"category":"빈도 학습"},{"id":14619,"term":"petty","meaning":"사소한; 쩨쩨한","partOfSpeech":"adj.","example":"They argued over such petty things that nobody could remember the real issue.","exampleTranslation":"그들은 너무 사소한 것들로 싸워서 아무도 진짜 문제가 무엇인지 기억하지 못했습니다.","level":38,"category":"빈도 학습"},{"id":14620,"term":"pharmaceutical","meaning":"제약의; 의약품","partOfSpeech":"adj.","example":"She got a job at a pharmaceutical company right after graduation.","exampleTranslation":"그녀는 졸업 직후 제약 회사에 취직했습니다.","level":38,"category":"빈도 학습"},{"id":14621,"term":"physicist","meaning":"물리학자","partOfSpeech":"n.","example":"The physicist spent years studying how particles behave at high speed.","exampleTranslation":"그 물리학자는 고속에서 입자가 어떻게 행동하는지 수년간 연구했습니다.","level":38,"category":"빈도 학습"},{"id":14622,"term":"pickup","meaning":"픽업; 회수; 개선","partOfSpeech":"n.","example":"I scheduled a pickup for the package at the post office.","exampleTranslation":"우체국에서 소포 픽업을 예약했습니다.","level":38,"category":"빈도 학습"},{"id":14623,"term":"picnic","meaning":"소풍; 피크닉","partOfSpeech":"n.","example":"The family packed sandwiches and went on a picnic at the park.","exampleTranslation":"가족은 샌드위치를 챙겨 공원으로 소풍을 갔습니다.","level":38,"category":"빈도 학습"},{"id":14624,"term":"pier","meaning":"부두; 교각","partOfSpeech":"n.","example":"They sat at the end of the pier and watched the sunset together.","exampleTranslation":"그들은 부두 끝에 앉아 함께 일몰을 바라봤습니다.","level":38,"category":"빈도 학습"},{"id":14625,"term":"pierce","meaning":"뚫다; 꿰뚫다","partOfSpeech":"v.","example":"The needle will pierce the skin quickly so it should not hurt much.","exampleTranslation":"바늘이 빠르게 피부를 뚫으므로 많이 아프지 않을 것입니다.","level":38,"category":"빈도 학습"},{"id":14626,"term":"pigeon","meaning":"비둘기","partOfSpeech":"n.","example":"A pigeon landed on her windowsill and pecked at the crumbs.","exampleTranslation":"비둘기 한 마리가 그녀의 창턱에 내려앉아 빵 부스러기를 쪼아 먹었습니다.","level":38,"category":"빈도 학습"},{"id":14627,"term":"pillar","meaning":"기둥; 핵심적 인물","partOfSpeech":"n.","example":"The old temple had a tall marble pillar at each corner of the entrance.","exampleTranslation":"오래된 사원은 입구 각 모서리에 높은 대리석 기둥이 있었습니다.","level":38,"category":"빈도 학습"},{"id":14628,"term":"pint","meaning":"파인트(용량 단위); 맥주 한 잔","partOfSpeech":"n.","example":"He ordered a pint of beer and watched the football match at the pub.","exampleTranslation":"그는 펍에서 맥주 한 파인트를 주문하고 축구 경기를 봤습니다.","level":38,"category":"빈도 학습"},{"id":14629,"term":"pipeline","meaning":"파이프라인; 수송관; 진행 중인 계획","partOfSpeech":"n.","example":"The company has several new products in the pipeline for next year.","exampleTranslation":"그 회사는 내년을 위해 파이프라인에 여러 신제품을 준비하고 있습니다.","level":38,"category":"빈도 학습"},{"id":14630,"term":"pirate","meaning":"해적; 저작권 침해자","partOfSpeech":"n.","example":"The children dressed up as a pirate for the school costume party.","exampleTranslation":"아이들은 학교 코스튬 파티를 위해 해적으로 변장했습니다.","level":38,"category":"빈도 학습"},{"id":14631,"term":"pistol","meaning":"권총","partOfSpeech":"n.","example":"The security guard kept a pistol in a holster on his belt.","exampleTranslation":"경비원은 벨트의 홀스터에 권총을 보관했습니다.","level":38,"category":"빈도 학습"},{"id":14632,"term":"pivot","meaning":"중심축; 방향을 전환하다","partOfSpeech":"n.","example":"The startup decided to pivot and focus on a completely different market.","exampleTranslation":"그 스타트업은 방향을 전환해 완전히 다른 시장에 집중하기로 결정했습니다.","level":38,"category":"빈도 학습"},{"id":14633,"term":"pizza","meaning":"피자","partOfSpeech":"n.","example":"They ordered a large pizza with extra cheese for movie night.","exampleTranslation":"그들은 영화 보는 밤을 위해 치즈를 추가한 라지 피자를 주문했습니다.","level":38,"category":"빈도 학습"},{"id":14634,"term":"plantation","meaning":"농장; 대농원; 조림지","partOfSpeech":"n.","example":"The tea plantation stretched across the hillside as far as they could see.","exampleTranslation":"차 농장은 그들이 볼 수 있는 한 언덕 위로 끝없이 펼쳐져 있었습니다.","level":38,"category":"빈도 학습"},{"id":14635,"term":"plasma","meaning":"플라즈마; 혈장","partOfSpeech":"n.","example":"The hospital needed plasma donations to help patients after surgery.","exampleTranslation":"병원은 수술 후 환자를 돕기 위해 혈장 기부가 필요했습니다.","level":38,"category":"빈도 학습"},{"id":14636,"term":"plaster","meaning":"석고; 반창고; 회반죽을 바르다","partOfSpeech":"n.","example":"She put a plaster on her finger after cutting it while cooking.","exampleTranslation":"그녀는 요리하다가 손가락을 베고 나서 반창고를 붙였습니다.","level":38,"category":"빈도 학습"},{"id":14637,"term":"plausible","meaning":"그럴듯한; 타당해 보이는","partOfSpeech":"adj.","example":"Her explanation sounded plausible, so we decided to believe her.","exampleTranslation":"그녀의 설명이 그럴듯하게 들려서 우리는 그녀를 믿기로 했습니다.","level":38,"category":"빈도 학습"},{"id":14638,"term":"plough","meaning":"쟁기; 쟁기로 갈다","partOfSpeech":"n.","example":"The farmer used a plough to turn the soil before planting seeds.","exampleTranslation":"농부는 씨를 뿌리기 전에 쟁기를 사용해 흙을 뒤집었습니다.","level":38,"category":"빈도 학습"},{"id":14639,"term":"pluck","meaning":"용기; 잡아당기다; 뽑다","partOfSpeech":"v.","example":"She had to pluck up the courage to speak in front of the crowd.","exampleTranslation":"그녀는 군중 앞에서 말하기 위해 용기를 내야 했습니다.","level":38,"category":"빈도 학습"},{"id":14640,"term":"plumbing","meaning":"배관; 배관 공사","partOfSpeech":"n.","example":"The plumbing in the old apartment needs to be replaced soon.","exampleTranslation":"오래된 아파트의 배관은 곧 교체해야 합니다.","level":38,"category":"빈도 학습"},{"id":14641,"term":"poise","meaning":"침착함; 균형; 자세","partOfSpeech":"n.","example":"She answered every difficult question with poise and confidence.","exampleTranslation":"그녀는 모든 어려운 질문에 침착하고 자신감 있게 답했습니다.","level":38,"category":"빈도 학습"},{"id":14642,"term":"ponder","meaning":"곰곰이 생각하다; 심사숙고하다","partOfSpeech":"v.","example":"He took a long walk to ponder his decision about changing jobs.","exampleTranslation":"그는 직업을 바꾸는 결정을 심사숙고하기 위해 오랫동안 산책했습니다.","level":38,"category":"빈도 학습"},{"id":14643,"term":"pony","meaning":"조랑말","partOfSpeech":"n.","example":"The children were excited to ride a pony at the county fair.","exampleTranslation":"아이들은 지역 박람회에서 조랑말을 타게 되어 신이 났습니다.","level":38,"category":"빈도 학습"},{"id":14644,"term":"porch","meaning":"현관; 베란다","partOfSpeech":"n.","example":"They sat on the porch and watched the sunset together.","exampleTranslation":"그들은 현관에 앉아 함께 일몰을 바라봤습니다.","level":38,"category":"빈도 학습"},{"id":14645,"term":"pork","meaning":"돼지고기","partOfSpeech":"n.","example":"She ordered a bowl of noodles with pork and vegetables.","exampleTranslation":"그녀는 돼지고기와 채소가 들어간 국수 한 그릇을 주문했습니다.","level":38,"category":"빈도 학습"},{"id":14646,"term":"posture","meaning":"자세; 태도","partOfSpeech":"n.","example":"The doctor advised her to improve her posture when sitting at a desk.","exampleTranslation":"의사는 책상에 앉을 때 자세를 개선하라고 조언했습니다.","level":38,"category":"빈도 학습"},{"id":14647,"term":"potent","meaning":"강력한; 효력 있는","partOfSpeech":"adj.","example":"The doctor prescribed a potent antibiotic to treat the infection quickly.","exampleTranslation":"의사는 감염을 빠르게 치료하기 위해 강력한 항생제를 처방했습니다.","level":38,"category":"빈도 학습"},{"id":14648,"term":"pragmatic","meaning":"실용적인; 현실적인","partOfSpeech":"adj.","example":"We need a pragmatic solution that actually works within our budget.","exampleTranslation":"우리는 예산 내에서 실제로 작동하는 실용적인 해결책이 필요합니다.","level":38,"category":"빈도 학습"},{"id":14649,"term":"precaution","meaning":"예방 조치; 사전 대비","partOfSpeech":"n.","example":"You should take every precaution when hiking in unfamiliar mountains.","exampleTranslation":"낯선 산을 등산할 때는 모든 예방 조치를 취해야 합니다.","level":38,"category":"빈도 학습"},{"id":14650,"term":"precipitate","meaning":"촉발하다; 앞당기다; 성급한","partOfSpeech":"v.","example":"The sudden announcement could precipitate a sharp drop in stock prices.","exampleTranslation":"갑작스러운 발표가 주가의 급격한 하락을 촉발할 수 있습니다.","level":38,"category":"빈도 학습"},{"id":14651,"term":"premature","meaning":"조기의; 너무 이른","partOfSpeech":"adj.","example":"It would be premature to celebrate before all the votes are counted.","exampleTranslation":"모든 투표가 집계되기 전에 축하하는 것은 너무 이릅니다.","level":38,"category":"빈도 학습"},{"id":14652,"term":"preside","meaning":"주재하다; 사회를 보다","partOfSpeech":"v.","example":"The senior professor will preside over the graduation ceremony this year.","exampleTranslation":"올해는 수석 교수님이 졸업식을 주재할 것입니다.","level":38,"category":"빈도 학습"},{"id":14653,"term":"probation","meaning":"수습 기간; 집행유예","partOfSpeech":"n.","example":"The new employee is still on probation for the first three months.","exampleTranslation":"신입 직원은 처음 3개월 동안 아직 수습 기간 중입니다.","level":38,"category":"빈도 학습"},{"id":14654,"term":"procession","meaning":"행렬; 행진","partOfSpeech":"n.","example":"A long procession of students walked across the stage to receive their diplomas.","exampleTranslation":"긴 행렬의 학생들이 졸업장을 받기 위해 무대를 가로질러 걸어갔습니다.","level":38,"category":"빈도 학습"},{"id":14655,"term":"prone","meaning":"경향이 있는; 엎드린","partOfSpeech":"adj.","example":"People who skip meals are prone to overeating later in the day.","exampleTranslation":"식사를 거르는 사람들은 나중에 과식하는 경향이 있습니다.","level":38,"category":"빈도 학습"},{"id":14656,"term":"propel","meaning":"추진하다; 나아가게 하다","partOfSpeech":"v.","example":"Hard work and dedication can propel you toward achieving your goals.","exampleTranslation":"열심히 노력하고 헌신하면 목표를 향해 나아갈 수 있습니다.","level":38,"category":"빈도 학습"},{"id":14657,"term":"prophet","meaning":"예언자; 선지자","partOfSpeech":"n.","example":"In the story, the prophet warned the king of dangers ahead.","exampleTranslation":"이야기 속에서 예언자는 왕에게 앞으로의 위험을 경고했습니다.","level":38,"category":"빈도 학습"},{"id":14658,"term":"proprietor","meaning":"소유주; 경영자","partOfSpeech":"n.","example":"The proprietor of the small bakery greeted every customer by name.","exampleTranslation":"그 작은 빵집 소유주는 모든 손님을 이름으로 맞이했습니다.","level":38,"category":"빈도 학습"},{"id":14659,"term":"prose","meaning":"산문; 일반 문장","partOfSpeech":"n.","example":"His essay was written in clear, elegant prose that was easy to follow.","exampleTranslation":"그의 에세이는 따라가기 쉬운 명확하고 우아한 산문으로 쓰였습니다.","level":38,"category":"빈도 학습"},{"id":14660,"term":"prototype","meaning":"시제품; 원형","partOfSpeech":"n.","example":"The engineers built a prototype of the new device to test its functions.","exampleTranslation":"엔지니어들은 기능을 테스트하기 위해 새 기기의 시제품을 만들었습니다.","level":38,"category":"빈도 학습"},{"id":14661,"term":"proximity","meaning":"근접; 가까움","partOfSpeech":"n.","example":"Living in close proximity to work saves her a lot of commuting time.","exampleTranslation":"직장과 가까운 곳에 사는 것이 그녀의 통근 시간을 많이 절약해 줍니다.","level":38,"category":"빈도 학습"},{"id":14662,"term":"prudent","meaning":"신중한; 분별 있는","partOfSpeech":"adj.","example":"It is prudent to save some money each month for unexpected expenses.","exampleTranslation":"예상치 못한 지출을 위해 매달 일정 금액을 저축하는 것이 신중한 행동입니다.","level":38,"category":"빈도 학습"},{"id":14663,"term":"publicize","meaning":"홍보하다; 알리다","partOfSpeech":"v.","example":"They used social media to publicize the charity event and attract volunteers.","exampleTranslation":"그들은 자선 행사를 홍보하고 자원봉사자를 모집하기 위해 소셜 미디어를 활용했습니다.","level":38,"category":"빈도 학습"},{"id":14664,"term":"puff","meaning":"훅 불다; 한 모금; 부풀리다","partOfSpeech":"v.","example":"She gave a puff on the candles and blew them all out at once.","exampleTranslation":"그녀는 촛불을 한 번에 훅 불어 모두 껐습니다.","level":38,"category":"빈도 학습"},{"id":14665,"term":"purse","meaning":"지갑; 핸드백","partOfSpeech":"n.","example":"She couldn't find her keys because they were buried in her purse.","exampleTranslation":"그녀는 열쇠가 핸드백 안 깊숙이 있어서 찾을 수 없었습니다.","level":39,"category":"빈도 학습"},{"id":14666,"term":"putt","meaning":"(골프) 퍼트; 퍼트하다","partOfSpeech":"v.","example":"He missed an easy putt on the final hole and lost the match.","exampleTranslation":"그는 마지막 홀에서 쉬운 퍼트를 놓쳐 경기에서 졌습니다.","level":39,"category":"빈도 학습"},{"id":14667,"term":"pyramid","meaning":"피라미드; 삼각뿔","partOfSpeech":"n.","example":"Visiting the ancient pyramid in Egypt was an unforgettable experience.","exampleTranslation":"이집트의 고대 피라미드를 방문하는 것은 잊을 수 없는 경험이었습니다.","level":39,"category":"빈도 학습"},{"id":14668,"term":"qualitative","meaning":"질적인; 정성적인","partOfSpeech":"adj.","example":"The study used qualitative interviews to understand people's personal experiences.","exampleTranslation":"그 연구는 사람들의 개인적인 경험을 이해하기 위해 질적 인터뷰를 활용했습니다.","level":39,"category":"빈도 학습"},{"id":14669,"term":"quantify","meaning":"수량화하다; 측정하다","partOfSpeech":"v.","example":"It is difficult to quantify the emotional impact of losing a loved one.","exampleTranslation":"사랑하는 사람을 잃는 것의 감정적 충격을 수량화하기는 어렵습니다.","level":39,"category":"빈도 학습"},{"id":14670,"term":"quantum","meaning":"양자; 양(量)","partOfSpeech":"n.","example":"Scientists are exploring how quantum computing could revolutionize data processing.","exampleTranslation":"과학자들은 양자 컴퓨팅이 데이터 처리를 어떻게 혁신할 수 있는지 연구하고 있습니다.","level":39,"category":"빈도 학습"},{"id":14671,"term":"quarrel","meaning":"다툼; 말다툼하다","partOfSpeech":"n.","example":"They had a quarrel over who should pay the bill at dinner.","exampleTranslation":"그들은 저녁 식사에서 누가 계산해야 하는지를 놓고 다퉜습니다.","level":39,"category":"빈도 학습"},{"id":14672,"term":"quarry","meaning":"채석장; 사냥감","partOfSpeech":"n.","example":"Workers at the quarry cut large blocks of stone for construction.","exampleTranslation":"채석장 직원들은 건설을 위해 큰 돌 블록을 잘랐습니다.","level":39,"category":"빈도 학습"},{"id":14673,"term":"query","meaning":"질문; 문의하다","partOfSpeech":"n.","example":"She sent a query to customer service about the delayed delivery.","exampleTranslation":"그녀는 배송 지연에 대해 고객 서비스에 문의를 보냈습니다.","level":39,"category":"빈도 학습"},{"id":14674,"term":"quest","meaning":"탐구; 추구; 여정","partOfSpeech":"n.","example":"His quest for knowledge led him to read books on almost every subject.","exampleTranslation":"지식에 대한 그의 탐구는 거의 모든 분야의 책을 읽게 만들었습니다.","level":39,"category":"빈도 학습"},{"id":14675,"term":"radar","meaning":"레이더; 탐지 장치","partOfSpeech":"n.","example":"The ship's radar detected another vessel approaching in the fog.","exampleTranslation":"선박의 레이더가 안개 속에서 접근하는 다른 선박을 감지했습니다.","level":39,"category":"빈도 학습"},{"id":14676,"term":"radioactive","meaning":"방사성의; 방사능을 띤","partOfSpeech":"adj.","example":"Workers handling radioactive materials must wear protective gear at all times.","exampleTranslation":"방사성 물질을 다루는 작업자들은 항상 보호 장비를 착용해야 합니다.","level":39,"category":"빈도 학습"},{"id":14677,"term":"rag","meaning":"낡은 천; 걸레","partOfSpeech":"n.","example":"He wiped the spill off the floor with an old rag from the garage.","exampleTranslation":"그는 차고에서 꺼낸 낡은 걸레로 바닥에 엎질러진 것을 닦았습니다.","level":39,"category":"빈도 학습"},{"id":14678,"term":"rainbow","meaning":"무지개","partOfSpeech":"n.","example":"After the heavy rain, a bright rainbow appeared across the sky.","exampleTranslation":"폭우가 그친 뒤 하늘에 밝은 무지개가 나타났습니다.","level":39,"category":"빈도 학습"},{"id":14679,"term":"rake","meaning":"갈퀴; 갈퀴질하다","partOfSpeech":"n.","example":"She used a rake to gather fallen leaves in the backyard.","exampleTranslation":"그녀는 뒷마당에 떨어진 낙엽을 모으기 위해 갈퀴를 사용했습니다.","level":39,"category":"빈도 학습"},{"id":14680,"term":"ramp","meaning":"경사로; 진입로","partOfSpeech":"n.","example":"The building has a ramp at the entrance for wheelchair users.","exampleTranslation":"그 건물에는 휠체어 이용자를 위한 경사로가 입구에 있습니다.","level":39,"category":"빈도 학습"},{"id":14681,"term":"ranch","meaning":"목장; 농장","partOfSpeech":"n.","example":"They spent the weekend at a ranch in Texas riding horses and hiking.","exampleTranslation":"그들은 텍사스의 목장에서 승마와 하이킹을 하며 주말을 보냈습니다.","level":39,"category":"빈도 학습"},{"id":14682,"term":"ratify","meaning":"비준하다; 공식 승인하다","partOfSpeech":"v.","example":"Both countries agreed to ratify the peace treaty by the end of the year.","exampleTranslation":"양국은 연말까지 평화 조약을 비준하기로 합의했습니다.","level":39,"category":"빈도 학습"},{"id":14683,"term":"ration","meaning":"배급량; 배급하다","partOfSpeech":"n.","example":"During the shortage, the government decided to ration food supplies fairly.","exampleTranslation":"부족 사태 동안 정부는 식량을 공평하게 배급하기로 결정했습니다.","level":39,"category":"빈도 학습"},{"id":14684,"term":"rationale","meaning":"근거; 이유; 논리적 근거","partOfSpeech":"n.","example":"The manager explained the rationale behind the new work-from-home policy.","exampleTranslation":"관리자는 새로운 재택근무 정책의 근거를 설명했습니다.","level":39,"category":"빈도 학습"},{"id":14685,"term":"recite","meaning":"암송하다; 낭독하다","partOfSpeech":"v.","example":"The students were asked to recite the poem they had memorized last week.","exampleTranslation":"학생들은 지난주에 외운 시를 암송해 달라는 요청을 받았습니다.","level":39,"category":"빈도 학습"},{"id":14686,"term":"reckless","meaning":"무모한; 신중하지 않은","partOfSpeech":"adj.","example":"His reckless driving caused a minor accident in the parking lot.","exampleTranslation":"그의 무모한 운전이 주차장에서 가벼운 사고를 일으켰습니다.","level":39,"category":"빈도 학습"},{"id":14687,"term":"reclaim","meaning":"되찾다; 회수하다","partOfSpeech":"v.","example":"She worked hard to reclaim her confidence after the difficult setback.","exampleTranslation":"그녀는 힘든 좌절 이후 자신감을 되찾기 위해 열심히 노력했습니다.","level":39,"category":"빈도 학습"},{"id":14688,"term":"recollect","meaning":"기억해내다; 회상하다","partOfSpeech":"v.","example":"Can you recollect where you put your passport before the trip?","exampleTranslation":"여행 전에 여권을 어디에 두었는지 기억해낼 수 있나요?","level":39,"category":"빈도 학습"},{"id":14689,"term":"rectangle","meaning":"직사각형","partOfSpeech":"n.","example":"The teacher drew a rectangle on the board to explain the area formula.","exampleTranslation":"선생님은 넓이 공식을 설명하기 위해 칠판에 직사각형을 그렸습니다.","level":39,"category":"빈도 학습"},{"id":14690,"term":"redundant","meaning":"불필요한; 중복된","partOfSpeech":"adj.","example":"The editor removed redundant sentences to make the article clearer.","exampleTranslation":"편집자는 기사를 더 명확하게 만들기 위해 중복된 문장을 삭제했습니다.","level":39,"category":"빈도 학습"},{"id":14691,"term":"reef","meaning":"암초; 산호초","partOfSpeech":"n.","example":"The divers were amazed by the colorful fish living around the reef.","exampleTranslation":"다이버들은 암초 주변에 사는 알록달록한 물고기들에 감탄했습니다.","level":39,"category":"빈도 학습"},{"id":14692,"term":"reel","meaning":"실패; 비틀거리다","partOfSpeech":"n.","example":"He grabbed a reel of fishing line from the tackle box.","exampleTranslation":"그는 낚시 도구함에서 낚싯줄 실패를 꺼냈습니다.","level":39,"category":"빈도 학습"},{"id":14693,"term":"referee","meaning":"심판; 중재자","partOfSpeech":"n.","example":"The referee blew the whistle to stop the play after the foul.","exampleTranslation":"심판은 반칙 이후 경기를 멈추기 위해 휘슬을 불었습니다.","level":39,"category":"빈도 학습"},{"id":14694,"term":"referendum","meaning":"국민투표; 주민투표","partOfSpeech":"n.","example":"The government held a referendum to decide on the new policy.","exampleTranslation":"정부는 새 정책을 결정하기 위해 국민투표를 실시했습니다.","level":39,"category":"빈도 학습"},{"id":14695,"term":"regiment","meaning":"연대; 엄격히 통제하다","partOfSpeech":"n.","example":"The regiment marched through the town during the national parade.","exampleTranslation":"연대는 국가 행진 중 마을을 행군했습니다.","level":39,"category":"빈도 학습"},{"id":14696,"term":"rein","meaning":"고삐; 통제하다","partOfSpeech":"n.","example":"The rider held the rein firmly to keep the horse under control.","exampleTranslation":"기수는 말을 통제하기 위해 고삐를 단단히 잡았습니다.","level":39,"category":"빈도 학습"},{"id":14697,"term":"relay","meaning":"전달하다; 릴레이","partOfSpeech":"v.","example":"Please relay this message to the team before the meeting starts.","exampleTranslation":"회의가 시작되기 전에 팀에 이 메시지를 전달해 주세요.","level":39,"category":"빈도 학습"},{"id":14698,"term":"relentless","meaning":"끊임없는; 가차 없는","partOfSpeech":"adj.","example":"Her relentless effort finally paid off when she passed the exam.","exampleTranslation":"끊임없는 노력이 마침내 시험에 합격하는 결실을 맺었습니다.","level":39,"category":"빈도 학습"},{"id":14699,"term":"relish","meaning":"즐기다; 맛을 즐기다","partOfSpeech":"v.","example":"He seemed to relish every bite of the homemade pasta.","exampleTranslation":"그는 집에서 만든 파스타 한 입 한 입을 즐기는 것 같았습니다.","level":39,"category":"빈도 학습"},{"id":14700,"term":"reluctance","meaning":"마지못함; 꺼림","partOfSpeech":"n.","example":"She accepted the offer with obvious reluctance but agreed in the end.","exampleTranslation":"그녀는 분명히 내키지 않는 기색으로 제안을 받아들였지만 결국 동의했습니다.","level":39,"category":"빈도 학습"},{"id":14701,"term":"remainder","meaning":"나머지; 잔여","partOfSpeech":"n.","example":"They spent the remainder of the afternoon exploring the old market.","exampleTranslation":"그들은 오후 나머지 시간을 오래된 시장을 둘러보며 보냈습니다.","level":39,"category":"빈도 학습"},{"id":14702,"term":"reminisce","meaning":"회상하다; 추억에 잠기다","partOfSpeech":"v.","example":"The old friends gathered to reminisce about their school days together.","exampleTranslation":"오랜 친구들이 학창 시절을 함께 회상하기 위해 모였습니다.","level":39,"category":"빈도 학습"},{"id":14703,"term":"renaissance","meaning":"르네상스; 부흥","partOfSpeech":"n.","example":"The city is experiencing a cultural renaissance with new galleries opening.","exampleTranslation":"그 도시는 새로운 갤러리들이 문을 열면서 문화적 부흥을 경험하고 있습니다.","level":39,"category":"빈도 학습"},{"id":14704,"term":"renown","meaning":"명성; 명망","partOfSpeech":"n.","example":"The chef gained international renown for his unique cooking style.","exampleTranslation":"그 요리사는 독특한 요리 스타일로 국제적인 명성을 얻었습니다.","level":39,"category":"빈도 학습"},{"id":14705,"term":"replicate","meaning":"복제하다; 재현하다","partOfSpeech":"v.","example":"Scientists tried to replicate the experiment under the same conditions.","exampleTranslation":"과학자들은 동일한 조건에서 실험을 재현하려고 시도했습니다.","level":39,"category":"빈도 학습"},{"id":14706,"term":"reproductive","meaning":"생식의; 번식과 관련된","partOfSpeech":"adj.","example":"The documentary covered the reproductive habits of sea turtles.","exampleTranslation":"그 다큐멘터리는 바다거북의 번식 습성을 다뤘습니다.","level":39,"category":"빈도 학습"},{"id":14707,"term":"requisite","meaning":"필수적인; 필요 조건","partOfSpeech":"adj.","example":"A valid ID is requisite to enter the event venue.","exampleTranslation":"행사장에 입장하려면 유효한 신분증이 필수입니다.","level":39,"category":"빈도 학습"},{"id":14708,"term":"reservoir","meaning":"저수지; 비축량","partOfSpeech":"n.","example":"The city's main reservoir supplies drinking water to millions of residents.","exampleTranslation":"도시의 주요 저수지는 수백만 주민에게 식수를 공급합니다.","level":39,"category":"빈도 학습"},{"id":14709,"term":"resurrect","meaning":"부활시키다; 되살리다","partOfSpeech":"v.","example":"The band decided to resurrect their classic song for the reunion concert.","exampleTranslation":"그 밴드는 재결합 콘서트를 위해 클래식 곡을 되살리기로 결정했습니다.","level":39,"category":"빈도 학습"},{"id":14710,"term":"retaliate","meaning":"보복하다; 앙갚음하다","partOfSpeech":"v.","example":"He chose not to retaliate and simply walked away from the argument.","exampleTranslation":"그는 보복하지 않기로 하고 그냥 말다툼에서 자리를 피했습니다.","level":39,"category":"빈도 학습"},{"id":14711,"term":"retention","meaning":"보유; 유지","partOfSpeech":"n.","example":"The company improved staff retention by offering better benefits.","exampleTranslation":"회사는 더 나은 복리후생을 제공하여 직원 유지율을 높였습니다.","level":39,"category":"빈도 학습"},{"id":14712,"term":"retrospect","meaning":"회고; 되돌아봄","partOfSpeech":"n.","example":"In retrospect, taking that job was the best decision she ever made.","exampleTranslation":"되돌아보면, 그 일자리를 택한 것이 그녀가 한 최고의 결정이었습니다.","level":39,"category":"빈도 학습"},{"id":14713,"term":"reunion","meaning":"재회; 동창회","partOfSpeech":"n.","example":"The family planned a reunion at their grandmother's house this summer.","exampleTranslation":"가족은 이번 여름 할머니 댁에서 재회를 계획했습니다.","level":39,"category":"빈도 학습"},{"id":14714,"term":"revenge","meaning":"복수; 앙갚음","partOfSpeech":"n.","example":"He wanted revenge but eventually decided to forgive and move on.","exampleTranslation":"그는 복수를 원했지만 결국 용서하고 앞으로 나아가기로 결심했습니다.","level":39,"category":"빈도 학습"},{"id":14715,"term":"revere","meaning":"존경하다; 경외하다","partOfSpeech":"v.","example":"The students revere their professor for his wisdom and dedication.","exampleTranslation":"학생들은 교수님의 지혜와 헌신을 존경합니다.","level":39,"category":"빈도 학습"},{"id":14716,"term":"revolt","meaning":"반란; 반란을 일으키다","partOfSpeech":"n.","example":"The workers staged a revolt against the unfair working conditions.","exampleTranslation":"노동자들은 불공정한 근무 환경에 맞서 반란을 일으켰습니다.","level":39,"category":"빈도 학습"},{"id":14717,"term":"revolve","meaning":"회전하다; 중심으로 돌다","partOfSpeech":"v.","example":"The Earth takes one year to revolve around the Sun.","exampleTranslation":"지구가 태양을 한 바퀴 공전하는 데 1년이 걸립니다.","level":39,"category":"빈도 학습"},{"id":14718,"term":"ribbon","meaning":"리본; 띠","partOfSpeech":"n.","example":"She tied a pink ribbon around the gift box before handing it over.","exampleTranslation":"그녀는 선물 상자를 건네기 전에 분홍색 리본을 묶었습니다.","level":39,"category":"빈도 학습"},{"id":14719,"term":"rig","meaning":"장비; 조작하다","partOfSpeech":"n.","example":"The workers set up a rig to drill for oil in the open sea.","exampleTranslation":"작업자들은 공해에서 석유를 시추하기 위해 장비를 설치했습니다.","level":39,"category":"빈도 학습"},{"id":14720,"term":"rim","meaning":"테두리; 가장자리","partOfSpeech":"n.","example":"He tapped the rim of his glass lightly to get everyone's attention.","exampleTranslation":"그는 모두의 주의를 끌기 위해 유리잔의 테두리를 살짝 두드렸습니다.","level":39,"category":"빈도 학습"},{"id":14721,"term":"rinse","meaning":"헹구다; 씻어내다","partOfSpeech":"v.","example":"Make sure to rinse the vegetables thoroughly before cooking them.","exampleTranslation":"요리하기 전에 채소를 꼼꼼히 헹궈야 합니다.","level":39,"category":"빈도 학습"},{"id":14722,"term":"ripple","meaning":"잔물결; 퍼져 나가다","partOfSpeech":"n.","example":"A small stone created a ripple that spread across the calm lake.","exampleTranslation":"작은 돌 하나가 잔물결을 만들어 고요한 호수 위로 퍼져 나갔습니다.","level":39,"category":"빈도 학습"},{"id":14723,"term":"rite","meaning":"의식; 의례","partOfSpeech":"n.","example":"The wedding ceremony included a traditional rite passed down for generations.","exampleTranslation":"결혼 의식에는 대대로 전해 내려온 전통 의례가 포함되었습니다.","level":39,"category":"빈도 학습"},{"id":14724,"term":"roam","meaning":"돌아다니다; 배회하다","partOfSpeech":"v.","example":"They were free to roam the countryside during their vacation.","exampleTranslation":"그들은 휴가 동안 시골을 자유롭게 돌아다닐 수 있었습니다.","level":39,"category":"빈도 학습"},{"id":14725,"term":"robe","meaning":"가운; 예복","partOfSpeech":"n.","example":"She put on a warm robe after stepping out of the shower.","exampleTranslation":"그녀는 샤워 후 따뜻한 가운을 걸쳤습니다.","level":39,"category":"빈도 학습"},{"id":14726,"term":"robust","meaning":"강건한; 튼튼한","partOfSpeech":"adj.","example":"The company built a robust system that can handle heavy traffic.","exampleTranslation":"그 회사는 높은 트래픽을 처리할 수 있는 강건한 시스템을 구축했습니다.","level":39,"category":"빈도 학습"},{"id":14727,"term":"rove","meaning":"돌아다니다; 방랑하다","partOfSpeech":"v.","example":"He spent his youth to rove across different countries and cultures.","exampleTranslation":"그는 청년 시절을 여러 나라와 문화를 돌아다니며 보냈습니다.","level":39,"category":"빈도 학습"},{"id":14728,"term":"rumble","meaning":"우르릉 소리; 우르릉거리다","partOfSpeech":"n.","example":"We heard a loud rumble of thunder just before the rain started.","exampleTranslation":"비가 시작되기 직전에 큰 천둥 소리가 들렸습니다.","level":39,"category":"빈도 학습"},{"id":14729,"term":"runway","meaning":"활주로; 패션쇼 무대","partOfSpeech":"n.","example":"The pilot checked the runway carefully before starting the takeoff.","exampleTranslation":"파일럿은 이륙을 시작하기 전에 활주로를 주의 깊게 확인했습니다.","level":39,"category":"빈도 학습"},{"id":14730,"term":"rust","meaning":"녹; 녹슬다","partOfSpeech":"n.","example":"There was visible rust on the old iron gate outside the house.","exampleTranslation":"집 밖의 오래된 철문에 눈에 띄는 녹이 있었습니다.","level":39,"category":"빈도 학습"},{"id":14731,"term":"ruthless","meaning":"무자비한; 냉혹한","partOfSpeech":"adj.","example":"The ruthless competitor did whatever it took to win the contract.","exampleTranslation":"그 냉혹한 경쟁자는 계약을 따내기 위해 무슨 일이든 했습니다.","level":39,"category":"빈도 학습"},{"id":14733,"term":"saddle","meaning":"안장; 안장을 얹다","partOfSpeech":"n.","example":"The instructor showed her how to fit the saddle onto the horse properly.","exampleTranslation":"강사는 말에 안장을 제대로 얹는 방법을 그녀에게 알려주었습니다.","level":39,"category":"빈도 학습"},{"id":14734,"term":"salon","meaning":"미용실; 살롱","partOfSpeech":"n.","example":"She made an appointment at the salon to get her hair colored.","exampleTranslation":"그녀는 머리를 염색하기 위해 미용실에 예약을 잡았습니다.","level":39,"category":"빈도 학습"},{"id":14735,"term":"salute","meaning":"경례하다; 인사하다","partOfSpeech":"v.","example":"The soldiers were asked to salute the flag during the ceremony.","exampleTranslation":"의식 중에 군인들은 국기에 경례하도록 요청받았습니다.","level":39,"category":"빈도 학습"},{"id":14736,"term":"salvation","meaning":"구원; 구제","partOfSpeech":"n.","example":"He found salvation in his faith after going through a very difficult time.","exampleTranslation":"그는 매우 힘든 시간을 보낸 후 신앙 안에서 구원을 찾았습니다.","level":39,"category":"빈도 학습"},{"id":14737,"term":"sanctuary","meaning":"성역; 피난처; 보호구역","partOfSpeech":"n.","example":"The old library became a sanctuary for students who needed quiet.","exampleTranslation":"그 오래된 도서관은 조용함이 필요한 학생들의 피난처가 되었습니다.","level":39,"category":"빈도 학습"},{"id":14738,"term":"saturate","meaning":"포화시키다; 흠뻑 적시다","partOfSpeech":"v.","example":"Heavy rain will saturate the soil and make hiking difficult.","exampleTranslation":"폭우가 토양을 흠뻑 적셔 하이킹을 어렵게 만들 것입니다.","level":39,"category":"빈도 학습"},{"id":14739,"term":"scarf","meaning":"스카프; 목도리","partOfSpeech":"n.","example":"She wrapped the scarf tightly around her neck to stay warm.","exampleTranslation":"그녀는 따뜻하게 지내기 위해 목에 스카프를 단단히 둘렀습니다.","level":39,"category":"빈도 학습"},{"id":14740,"term":"scoop","meaning":"퍼 올리다; 특종; 한 국자","partOfSpeech":"v.","example":"Can you scoop some ice cream into my bowl, please?","exampleTranslation":"제 그릇에 아이스크림 좀 퍼 주실 수 있나요?","level":39,"category":"빈도 학습"},{"id":14741,"term":"scripture","meaning":"성경; 경전","partOfSpeech":"n.","example":"The priest read a passage from scripture at the beginning of the service.","exampleTranslation":"사제는 예배 시작 때 성경의 한 구절을 읽었습니다.","level":39,"category":"빈도 학습"},{"id":14742,"term":"scrub","meaning":"문질러 씻다; 취소하다","partOfSpeech":"v.","example":"You need to scrub the pan carefully to remove the burned food.","exampleTranslation":"눌어붙은 음식을 제거하려면 냄비를 꼼꼼히 문질러 씻어야 합니다.","level":39,"category":"빈도 학습"},{"id":14743,"term":"seam","meaning":"솔기; 이음새","partOfSpeech":"n.","example":"The seam on my jacket tore after I wore it for years.","exampleTranslation":"몇 년 동안 입고 나니 재킷의 솔기가 뜯어졌습니다.","level":39,"category":"빈도 학습"},{"id":14744,"term":"sediment","meaning":"침전물; 퇴적물","partOfSpeech":"n.","example":"The river carried sediment down from the mountains over many years.","exampleTranslation":"강은 수년에 걸쳐 산에서 침전물을 실어 내려왔습니다.","level":39,"category":"빈도 학습"},{"id":14745,"term":"seduce","meaning":"유혹하다; 꾀다","partOfSpeech":"v.","example":"The advertisement tried to seduce customers with a promise of luxury.","exampleTranslation":"그 광고는 사치를 약속하며 고객들을 유혹하려 했습니다.","level":39,"category":"빈도 학습"},{"id":14746,"term":"segregate","meaning":"분리하다; 격리하다","partOfSpeech":"v.","example":"It is important to segregate recyclable materials from regular trash.","exampleTranslation":"재활용 가능한 재료를 일반 쓰레기와 분리하는 것이 중요합니다.","level":39,"category":"빈도 학습"},{"id":14747,"term":"semantic","meaning":"의미론적인; 의미와 관련된","partOfSpeech":"adj.","example":"There is a semantic difference between the words 'house' and 'home'.","exampleTranslation":"'house'와 'home'이라는 단어 사이에는 의미론적 차이가 있습니다.","level":39,"category":"빈도 학습"},{"id":14748,"term":"sensor","meaning":"감지기; 센서","partOfSpeech":"n.","example":"The sensor on the front door detects motion and turns on the light.","exampleTranslation":"현관문의 센서가 움직임을 감지해 불을 켭니다.","level":39,"category":"빈도 학습"},{"id":14749,"term":"serial","meaning":"연속적인; 연재물","partOfSpeech":"adj.","example":"The podcast was released as a serial with new episodes every week.","exampleTranslation":"그 팟캐스트는 매주 새 에피소드가 나오는 연재 형식으로 공개되었습니다.","level":39,"category":"빈도 학습"},{"id":14750,"term":"sermon","meaning":"설교; 훈계","partOfSpeech":"n.","example":"The pastor gave a sermon about the importance of kindness and forgiveness.","exampleTranslation":"목사는 친절과 용서의 중요성에 관한 설교를 했습니다.","level":39,"category":"빈도 학습"},{"id":14751,"term":"serum","meaning":"혈청; 세럼","partOfSpeech":"n.","example":"She applied a vitamin C serum to her face every morning.","exampleTranslation":"그녀는 매일 아침 얼굴에 비타민 C 세럼을 발랐습니다.","level":39,"category":"빈도 학습"},{"id":14752,"term":"sever","meaning":"절단하다; 끊다","partOfSpeech":"v.","example":"The company decided to sever ties with the unreliable supplier.","exampleTranslation":"그 회사는 신뢰할 수 없는 공급업체와의 관계를 끊기로 결정했습니다.","level":39,"category":"빈도 학습"},{"id":14753,"term":"sewage","meaning":"하수; 오수","partOfSpeech":"n.","example":"The old neighborhood lacked a proper system to handle sewage.","exampleTranslation":"그 오래된 동네는 하수를 처리할 제대로 된 시스템이 없었습니다.","level":39,"category":"빈도 학습"},{"id":14754,"term":"shark","meaning":"상어; 사기꾼","partOfSpeech":"n.","example":"Divers spotted a shark swimming near the coral reef.","exampleTranslation":"다이버들이 산호초 근처에서 헤엄치는 상어를 발견했습니다.","level":39,"category":"빈도 학습"},{"id":14755,"term":"shepherd","meaning":"양치기; 이끌다","partOfSpeech":"n.","example":"The shepherd led his flock of sheep across the grassy hillside.","exampleTranslation":"양치기는 양 떼를 풀이 우거진 언덕을 가로질러 이끌었습니다.","level":39,"category":"빈도 학습"},{"id":14756,"term":"shred","meaning":"잘게 찢다; 파쇄하다; 조각","partOfSpeech":"v.","example":"Please shred any documents that contain personal information.","exampleTranslation":"개인 정보가 담긴 서류는 파쇄해 주세요.","level":39,"category":"빈도 학습"},{"id":14757,"term":"shrimp","meaning":"새우","partOfSpeech":"n.","example":"I ordered a shrimp salad and a glass of lemonade for lunch.","exampleTranslation":"점심으로 새우 샐러드와 레모네이드 한 잔을 주문했습니다.","level":39,"category":"빈도 학습"},{"id":14758,"term":"shrine","meaning":"성소; 신사; 사당","partOfSpeech":"n.","example":"Thousands of visitors come to the shrine during the annual festival.","exampleTranslation":"연례 축제 기간에 수천 명의 방문객이 그 신사를 찾아옵니다.","level":39,"category":"빈도 학습"},{"id":14759,"term":"shrub","meaning":"관목; 덤불","partOfSpeech":"n.","example":"They planted a low shrub along the garden fence for privacy.","exampleTranslation":"그들은 사생활 보호를 위해 정원 울타리를 따라 낮은 관목을 심었습니다.","level":39,"category":"빈도 학습"},{"id":14760,"term":"shudder","meaning":"몸서리치다; 전율하다","partOfSpeech":"v.","example":"She began to shudder when she heard the strange noise outside.","exampleTranslation":"그녀는 밖에서 이상한 소리를 듣자 몸서리치기 시작했습니다.","level":39,"category":"빈도 학습"},{"id":14761,"term":"shuffle","meaning":"뒤섞다; 발을 끌며 걷다","partOfSpeech":"v.","example":"Please shuffle the cards well before we start the game.","exampleTranslation":"게임을 시작하기 전에 카드를 잘 섞어 주세요.","level":39,"category":"빈도 학습"},{"id":14762,"term":"shuttle","meaning":"셔틀; 왕복 운행하다","partOfSpeech":"n.","example":"The hotel provides a free shuttle from the airport to the lobby.","exampleTranslation":"호텔은 공항에서 로비까지 무료 셔틀을 제공합니다.","level":39,"category":"빈도 학습"},{"id":14763,"term":"sibling","meaning":"형제자매","partOfSpeech":"n.","example":"Do you have a sibling, or are you an only child?","exampleTranslation":"형제자매가 있나요, 아니면 외동인가요?","level":39,"category":"빈도 학습"},{"id":14764,"term":"siege","meaning":"포위; 공성전","partOfSpeech":"n.","example":"The city endured a long siege before the army broke through.","exampleTranslation":"그 도시는 군대가 돌파하기 전까지 오랜 포위를 버텨냈습니다.","level":39,"category":"빈도 학습"},{"id":14765,"term":"signify","meaning":"의미하다; 나타내다","partOfSpeech":"v.","example":"A red light on the device will signify that the battery is low.","exampleTranslation":"기기의 빨간 불빛은 배터리가 부족함을 나타냅니다.","level":39,"category":"빈도 학습"},{"id":14766,"term":"silicon","meaning":"실리콘; 규소","partOfSpeech":"n.","example":"Silicon is a key material used in the production of computer chips.","exampleTranslation":"실리콘은 컴퓨터 칩 생산에 사용되는 핵심 소재입니다.","level":39,"category":"빈도 학습"},{"id":14767,"term":"simmer","meaning":"약불로 끓이다; 부글부글 끓다","partOfSpeech":"v.","example":"Let the soup simmer for twenty minutes to develop the flavor.","exampleTranslation":"맛을 내기 위해 수프를 20분 동안 약불로 끓이세요.","level":39,"category":"빈도 학습"},{"id":14768,"term":"simplicity","meaning":"단순함; 소박함","partOfSpeech":"n.","example":"I admire the simplicity of the design — it's clean and easy to use.","exampleTranslation":"저는 그 디자인의 단순함이 마음에 들어요. 깔끔하고 사용하기 쉬워요.","level":39,"category":"빈도 학습"},{"id":14769,"term":"singular","meaning":"단수의; 유일한; 특이한","partOfSpeech":"adj.","example":"She has a singular talent for making people feel at ease.","exampleTranslation":"그녀는 사람들을 편안하게 만드는 유일한 재능을 가지고 있습니다.","level":39,"category":"빈도 학습"},{"id":14770,"term":"skate","meaning":"스케이트를 타다; 스케이트","partOfSpeech":"v.","example":"We went to the rink to skate together on a cold winter afternoon.","exampleTranslation":"우리는 추운 겨울 오후에 함께 스케이트를 타러 링크장에 갔습니다.","level":39,"category":"빈도 학습"},{"id":14771,"term":"skeleton","meaning":"골격; 해골; 뼈대","partOfSpeech":"n.","example":"The museum displayed the skeleton of a large dinosaur in the main hall.","exampleTranslation":"박물관은 중앙 홀에 커다란 공룡의 골격을 전시했습니다.","level":39,"category":"빈도 학습"},{"id":14772,"term":"slab","meaning":"두꺼운 판; 슬래브","partOfSpeech":"n.","example":"Workers lifted a heavy slab of concrete to repair the sidewalk.","exampleTranslation":"인부들이 인도를 수리하기 위해 무거운 콘크리트 판을 들어 올렸습니다.","level":39,"category":"빈도 학습"},{"id":14773,"term":"slack","meaning":"느슨한; 부진한; 여유","partOfSpeech":"adj.","example":"Business has been slack this month, so the store closes early.","exampleTranslation":"이번 달은 영업이 부진해서 가게가 일찍 문을 닫습니다.","level":40,"category":"빈도 학습"},{"id":14774,"term":"slash","meaning":"베다; 대폭 삭감하다; 빗금","partOfSpeech":"v.","example":"The store decided to slash prices by fifty percent during the sale.","exampleTranslation":"그 가게는 세일 기간에 가격을 50% 대폭 삭감하기로 결정했습니다.","level":40,"category":"빈도 학습"},{"id":14775,"term":"slate","meaning":"슬레이트(암석); 예정하다; 후보 명단","partOfSpeech":"n.","example":"The old cottage had a slate roof that lasted over a hundred years.","exampleTranslation":"그 오래된 농가는 100년 이상 지속된 슬레이트 지붕을 가지고 있었습니다.","level":40,"category":"빈도 학습"},{"id":14776,"term":"slaughter","meaning":"도살하다; 학살; 대패시키다","partOfSpeech":"v.","example":"The documentary shows how animals are slaughter at industrial farms.","exampleTranslation":"그 다큐멘터리는 산업 농장에서 동물이 도살되는 방식을 보여줍니다.","level":40,"category":"빈도 학습"},{"id":14777,"term":"slender","meaning":"가느다란; 날씬한; 빈약한","partOfSpeech":"adj.","example":"She had slender fingers that were perfect for playing the piano.","exampleTranslation":"그녀는 피아노 연주에 완벽한 가느다란 손가락을 가지고 있었습니다.","level":40,"category":"빈도 학습"},{"id":14778,"term":"slick","meaning":"매끄러운; 능숙한; 기름막","partOfSpeech":"adj.","example":"The floor was slick after the janitor mopped it, so be careful.","exampleTranslation":"청소부가 걸레질한 후 바닥이 미끄러우니 조심하세요.","level":40,"category":"빈도 학습"},{"id":14779,"term":"slogan","meaning":"슬로건; 표어","partOfSpeech":"n.","example":"The campaign's slogan was simple and easy for everyone to remember.","exampleTranslation":"그 캠페인의 슬로건은 단순하고 모두가 기억하기 쉬웠습니다.","level":40,"category":"빈도 학습"},{"id":14780,"term":"smack","meaning":"철썩 때리다; 탁 치다; 맛","partOfSpeech":"v.","example":"He accidentally smack his knee on the edge of the table.","exampleTranslation":"그는 실수로 무릎을 테이블 모서리에 부딪혔습니다.","level":40,"category":"빈도 학습"},{"id":14781,"term":"smear","meaning":"바르다; 더럽히다; 얼룩","partOfSpeech":"v.","example":"The child managed to smear paint all over the kitchen table.","exampleTranslation":"아이가 주방 식탁 전체에 물감을 발라버렸습니다.","level":40,"category":"빈도 학습"},{"id":14782,"term":"smuggle","meaning":"밀수하다; 몰래 들여오다","partOfSpeech":"v.","example":"Customs officers caught a man trying to smuggle rare animals into the country.","exampleTranslation":"세관원들이 희귀 동물을 나라 안으로 밀수하려는 남자를 붙잡았습니다.","level":40,"category":"빈도 학습"},{"id":14783,"term":"sneak","meaning":"몰래 움직이다; 살금살금 가다","partOfSpeech":"v.","example":"The kids tried to sneak downstairs to get more dessert after bedtime.","exampleTranslation":"아이들은 잠자리에 든 후 디저트를 더 먹으러 아래층으로 살금살금 내려가려 했습니다.","level":40,"category":"빈도 학습"},{"id":14784,"term":"sniff","meaning":"코를 킁킁거리다; 냄새를 맡다","partOfSpeech":"v.","example":"The dog started to sniff around the yard, looking for something.","exampleTranslation":"개가 무언가를 찾으며 마당 여기저기 냄새를 맡기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14785,"term":"sob","meaning":"흐느끼다; 흐느낌","partOfSpeech":"v.","example":"She began to sob quietly when she heard the sad news.","exampleTranslation":"그녀는 슬픈 소식을 듣자 조용히 흐느끼기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14786,"term":"sober","meaning":"술에 취하지 않은; 냉정한","partOfSpeech":"adj.","example":"He decided to stay sober at the party so he could drive everyone home.","exampleTranslation":"그는 모두를 집에 데려다 줄 수 있도록 파티에서 술을 마시지 않기로 했습니다.","level":40,"category":"빈도 학습"},{"id":14787,"term":"socialise","meaning":"어울리다; 사교 활동을 하다","partOfSpeech":"v.","example":"It can be hard to socialise with new coworkers at first.","exampleTranslation":"처음에는 새 동료들과 어울리는 것이 어려울 수 있습니다.","level":40,"category":"빈도 학습"},{"id":14788,"term":"socialism","meaning":"사회주의","partOfSpeech":"n.","example":"The professor explained how socialism differs from capitalism in class.","exampleTranslation":"교수님은 수업에서 사회주의가 자본주의와 어떻게 다른지 설명했습니다.","level":40,"category":"빈도 학습"},{"id":14789,"term":"socket","meaning":"소켓; 콘센트; 구멍","partOfSpeech":"n.","example":"Please plug the charger into the socket on the wall.","exampleTranslation":"벽에 있는 콘센트에 충전기를 꽂아 주세요.","level":40,"category":"빈도 학습"},{"id":14790,"term":"sofa","meaning":"소파","partOfSpeech":"n.","example":"We spent the whole afternoon lounging on the sofa and watching movies.","exampleTranslation":"우리는 오후 내내 소파에 누워 영화를 봤습니다.","level":40,"category":"빈도 학습"},{"id":14791,"term":"solemn","meaning":"엄숙한; 진지한","partOfSpeech":"adj.","example":"The ceremony was solemn and everyone stood quietly in respect.","exampleTranslation":"그 의식은 엄숙했고 모두가 경의를 표하며 조용히 서 있었습니다.","level":40,"category":"빈도 학습"},{"id":14792,"term":"solicitor","meaning":"변호사; 법률 대리인","partOfSpeech":"n.","example":"She hired a solicitor to help her with the property purchase.","exampleTranslation":"그녀는 부동산 매입을 도와줄 변호사를 고용했습니다.","level":40,"category":"빈도 학습"},{"id":14793,"term":"solidarity","meaning":"연대; 단결","partOfSpeech":"n.","example":"The workers showed solidarity by standing together during the strike.","exampleTranslation":"노동자들은 파업 중 함께 서서 연대를 보여 주었습니다.","level":40,"category":"빈도 학습"},{"id":14794,"term":"solitary","meaning":"혼자인; 고독한","partOfSpeech":"adj.","example":"He enjoys solitary walks in the park early in the morning.","exampleTranslation":"그는 이른 아침에 공원에서 혼자 산책하는 것을 즐깁니다.","level":40,"category":"빈도 학습"},{"id":14795,"term":"soothe","meaning":"달래다; 진정시키다","partOfSpeech":"v.","example":"She sang softly to soothe the crying baby.","exampleTranslation":"그녀는 우는 아기를 달래기 위해 부드럽게 노래를 불렀습니다.","level":40,"category":"빈도 학습"},{"id":14796,"term":"sorrow","meaning":"슬픔; 비탄","partOfSpeech":"n.","example":"His face was full of sorrow when he heard the bad news.","exampleTranslation":"그는 나쁜 소식을 들었을 때 얼굴이 슬픔으로 가득했습니다.","level":40,"category":"빈도 학습"},{"id":14797,"term":"sow","meaning":"씨를 뿌리다; 심다","partOfSpeech":"v.","example":"The farmer will sow the seeds in early spring before the rains come.","exampleTranslation":"농부는 비가 오기 전 이른 봄에 씨를 뿌릴 것입니다.","level":40,"category":"빈도 학습"},{"id":14798,"term":"spa","meaning":"스파; 온천","partOfSpeech":"n.","example":"After the long hike, she relaxed at the spa for the rest of the evening.","exampleTranslation":"긴 하이킹 후 그녀는 저녁 내내 스파에서 휴식을 취했습니다.","level":40,"category":"빈도 학습"},{"id":14799,"term":"spawn","meaning":"낳다; 생기게 하다","partOfSpeech":"v.","example":"The viral video managed to spawn dozens of similar online trends.","exampleTranslation":"그 바이럴 영상은 수십 개의 유사한 온라인 트렌드를 만들어냈습니다.","level":40,"category":"빈도 학습"},{"id":14800,"term":"spear","meaning":"창; 창으로 찌르다","partOfSpeech":"n.","example":"The museum displayed an ancient spear used by warriors centuries ago.","exampleTranslation":"박물관에는 수백 년 전 전사들이 사용한 고대 창이 전시되어 있었습니다.","level":40,"category":"빈도 학습"},{"id":14801,"term":"spectator","meaning":"관중; 구경꾼","partOfSpeech":"n.","example":"Every spectator cheered loudly when the team scored the final goal.","exampleTranslation":"팀이 마지막 골을 넣자 모든 관중이 크게 환호했습니다.","level":40,"category":"빈도 학습"},{"id":14802,"term":"spider","meaning":"거미","partOfSpeech":"n.","example":"There was a large spider sitting in the corner of the bathroom.","exampleTranslation":"욕실 구석에 큰 거미 한 마리가 앉아 있었습니다.","level":40,"category":"빈도 학습"},{"id":14803,"term":"spiral","meaning":"나선형; 소용돌이치다","partOfSpeech":"n.","example":"The staircase was built in a beautiful spiral shape inside the tower.","exampleTranslation":"계단은 탑 안에 아름다운 나선형으로 만들어졌습니다.","level":40,"category":"빈도 학습"},{"id":14804,"term":"spite","meaning":"악의; 앙심","partOfSpeech":"n.","example":"He said those cruel words out of spite rather than honesty.","exampleTranslation":"그는 솔직함이 아니라 악의로 그런 잔인한 말을 했습니다.","level":40,"category":"빈도 학습"},{"id":14805,"term":"splendid","meaning":"훌륭한; 멋진","partOfSpeech":"adj.","example":"We had a splendid view of the city from the top of the hill.","exampleTranslation":"우리는 언덕 꼭대기에서 도시의 멋진 전경을 보았습니다.","level":40,"category":"빈도 학습"},{"id":14806,"term":"sprawl","meaning":"펼쳐지다; 아무렇게나 눕다","partOfSpeech":"v.","example":"He was so tired that he decided to sprawl on the couch after work.","exampleTranslation":"그는 너무 피곤해서 퇴근 후 소파에 쭉 뻗어 누웠습니다.","level":40,"category":"빈도 학습"},{"id":14807,"term":"sprinkle","meaning":"뿌리다; 흩뿌리다","partOfSpeech":"v.","example":"She decided to sprinkle some cheese on top of the pasta.","exampleTranslation":"그녀는 파스타 위에 치즈를 조금 뿌리기로 했습니다.","level":40,"category":"빈도 학습"},{"id":14808,"term":"sprint","meaning":"전력 질주하다; 단거리 달리기","partOfSpeech":"v.","example":"He had to sprint to catch the bus before it left the stop.","exampleTranslation":"그는 버스가 정류장을 떠나기 전에 잡기 위해 전력 질주해야 했습니다.","level":40,"category":"빈도 학습"},{"id":14809,"term":"sprout","meaning":"싹트다; 새싹","partOfSpeech":"v.","example":"The seeds began to sprout just three days after we planted them.","exampleTranslation":"씨앗을 심은 지 불과 사흘 만에 싹이 트기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14810,"term":"squash","meaning":"짓누르다; 호박; 스쿼시","partOfSpeech":"v.","example":"Be careful not to squash the bread when you put it in the bag.","exampleTranslation":"가방에 넣을 때 빵이 눌리지 않도록 조심하세요.","level":40,"category":"빈도 학습"},{"id":14811,"term":"squat","meaning":"쪼그려 앉다; 스쿼트","partOfSpeech":"v.","example":"She did twenty squat repetitions as part of her morning workout.","exampleTranslation":"그녀는 아침 운동의 일환으로 스쿼트를 20번 반복했습니다.","level":40,"category":"빈도 학습"},{"id":14812,"term":"staircase","meaning":"계단; 층계","partOfSpeech":"n.","example":"The old mansion had a grand staircase leading up to the second floor.","exampleTranslation":"그 오래된 저택에는 2층으로 이어지는 웅장한 계단이 있었습니다.","level":40,"category":"빈도 학습"},{"id":14813,"term":"stalk","meaning":"줄기; 몰래 따라다니다","partOfSpeech":"n.","example":"She snapped the stalk off the flower before putting it in a vase.","exampleTranslation":"그녀는 꽃을 꽃병에 꽂기 전에 줄기를 꺾었습니다.","level":40,"category":"빈도 학습"},{"id":14814,"term":"stark","meaning":"완전한; 황량한; 냉혹한","partOfSpeech":"adj.","example":"The report presented a stark reminder of how serious the problem has become.","exampleTranslation":"그 보고서는 문제가 얼마나 심각해졌는지를 냉혹하게 상기시켜 주었습니다.","level":40,"category":"빈도 학습"},{"id":14815,"term":"static","meaning":"정적인; 변화 없는; 잡음","partOfSpeech":"adj.","example":"The economy has remained static for the past two quarters with no real growth.","exampleTranslation":"경제는 실질적인 성장 없이 지난 두 분기 동안 정체 상태를 유지했습니다.","level":40,"category":"빈도 학습"},{"id":14816,"term":"stepmother","meaning":"계모; 새어머니","partOfSpeech":"n.","example":"His stepmother moved in with the family after his father remarried last year.","exampleTranslation":"그의 계모는 아버지가 작년에 재혼한 후 가족과 함께 살게 되었습니다.","level":40,"category":"빈도 학습"},{"id":14817,"term":"stereo","meaning":"스테레오; 입체 음향","partOfSpeech":"n.","example":"He turned on the stereo and the room filled with music.","exampleTranslation":"그가 스테레오를 켜자 방이 음악으로 가득 찼습니다.","level":40,"category":"빈도 학습"},{"id":14818,"term":"sterile","meaning":"무균의; 불임의; 메마른","partOfSpeech":"adj.","example":"The nurse used sterile gloves before treating the patient's wound.","exampleTranslation":"간호사는 환자의 상처를 치료하기 전에 무균 장갑을 사용했습니다.","level":40,"category":"빈도 학습"},{"id":14819,"term":"sterling","meaning":"영국 파운드; 순은; 뛰어난","partOfSpeech":"n.","example":"The price of the item was listed in sterling on the British website.","exampleTranslation":"그 물건의 가격은 영국 웹사이트에 파운드화로 표시되어 있었습니다.","level":40,"category":"빈도 학습"},{"id":14820,"term":"steward","meaning":"승무원; 관리인","partOfSpeech":"n.","example":"The steward brought extra blankets to passengers on the overnight flight.","exampleTranslation":"승무원은 야간 비행 승객들에게 여분의 담요를 가져다주었습니다.","level":40,"category":"빈도 학습"},{"id":14821,"term":"sticky","meaning":"끈적한; 달라붙는","partOfSpeech":"adj.","example":"The table was sticky because someone had spilled juice on it.","exampleTranslation":"누군가 주스를 쏟아서 테이블이 끈적거렸습니다.","level":40,"category":"빈도 학습"},{"id":14822,"term":"stink","meaning":"악취가 나다; 냄새","partOfSpeech":"v.","example":"The garbage can began to stink after sitting in the sun all day.","exampleTranslation":"쓰레기통이 하루 종일 햇볕에 있다 보니 악취가 나기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14823,"term":"stool","meaning":"의자; 스툴; 변","partOfSpeech":"n.","example":"She sat on a tall stool at the kitchen counter while eating breakfast.","exampleTranslation":"그녀는 아침을 먹으면서 주방 카운터의 높은 스툴에 앉았습니다.","level":40,"category":"빈도 학습"},{"id":14824,"term":"stove","meaning":"가스레인지; 난로","partOfSpeech":"n.","example":"He left the stove on by accident and the soup boiled over.","exampleTranslation":"그는 실수로 가스레인지를 켜둬서 수프가 넘쳐버렸습니다.","level":40,"category":"빈도 학습"},{"id":14825,"term":"stray","meaning":"길을 잃은; 떠돌다","partOfSpeech":"adj.","example":"They found a stray cat hiding behind the building and brought it inside.","exampleTranslation":"그들은 건물 뒤에 숨어 있는 길 잃은 고양이를 발견해 안으로 데려왔습니다.","level":40,"category":"빈도 학습"},{"id":14826,"term":"strive","meaning":"노력하다; 분투하다","partOfSpeech":"v.","example":"She continues to strive for excellence in everything she does at work.","exampleTranslation":"그녀는 직장에서 하는 모든 일에서 탁월함을 위해 계속 노력합니다.","level":40,"category":"빈도 학습"},{"id":14827,"term":"stubborn","meaning":"고집스러운; 완고한","partOfSpeech":"adj.","example":"He is so stubborn that he refuses to ask for help even when he needs it.","exampleTranslation":"그는 너무 고집스러워서 도움이 필요할 때도 도움을 요청하기를 거부합니다.","level":40,"category":"빈도 학습"},{"id":14828,"term":"stud","meaning":"스터드; 장식 못; 종마","partOfSpeech":"n.","example":"She wore a simple diamond stud in each ear for the formal event.","exampleTranslation":"그녀는 공식 행사에서 각 귀에 간단한 다이아몬드 스터드를 착용했습니다.","level":40,"category":"빈도 학습"},{"id":14829,"term":"stump","meaning":"그루터기; 당황하게 하다","partOfSpeech":"n.","example":"They sat on the old stump in the yard to rest after clearing the trees.","exampleTranslation":"그들은 나무를 정리한 후 쉬기 위해 마당의 오래된 그루터기에 앉았습니다.","level":40,"category":"빈도 학습"},{"id":14830,"term":"submarine","meaning":"잠수함; 잠수의","partOfSpeech":"n.","example":"The navy sent a submarine to monitor the area beneath the surface.","exampleTranslation":"해군은 수면 아래 지역을 감시하기 위해 잠수함을 보냈습니다.","level":40,"category":"빈도 학습"},{"id":14831,"term":"submission","meaning":"제출; 복종","partOfSpeech":"n.","example":"The deadline for submission of the report is this Friday at noon.","exampleTranslation":"보고서 제출 마감일은 이번 주 금요일 정오입니다.","level":40,"category":"빈도 학습"},{"id":14832,"term":"substantive","meaning":"실질적인; 중요한","partOfSpeech":"adj.","example":"The two sides finally had a substantive discussion about the contract terms.","exampleTranslation":"양측은 마침내 계약 조건에 대해 실질적인 논의를 나눴습니다.","level":40,"category":"빈도 학습"},{"id":14833,"term":"sulphur","meaning":"황(黃); 유황","partOfSpeech":"n.","example":"The strong smell of sulphur near the volcano made it hard to breathe.","exampleTranslation":"화산 근처의 강한 유황 냄새로 숨쉬기가 힘들었습니다.","level":40,"category":"빈도 학습"},{"id":14834,"term":"superficial","meaning":"표면적인; 피상적인","partOfSpeech":"adj.","example":"The damage to the car looked serious but turned out to be superficial.","exampleTranslation":"차 손상이 심각해 보였지만 알고 보니 표면적인 것에 불과했습니다.","level":40,"category":"빈도 학습"},{"id":14835,"term":"superintendent","meaning":"감독관; 관리자","partOfSpeech":"n.","example":"The superintendent visited the school to review the new teaching program.","exampleTranslation":"감독관은 새 교육 프로그램을 검토하기 위해 학교를 방문했습니다.","level":40,"category":"빈도 학습"},{"id":14836,"term":"surf","meaning":"서핑하다; 파도타기하다; 인터넷을 검색하다","partOfSpeech":"v.","example":"He loves to surf early in the morning before the beach gets crowded.","exampleTranslation":"그는 해변이 붐비기 전 이른 아침에 서핑하는 것을 좋아합니다.","level":40,"category":"빈도 학습"},{"id":14837,"term":"surgical","meaning":"외과의; 수술의; 정밀한","partOfSpeech":"adj.","example":"The doctor performed a surgical procedure to remove the small tumor.","exampleTranslation":"의사는 작은 종양을 제거하기 위해 외과적 시술을 시행했습니다.","level":40,"category":"빈도 학습"},{"id":14838,"term":"surveillance","meaning":"감시; 감독","partOfSpeech":"n.","example":"The parking lot is under constant surveillance by security cameras.","exampleTranslation":"주차장은 보안 카메라로 24시간 감시되고 있습니다.","level":40,"category":"빈도 학습"},{"id":14839,"term":"susceptible","meaning":"영향받기 쉬운; 취약한","partOfSpeech":"adj.","example":"Young children are more susceptible to colds during the winter months.","exampleTranslation":"어린아이들은 겨울철에 감기에 더 취약합니다.","level":40,"category":"빈도 학습"},{"id":14840,"term":"swamp","meaning":"늪; 압도하다","partOfSpeech":"n.","example":"The hikers carefully avoided the swamp on the edge of the trail.","exampleTranslation":"등산객들은 등산로 끝에 있는 늪을 조심스럽게 피했습니다.","level":40,"category":"빈도 학습"},{"id":14841,"term":"swap","meaning":"교환하다; 바꾸다","partOfSpeech":"v.","example":"Can we swap seats so I can sit closer to the window?","exampleTranslation":"창문 쪽에 더 가깝게 앉을 수 있도록 자리를 바꿀 수 있을까요?","level":40,"category":"빈도 학습"},{"id":14842,"term":"sway","meaning":"흔들리다; 영향을 미치다; 흔들림","partOfSpeech":"v.","example":"The tall trees began to sway gently in the evening breeze.","exampleTranslation":"키 큰 나무들이 저녁 산들바람에 부드럽게 흔들리기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14843,"term":"sweater","meaning":"스웨터; 두꺼운 상의","partOfSpeech":"n.","example":"She put on a warm sweater before heading out into the cold morning.","exampleTranslation":"그녀는 추운 아침에 나가기 전에 따뜻한 스웨터를 입었습니다.","level":40,"category":"빈도 학습"},{"id":14844,"term":"swirl","meaning":"소용돌이치다; 빙빙 돌다","partOfSpeech":"v.","example":"The leaves began to swirl around in circles as the wind picked up.","exampleTranslation":"바람이 강해지자 나뭇잎들이 원을 그리며 소용돌이치기 시작했습니다.","level":40,"category":"빈도 학습"},{"id":14845,"term":"symmetry","meaning":"대칭; 균형","partOfSpeech":"n.","example":"The architect designed the building with perfect symmetry on both sides.","exampleTranslation":"건축가는 양쪽이 완벽한 대칭을 이루도록 건물을 설계했습니다.","level":40,"category":"빈도 학습"},{"id":14846,"term":"symphony","meaning":"교향곡; 심포니","partOfSpeech":"n.","example":"The orchestra performed a beautiful symphony at the concert hall last night.","exampleTranslation":"오케스트라는 어젯밤 콘서트홀에서 아름다운 교향곡을 연주했습니다.","level":40,"category":"빈도 학습"},{"id":14847,"term":"synthetic","meaning":"합성의; 인조의","partOfSpeech":"adj.","example":"The jacket is made from synthetic materials that are water-resistant.","exampleTranslation":"그 재킷은 방수 기능이 있는 합성 소재로 만들어졌습니다.","level":40,"category":"빈도 학습"},{"id":14848,"term":"tablet","meaning":"태블릿; 알약; 석판","partOfSpeech":"n.","example":"She uses a tablet to read e-books and watch videos during her commute.","exampleTranslation":"그녀는 출퇴근 중에 태블릿으로 전자책을 읽고 동영상을 봅니다.","level":40,"category":"빈도 학습"},{"id":14849,"term":"tabloid","meaning":"타블로이드 신문; 선정적 신문","partOfSpeech":"n.","example":"The celebrity refused to comment on the story published in the tabloid.","exampleTranslation":"그 유명인은 타블로이드 신문에 실린 기사에 대한 언급을 거부했습니다.","level":40,"category":"빈도 학습"},{"id":14850,"term":"tack","meaning":"압정; 방향을 바꾸다; 가봉하다","partOfSpeech":"n.","example":"She used a tack to pin the notice up on the bulletin board.","exampleTranslation":"그녀는 게시판에 공지를 붙이기 위해 압정을 사용했습니다.","level":40,"category":"빈도 학습"},{"id":14851,"term":"tailor","meaning":"재단사; 맞춤 제작하다","partOfSpeech":"n.","example":"He visited the tailor to have his suit adjusted before the wedding.","exampleTranslation":"그는 결혼식 전에 정장을 수선하기 위해 재단사를 찾아갔습니다.","level":40,"category":"빈도 학습"},{"id":14852,"term":"tame","meaning":"길들여진; 길들이다; 따분한","partOfSpeech":"adj.","example":"The tame deer at the park would eat right out of visitors' hands.","exampleTranslation":"공원의 길들여진 사슴은 방문객들의 손에서 바로 먹이를 먹었습니다.","level":40,"category":"빈도 학습"},{"id":14853,"term":"tan","meaning":"햇볕에 그을린; 황갈색; 선탠하다","partOfSpeech":"adj.","example":"She came back from vacation with a deep tan from spending days on the beach.","exampleTranslation":"그녀는 해변에서 며칠을 보낸 후 깊이 그을린 피부로 휴가에서 돌아왔습니다.","level":40,"category":"빈도 학습"},{"id":14854,"term":"tangible","meaning":"유형의; 실질적인; 만질 수 있는","partOfSpeech":"adj.","example":"The manager wanted tangible evidence before making any final decision.","exampleTranslation":"관리자는 최종 결정을 내리기 전에 실질적인 증거를 원했습니다.","level":40,"category":"빈도 학습"},{"id":14855,"term":"tariff","meaning":"관세; 요금표","partOfSpeech":"n.","example":"The government raised the tariff on imported steel to protect local producers.","exampleTranslation":"정부는 국내 생산자를 보호하기 위해 수입 철강에 대한 관세를 인상했습니다.","level":40,"category":"빈도 학습"},{"id":14856,"term":"technician","meaning":"기술자; 전문 기사","partOfSpeech":"n.","example":"A technician came to the office to fix the broken air conditioning unit.","exampleTranslation":"기술자가 고장난 에어컨 유닛을 수리하러 사무실에 왔습니다.","level":40,"category":"빈도 학습"},{"id":14857,"term":"tee","meaning":"티(골프); T자 모양; 티셔츠","partOfSpeech":"n.","example":"He placed the ball on the tee and took a deep breath before his first swing.","exampleTranslation":"그는 첫 번째 스윙 전에 티 위에 공을 올려놓고 깊게 숨을 들이쉬었습니다.","level":40,"category":"빈도 학습"},{"id":14858,"term":"teen","meaning":"십 대; 청소년","partOfSpeech":"n.","example":"The community center offers free programs for every teen in the neighborhood.","exampleTranslation":"지역 센터는 동네의 모든 십 대를 위한 무료 프로그램을 제공합니다.","level":40,"category":"빈도 학습"},{"id":14859,"term":"telegraph","meaning":"전신; 전보를 치다","partOfSpeech":"n.","example":"Before telephones, people sent urgent messages by telegraph across the country.","exampleTranslation":"전화가 생기기 전에 사람들은 전국에 걸쳐 전신으로 긴급 메시지를 보냈습니다.","level":40,"category":"빈도 학습"},{"id":14860,"term":"temper","meaning":"성질; 화; 감정을 조절하다","partOfSpeech":"n.","example":"He has a short temper and gets frustrated very easily under pressure.","exampleTranslation":"그는 성질이 급해서 압박을 받으면 아주 쉽게 짜증을 냅니다.","level":40,"category":"빈도 학습"},{"id":14861,"term":"temperament","meaning":"기질; 성격; 천성","partOfSpeech":"n.","example":"Her calm temperament makes her an excellent mediator in team conflicts.","exampleTranslation":"그녀의 차분한 기질은 팀 갈등에서 훌륭한 중재자가 되게 해줍니다.","level":40,"category":"빈도 학습"},{"id":14862,"term":"temporal","meaning":"시간의; 일시적인; 현세의","partOfSpeech":"adj.","example":"The researcher studied temporal patterns in how people use social media.","exampleTranslation":"연구원은 사람들이 소셜 미디어를 사용하는 방식에서 시간적 패턴을 연구했습니다.","level":40,"category":"빈도 학습"},{"id":14863,"term":"tentative","meaning":"잠정적인; 확정되지 않은; 소극적인","partOfSpeech":"adj.","example":"We made a tentative plan to meet on Friday but haven't confirmed yet.","exampleTranslation":"우리는 금요일에 만날 잠정적인 계획을 세웠지만 아직 확정하지 않았습니다.","level":40,"category":"빈도 학습"},{"id":14864,"term":"tenure","meaning":"재임 기간; 종신 재직권","partOfSpeech":"n.","example":"During his tenure as principal, the school's test scores improved significantly.","exampleTranslation":"그의 교장 재임 기간 동안 학교의 시험 점수가 크게 향상되었습니다.","level":40,"category":"빈도 학습"},{"id":14865,"term":"terrain","meaning":"지형; 지대","partOfSpeech":"n.","example":"The soldiers trained on rough terrain to prepare for mountain operations.","exampleTranslation":"병사들은 산악 작전을 대비하기 위해 험준한 지형에서 훈련했습니다.","level":40,"category":"빈도 학습"},{"id":14866,"term":"terrific","meaning":"훌륭한; 굉장한; 대단한","partOfSpeech":"adj.","example":"You did a terrific job on the presentation — everyone was really impressed.","exampleTranslation":"발표를 훌륭하게 해주셨어요 — 모두가 정말 감동받았습니다.","level":40,"category":"빈도 학습"},{"id":14867,"term":"testify","meaning":"증언하다; 입증하다","partOfSpeech":"v.","example":"The witness was asked to testify about what she saw on the night of the incident.","exampleTranslation":"목격자는 사건 당일 밤 자신이 본 것에 대해 증언해 달라는 요청을 받았습니다.","level":40,"category":"빈도 학습"},{"id":14868,"term":"theological","meaning":"신학의; 종교적인","partOfSpeech":"adj.","example":"The two professors had a long theological debate about the nature of faith.","exampleTranslation":"두 교수는 믿음의 본질에 관해 긴 신학적 토론을 벌였습니다.","level":40,"category":"빈도 학습"},{"id":14869,"term":"therapeutic","meaning":"치료의; 치유적인","partOfSpeech":"adj.","example":"Many people find gardening to be therapeutic after a stressful week at work.","exampleTranslation":"많은 사람들은 스트레스 받는 한 주를 보낸 후 원예 가꾸기가 치유적이라고 느낍니다.","level":40,"category":"빈도 학습"},{"id":14870,"term":"thereafter","meaning":"그 이후에; 그 후로","partOfSpeech":"adv.","example":"She graduated in June and thereafter moved to a new city for work.","exampleTranslation":"그녀는 6월에 졸업하고 그 이후에 일을 위해 새 도시로 이사했습니다.","level":40,"category":"빈도 학습"},{"id":14871,"term":"thermal","meaning":"열의; 온열의; 보온성의","partOfSpeech":"adj.","example":"She packed thermal underwear for the camping trip in cold weather.","exampleTranslation":"그녀는 추운 날씨의 캠핑 여행을 위해 보온 내의를 챙겼습니다.","level":40,"category":"빈도 학습"},{"id":14872,"term":"throne","meaning":"왕좌; 왕위","partOfSpeech":"n.","example":"The golden throne stood at the center of the palace's grand hall.","exampleTranslation":"황금 왕좌는 궁전의 웅장한 홀 중앙에 서 있었습니다.","level":40,"category":"빈도 학습"},{"id":14873,"term":"thump","meaning":"쿵 치다; 쿵 하는 소리","partOfSpeech":"v.","example":"I heard a loud thump from upstairs and went to check on my roommate.","exampleTranslation":"위층에서 쿵 하는 큰 소리가 들려 룸메이트를 확인하러 올라갔습니다.","level":40,"category":"빈도 학습"},{"id":14874,"term":"tidy","meaning":"정돈된; 깔끔한; 정리하다","partOfSpeech":"adj.","example":"She keeps her desk tidy so she can find things quickly when needed.","exampleTranslation":"그녀는 필요할 때 빠르게 물건을 찾을 수 있도록 책상을 항상 정돈해 둡니다.","level":40,"category":"빈도 학습"},{"id":14875,"term":"toddle","meaning":"아장아장 걷다; 천천히 걷다","partOfSpeech":"v.","example":"The baby learned to toddle across the living room floor last week.","exampleTranslation":"아기는 지난 주에 거실 바닥을 가로질러 아장아장 걷는 법을 배웠습니다.","level":40,"category":"빈도 학습"},{"id":14876,"term":"token","meaning":"표시; 상징; 토큰; 사소한","partOfSpeech":"n.","example":"He gave her a small gift as a token of his appreciation for her help.","exampleTranslation":"그는 그녀의 도움에 감사의 표시로 작은 선물을 주었습니다.","level":40,"category":"빈도 학습"},{"id":14877,"term":"tolerance","meaning":"관용; 인내; 허용 범위","partOfSpeech":"n.","example":"Building tolerance for different viewpoints is an important life skill.","exampleTranslation":"다양한 관점에 대한 관용을 기르는 것은 중요한 삶의 기술입니다.","level":40,"category":"빈도 학습"},{"id":14878,"term":"tolerant","meaning":"관대한; 이해심 있는","partOfSpeech":"adj.","example":"A good teacher must be tolerant of students who learn at different speeds.","exampleTranslation":"좋은 선생님은 다양한 속도로 배우는 학생들에게 관대해야 합니다.","level":40,"category":"빈도 학습"},{"id":14879,"term":"toll","meaning":"통행료; 희생; 종을 울리다","partOfSpeech":"n.","example":"We had to pay a toll to cross the bridge on the highway.","exampleTranslation":"우리는 고속도로 다리를 건너기 위해 통행료를 내야 했습니다.","level":41,"category":"빈도 학습"},{"id":14880,"term":"tomb","meaning":"무덤; 묘소","partOfSpeech":"n.","example":"Tourists came from all over the world to visit the ancient pharaoh's tomb.","exampleTranslation":"관광객들은 고대 파라오의 무덤을 방문하기 위해 전 세계에서 찾아왔습니다.","level":41,"category":"빈도 학습"},{"id":14881,"term":"torch","meaning":"횃불; 손전등","partOfSpeech":"n.","example":"He carried a torch through the dark cave to find the exit.","exampleTranslation":"그는 출구를 찾기 위해 어두운 동굴 안에서 횃불을 들고 나아갔습니다.","level":41,"category":"빈도 학습"},{"id":14882,"term":"torment","meaning":"고통; 괴롭히다","partOfSpeech":"n.","example":"Constant back pain was a torment that affected his daily life for years.","exampleTranslation":"지속적인 허리 통증은 수년 동안 그의 일상생활에 영향을 미친 고통이었습니다.","level":41,"category":"빈도 학습"},{"id":14883,"term":"tow","meaning":"견인하다; 끌다","partOfSpeech":"v.","example":"The truck came to tow away the broken-down car from the side of the road.","exampleTranslation":"트럭이 도로변에 고장난 자동차를 견인하러 왔습니다.","level":41,"category":"빈도 학습"},{"id":14884,"term":"tract","meaning":"지역; 소책자; 관(管)","partOfSpeech":"n.","example":"The developer purchased a large tract of land on the edge of the city.","exampleTranslation":"개발업자는 도시 외곽에 있는 넓은 땅을 매입했습니다.","level":41,"category":"빈도 학습"},{"id":14885,"term":"tractor","meaning":"트랙터; 견인차","partOfSpeech":"n.","example":"The farmer drove his tractor across the field to prepare the soil for planting.","exampleTranslation":"농부는 파종을 위해 토양을 준비하려고 트랙터를 몰고 밭을 가로질렀습니다.","level":41,"category":"빈도 학습"},{"id":14886,"term":"trailer","meaning":"예고편; 트레일러; 트레일러 하우스","partOfSpeech":"n.","example":"We watched the trailer for the new movie before buying tickets.","exampleTranslation":"우리는 티켓을 구매하기 전에 새 영화의 예고편을 봤습니다.","level":41,"category":"빈도 학습"},{"id":14887,"term":"tranquil","meaning":"고요한; 평온한","partOfSpeech":"adj.","example":"The garden was tranquil in the early morning before the city woke up.","exampleTranslation":"도시가 깨어나기 전 이른 아침에 정원은 고요했습니다.","level":41,"category":"빈도 학습"},{"id":14888,"term":"transcend","meaning":"초월하다; 넘어서다","partOfSpeech":"v.","example":"Great music can transcend language and connect people from all cultures.","exampleTranslation":"훌륭한 음악은 언어를 초월하여 모든 문화권의 사람들을 연결할 수 있습니다.","level":41,"category":"빈도 학습"},{"id":14889,"term":"transit","meaning":"통과; 운송; 대중교통","partOfSpeech":"n.","example":"The goods were damaged while in transit to the warehouse.","exampleTranslation":"화물은 창고로 운송되는 도중에 손상되었습니다.","level":41,"category":"빈도 학습"},{"id":14890,"term":"transparent","meaning":"투명한; 명백한","partOfSpeech":"adj.","example":"The company wants to be transparent about how it uses customer data.","exampleTranslation":"그 회사는 고객 데이터를 사용하는 방식에 대해 투명하게 공개하고 싶어합니다.","level":41,"category":"빈도 학습"},{"id":14891,"term":"tread","meaning":"밟다; 걷다; 발걸음","partOfSpeech":"v.","example":"Be careful not to tread on the wet floor after mopping.","exampleTranslation":"걸레질 후 젖은 바닥을 밟지 않도록 조심하세요.","level":41,"category":"빈도 학습"},{"id":14892,"term":"trench","meaning":"도랑; 참호","partOfSpeech":"n.","example":"Workers dug a trench along the road to lay new water pipes.","exampleTranslation":"작업자들은 새 수도관을 설치하기 위해 도로를 따라 도랑을 팠습니다.","level":41,"category":"빈도 학습"},{"id":14893,"term":"trickle","meaning":"조금씩 흐르다; 소량","partOfSpeech":"v.","example":"Sweat began to trickle down his forehead during the long hike.","exampleTranslation":"긴 등산 중 땀이 그의 이마를 타고 흘러내리기 시작했습니다.","level":41,"category":"빈도 학습"},{"id":14894,"term":"trio","meaning":"세 사람; 삼중주","partOfSpeech":"n.","example":"The trio performed a jazz song at the school talent show.","exampleTranslation":"세 사람은 학교 장기 자랑에서 재즈 곡을 연주했습니다.","level":41,"category":"빈도 학습"},{"id":14895,"term":"triple","meaning":"세 배의; 세 배로 늘리다","partOfSpeech":"adj.","example":"The company managed to triple its profits over the past two years.","exampleTranslation":"그 회사는 지난 2년 동안 수익을 세 배로 늘리는 데 성공했습니다.","level":41,"category":"빈도 학습"},{"id":14896,"term":"trivial","meaning":"사소한; 하찮은","partOfSpeech":"adj.","example":"Don't waste your energy on such trivial matters.","exampleTranslation":"그런 사소한 문제에 에너지를 낭비하지 마세요.","level":41,"category":"빈도 학습"},{"id":14897,"term":"trot","meaning":"빠르게 걷다; 속보","partOfSpeech":"v.","example":"The dog began to trot ahead of its owner along the trail.","exampleTranslation":"개는 산책로에서 주인보다 앞서 종종걸음으로 걷기 시작했습니다.","level":41,"category":"빈도 학습"},{"id":14898,"term":"trout","meaning":"송어","partOfSpeech":"n.","example":"He caught a large trout in the mountain stream early in the morning.","exampleTranslation":"그는 이른 아침에 산 개울에서 큰 송어를 잡았습니다.","level":41,"category":"빈도 학습"},{"id":14899,"term":"trumpet","meaning":"트럼펫; 나팔","partOfSpeech":"n.","example":"She has been playing the trumpet in the school band for three years.","exampleTranslation":"그녀는 3년 동안 학교 밴드에서 트럼펫을 연주해 왔습니다.","level":41,"category":"빈도 학습"},{"id":14900,"term":"tub","meaning":"욕조; 통","partOfSpeech":"n.","example":"He filled the tub with warm water and took a long bath.","exampleTranslation":"그는 욕조에 따뜻한 물을 채우고 오랫동안 목욕을 했습니다.","level":41,"category":"빈도 학습"},{"id":14901,"term":"turbulence","meaning":"난기류; 격동; 혼란","partOfSpeech":"n.","example":"The pilot asked passengers to fasten their seatbelts due to turbulence.","exampleTranslation":"기장은 난기류로 인해 승객들에게 안전벨트를 매달라고 요청했습니다.","level":41,"category":"빈도 학습"},{"id":14902,"term":"turf","meaning":"잔디; 영역; 세력권","partOfSpeech":"n.","example":"The groundskeeper worked hard to keep the turf in perfect condition.","exampleTranslation":"경기장 관리인은 잔디를 완벽한 상태로 유지하기 위해 열심히 일했습니다.","level":41,"category":"빈도 학습"},{"id":14903,"term":"turtle","meaning":"거북이","partOfSpeech":"n.","example":"A sea turtle slowly swam past us while we were snorkeling.","exampleTranslation":"우리가 스노클링을 하는 동안 바다거북이 천천히 우리 곁을 지나갔습니다.","level":41,"category":"빈도 학습"},{"id":14904,"term":"twitch","meaning":"씰룩거리다; 경련; 빠른 움직임","partOfSpeech":"v.","example":"His eye started to twitch from too much stress and lack of sleep.","exampleTranslation":"과도한 스트레스와 수면 부족으로 그의 눈이 씰룩거리기 시작했습니다.","level":41,"category":"빈도 학습"},{"id":14905,"term":"typed","meaning":"타이핑된; 유형이 분류된","partOfSpeech":"adj.","example":"The application form must be typed and printed before submission.","exampleTranslation":"지원서는 제출 전에 타이핑하여 인쇄해야 합니다.","level":41,"category":"빈도 학습"},{"id":14906,"term":"ulcer","meaning":"궤양","partOfSpeech":"n.","example":"The doctor found that stress had caused a stomach ulcer.","exampleTranslation":"의사는 스트레스가 위궤양을 유발했다는 것을 발견했습니다.","level":41,"category":"빈도 학습"},{"id":14907,"term":"umbrella","meaning":"우산","partOfSpeech":"n.","example":"She forgot her umbrella and got completely soaked in the rain.","exampleTranslation":"그녀는 우산을 잊어버려서 빗속에서 완전히 흠뻑 젖었습니다.","level":41,"category":"빈도 학습"},{"id":14908,"term":"un","meaning":"아닌; 반대의(접두어)","partOfSpeech":"prefix","example":"Adding un to a word often gives it the opposite meaning, as in unhappy.","exampleTranslation":"단어 앞에 이 접두사를 붙이면 '불행한'처럼 반대 의미가 되는 경우가 많습니다.","level":41,"category":"빈도 학습"},{"id":14909,"term":"unanimous","meaning":"만장일치의; 이의 없는","partOfSpeech":"adj.","example":"The board reached a unanimous decision to approve the new policy.","exampleTranslation":"이사회는 새 정책을 승인하는 만장일치 결정에 이르렀습니다.","level":41,"category":"빈도 학습"},{"id":14910,"term":"underestimate","meaning":"과소평가하다; 너무 낮게 평가하다","partOfSpeech":"v.","example":"Don't underestimate how long the project will take to finish.","exampleTranslation":"프로젝트를 완료하는 데 얼마나 걸릴지 과소평가하지 마세요.","level":41,"category":"빈도 학습"},{"id":14911,"term":"undergraduate","meaning":"학부생; 대학원 이전의","partOfSpeech":"n.","example":"As an undergraduate, she took a wide variety of courses each semester.","exampleTranslation":"학부생으로서 그녀는 매 학기 다양한 과목을 수강했습니다.","level":41,"category":"빈도 학습"},{"id":14912,"term":"underline","meaning":"밑줄을 긋다; 강조하다","partOfSpeech":"v.","example":"Please underline the key vocabulary words as you read the passage.","exampleTranslation":"지문을 읽으면서 핵심 어휘 단어에 밑줄을 그어 주세요.","level":41,"category":"빈도 학습"},{"id":14913,"term":"uphold","meaning":"지지하다; 유지하다; 옹호하다","partOfSpeech":"v.","example":"It is the court's duty to uphold the rights guaranteed by the law.","exampleTranslation":"법이 보장하는 권리를 지지하는 것은 법원의 의무입니다.","level":41,"category":"빈도 학습"},{"id":14914,"term":"upright","meaning":"직립의; 꼿꼿한; 정직한","partOfSpeech":"adj.","example":"The physical therapist told him to sit upright to avoid back pain.","exampleTranslation":"물리치료사는 허리 통증을 피하려면 똑바로 앉으라고 말했습니다.","level":41,"category":"빈도 학습"},{"id":14915,"term":"urine","meaning":"소변; 오줌","partOfSpeech":"n.","example":"The nurse asked the patient to provide a urine sample for testing.","exampleTranslation":"간호사는 환자에게 검사를 위한 소변 샘플을 제공해 달라고 요청했습니다.","level":41,"category":"빈도 학습"},{"id":14916,"term":"usage","meaning":"사용법; 용법; 사용량","partOfSpeech":"n.","example":"The teacher explained the correct usage of articles in English sentences.","exampleTranslation":"선생님은 영어 문장에서 관사의 올바른 용법을 설명했습니다.","level":41,"category":"빈도 학습"},{"id":14917,"term":"usher","meaning":"안내하다; 안내원","partOfSpeech":"v.","example":"A staff member will usher you to your seat before the show begins.","exampleTranslation":"공연이 시작되기 전에 직원이 좌석으로 안내해 드릴 것입니다.","level":41,"category":"빈도 학습"},{"id":14919,"term":"vacant","meaning":"비어 있는; 공석의","partOfSpeech":"adj.","example":"There is a vacant seat next to me if you would like to join us.","exampleTranslation":"합류하고 싶으시면 제 옆에 빈자리가 있습니다.","level":41,"category":"빈도 학습"},{"id":14920,"term":"vacation","meaning":"휴가; 방학","partOfSpeech":"n.","example":"We are planning a vacation to Japan next summer.","exampleTranslation":"우리는 다음 여름에 일본으로 휴가를 계획하고 있습니다.","level":41,"category":"빈도 학습"},{"id":14921,"term":"vacuum","meaning":"진공; 진공청소기; 진공청소기로 청소하다","partOfSpeech":"n.","example":"She used a vacuum to clean up all the dust from the carpet.","exampleTranslation":"그녀는 카펫의 먼지를 모두 청소하기 위해 진공청소기를 사용했습니다.","level":41,"category":"빈도 학습"},{"id":14922,"term":"valve","meaning":"밸브; 판막","partOfSpeech":"n.","example":"The plumber replaced the old valve to stop the water from leaking.","exampleTranslation":"배관공은 물이 새는 것을 막기 위해 낡은 밸브를 교체했습니다.","level":41,"category":"빈도 학습"},{"id":14923,"term":"vase","meaning":"꽃병","partOfSpeech":"n.","example":"She placed fresh flowers in a vase on the dining table.","exampleTranslation":"그녀는 식탁 위 꽃병에 신선한 꽃을 꽂았습니다.","level":41,"category":"빈도 학습"},{"id":14924,"term":"vegetation","meaning":"식물; 초목","partOfSpeech":"n.","example":"The tropical region is covered with dense vegetation throughout the year.","exampleTranslation":"그 열대 지역은 연중 내내 울창한 초목으로 덮여 있습니다.","level":41,"category":"빈도 학습"},{"id":14925,"term":"velocity","meaning":"속도; 속력","partOfSpeech":"n.","example":"Scientists measured the velocity of the falling object in the experiment.","exampleTranslation":"과학자들은 실험에서 낙하하는 물체의 속도를 측정했습니다.","level":41,"category":"빈도 학습"},{"id":14926,"term":"velvet","meaning":"벨벳; 부드러운","partOfSpeech":"n.","example":"The bride wore a gown trimmed with soft velvet around the neckline.","exampleTranslation":"신부는 목선 주위에 부드러운 벨벳으로 장식된 가운을 입었습니다.","level":41,"category":"빈도 학습"},{"id":14927,"term":"vent","meaning":"환기구; 감정을 발산하다","partOfSpeech":"n.","example":"She covered the vent to keep the cold air from coming into the room.","exampleTranslation":"그녀는 차가운 공기가 방으로 들어오지 않도록 환기구를 막았습니다.","level":41,"category":"빈도 학습"},{"id":14928,"term":"ventilate","meaning":"환기하다; 통풍시키다","partOfSpeech":"v.","example":"Open the windows to ventilate the kitchen after cooking.","exampleTranslation":"요리 후 부엌을 환기하기 위해 창문을 여세요.","level":41,"category":"빈도 학습"},{"id":14929,"term":"verge","meaning":"가장자리; 직전; 직전에 있다","partOfSpeech":"n.","example":"She was on the verge of tears when she heard the unexpected news.","exampleTranslation":"그녀는 예상치 못한 소식을 들었을 때 눈물이 나올 것 같았습니다.","level":41,"category":"빈도 학습"},{"id":14930,"term":"versatile","meaning":"다재다능한; 다용도의","partOfSpeech":"adj.","example":"She is a versatile musician who can play guitar, piano, and drums.","exampleTranslation":"그녀는 기타, 피아노, 드럼을 연주할 수 있는 다재다능한 음악가입니다.","level":41,"category":"빈도 학습"},{"id":14931,"term":"vest","meaning":"조끼","partOfSpeech":"n.","example":"He wore a bright orange vest so drivers could see him clearly.","exampleTranslation":"그는 운전자들이 그를 잘 볼 수 있도록 밝은 주황색 조끼를 입었습니다.","level":41,"category":"빈도 학습"},{"id":14932,"term":"veto","meaning":"거부권; 거부하다","partOfSpeech":"n.","example":"The president used his veto to block the new spending bill.","exampleTranslation":"대통령은 새 지출 법안을 막기 위해 거부권을 행사했습니다.","level":41,"category":"빈도 학습"},{"id":14933,"term":"vicious","meaning":"잔인한; 사나운; 악의적인","partOfSpeech":"adj.","example":"The vicious storm destroyed several houses along the coast.","exampleTranslation":"사나운 폭풍이 해안을 따라 여러 채의 집을 파괴했습니다.","level":41,"category":"빈도 학습"},{"id":14934,"term":"vigil","meaning":"밤샘; 철야 기도; 감시","partOfSpeech":"n.","example":"Supporters held a candlelight vigil outside the hospital all night.","exampleTranslation":"지지자들은 밤새 병원 밖에서 촛불 철야를 지켰습니다.","level":41,"category":"빈도 학습"},{"id":14935,"term":"vine","meaning":"덩굴식물; 포도나무","partOfSpeech":"n.","example":"A wild vine had grown up and covered the old stone wall completely.","exampleTranslation":"야생 덩굴식물이 자라나 오래된 돌담을 완전히 뒤덮었습니다.","level":41,"category":"빈도 학습"},{"id":14936,"term":"vinegar","meaning":"식초","partOfSpeech":"n.","example":"She added a little vinegar to the salad dressing for extra flavor.","exampleTranslation":"그녀는 풍미를 더하기 위해 샐러드 드레싱에 식초를 조금 넣었습니다.","level":41,"category":"빈도 학습"},{"id":14937,"term":"vintage","meaning":"오래된; 빈티지; 특정 연도산 와인","partOfSpeech":"adj.","example":"He collects vintage cars from the 1960s as a hobby.","exampleTranslation":"그는 취미로 1960년대 빈티지 자동차를 수집합니다.","level":41,"category":"빈도 학습"},{"id":14938,"term":"violin","meaning":"바이올린","partOfSpeech":"n.","example":"She has been playing the violin since she was five years old.","exampleTranslation":"그녀는 다섯 살 때부터 바이올린을 연주해 왔습니다.","level":41,"category":"빈도 학습"},{"id":14939,"term":"vocabulary","meaning":"어휘; 단어 실력","partOfSpeech":"n.","example":"Reading every day is one of the best ways to expand your vocabulary.","exampleTranslation":"매일 독서하는 것은 어휘를 늘리는 최고의 방법 중 하나입니다.","level":41,"category":"빈도 학습"},{"id":14940,"term":"void","meaning":"무효의; 빈 공간; 공백","partOfSpeech":"adj.","example":"The contract was declared void because one party did not sign it.","exampleTranslation":"한 쪽이 서명하지 않아 계약이 무효로 선언되었습니다.","level":41,"category":"빈도 학습"},{"id":14941,"term":"volatile","meaning":"변동이 심한; 불안정한; 휘발성의","partOfSpeech":"adj.","example":"The stock market has been very volatile over the past few weeks.","exampleTranslation":"주식 시장이 지난 몇 주 동안 매우 불안정했습니다.","level":41,"category":"빈도 학습"},{"id":14942,"term":"volt","meaning":"볼트(전압 단위)","partOfSpeech":"n.","example":"This charger outputs five volt, which is standard for USB devices.","exampleTranslation":"이 충전기는 USB 기기에 표준인 5볼트를 출력합니다.","level":41,"category":"빈도 학습"},{"id":14943,"term":"voucher","meaning":"바우처; 상품권; 쿠폰","partOfSpeech":"n.","example":"The hotel gave us a voucher for a free breakfast the next morning.","exampleTranslation":"호텔은 다음 날 아침 무료 조식 바우처를 주었습니다.","level":41,"category":"빈도 학습"},{"id":14944,"term":"vow","meaning":"맹세; 서약하다","partOfSpeech":"n.","example":"They exchanged a vow to always support each other no matter what.","exampleTranslation":"그들은 어떤 상황에서도 서로를 항상 지지하겠다는 맹세를 나눴습니다.","level":41,"category":"빈도 학습"},{"id":14945,"term":"voyage","meaning":"항해; 긴 여행","partOfSpeech":"n.","example":"The sailors set off on a long voyage across the Pacific Ocean.","exampleTranslation":"선원들은 태평양을 가로지르는 긴 항해를 시작했습니다.","level":41,"category":"빈도 학습"},{"id":14946,"term":"wail","meaning":"울부짖다; 통곡하다","partOfSpeech":"v.","example":"The child began to wail loudly when her balloon flew away.","exampleTranslation":"풍선이 날아가자 아이는 큰 소리로 울부짖기 시작했습니다.","level":41,"category":"빈도 학습"},{"id":14947,"term":"wardrobe","meaning":"옷장; 의상","partOfSpeech":"n.","example":"She opened the wardrobe and picked out an outfit for the evening.","exampleTranslation":"그녀는 옷장을 열고 저녁에 입을 옷을 골랐습니다.","level":41,"category":"빈도 학습"},{"id":14948,"term":"warfare","meaning":"전쟁; 전투; 싸움","partOfSpeech":"n.","example":"The documentary explored the impact of modern warfare on civilian life.","exampleTranslation":"그 다큐멘터리는 현대 전쟁이 민간인 생활에 미치는 영향을 다뤘습니다.","level":41,"category":"빈도 학습"},{"id":14949,"term":"wary","meaning":"경계하는; 조심하는","partOfSpeech":"adj.","example":"Be wary of strangers who offer help without any reason.","exampleTranslation":"이유 없이 도움을 제공하는 낯선 사람을 조심하세요.","level":41,"category":"빈도 학습"},{"id":14950,"term":"wedge","meaning":"쐐기; 쐐기 모양의 것; 끼워 넣다","partOfSpeech":"n.","example":"He used a wedge to prop the door open while carrying boxes inside.","exampleTranslation":"그는 박스를 안으로 옮기는 동안 문이 열려 있도록 쐐기를 괴었습니다.","level":41,"category":"빈도 학습"},{"id":14951,"term":"wee","meaning":"아주 작은; 조금","partOfSpeech":"adj.","example":"Just add a wee bit of salt and it will taste much better.","exampleTranslation":"소금을 아주 조금만 넣으면 훨씬 맛있을 거예요.","level":41,"category":"빈도 학습"},{"id":14952,"term":"weld","meaning":"용접하다; 용접","partOfSpeech":"v.","example":"The technician had to weld the broken pipe back together carefully.","exampleTranslation":"기술자는 깨진 파이프를 조심스럽게 다시 용접해야 했습니다.","level":41,"category":"빈도 학습"},{"id":14953,"term":"whatsoever","meaning":"어떤 ~도; 전혀","partOfSpeech":"adv.","example":"There is no evidence whatsoever to support that claim.","exampleTranslation":"그 주장을 뒷받침할 증거가 전혀 없습니다.","level":41,"category":"빈도 학습"},{"id":14954,"term":"wheat","meaning":"밀; 소맥","partOfSpeech":"n.","example":"This bread is made from whole wheat flour for a healthier option.","exampleTranslation":"이 빵은 더 건강한 선택을 위해 통밀가루로 만들어졌습니다.","level":41,"category":"빈도 학습"},{"id":14955,"term":"whereby","meaning":"그것에 의해; 그 결과로","partOfSpeech":"adv.","example":"They set up a system whereby customers can track their orders online.","exampleTranslation":"그들은 고객이 온라인으로 주문을 추적할 수 있는 시스템을 구축했습니다.","level":41,"category":"빈도 학습"},{"id":14956,"term":"whisk","meaning":"거품기; 휘젓다; 빠르게 움직이다","partOfSpeech":"v.","example":"Whisk the eggs and sugar together until the mixture turns pale yellow.","exampleTranslation":"혼합물이 연한 노란색이 될 때까지 계란과 설탕을 함께 휘저으세요.","level":41,"category":"빈도 학습"},{"id":14957,"term":"wholesale","meaning":"도매; 도매의","partOfSpeech":"adj.","example":"The restaurant buys ingredients at wholesale prices to cut costs.","exampleTranslation":"그 식당은 비용을 절감하기 위해 도매 가격으로 재료를 구입합니다.","level":41,"category":"빈도 학습"},{"id":14958,"term":"wilderness","meaning":"황야; 자연 그대로의 지역","partOfSpeech":"n.","example":"They hiked through the wilderness for three days without seeing anyone.","exampleTranslation":"그들은 아무도 만나지 않고 사흘 동안 황야를 하이킹했습니다.","level":41,"category":"빈도 학습"},{"id":14959,"term":"wink","meaning":"윙크하다; 눈을 깜박이다","partOfSpeech":"v.","example":"He gave her a wink to signal that everything was going according to plan.","exampleTranslation":"그는 모든 것이 계획대로 진행되고 있다는 신호로 그녀에게 윙크했습니다.","level":41,"category":"빈도 학습"},{"id":14960,"term":"wireless","meaning":"무선의; 와이파이","partOfSpeech":"adj.","example":"The cafe offers free wireless internet to all of its customers.","exampleTranslation":"그 카페는 모든 고객에게 무료 무선 인터넷을 제공합니다.","level":41,"category":"빈도 학습"},{"id":14961,"term":"witch","meaning":"마녀","partOfSpeech":"n.","example":"The story was about a kind witch who helped lost children find their way home.","exampleTranslation":"그 이야기는 길을 잃은 아이들이 집을 찾도록 도운 친절한 마녀에 관한 것이었습니다.","level":41,"category":"빈도 학습"},{"id":14962,"term":"withhold","meaning":"보류하다; 주지 않다","partOfSpeech":"v.","example":"The company decided to withhold the bonus until the project was completed.","exampleTranslation":"회사는 프로젝트가 완료될 때까지 보너스를 보류하기로 결정했습니다.","level":41,"category":"빈도 학습"},{"id":14963,"term":"wizard","meaning":"마법사; 달인","partOfSpeech":"n.","example":"The old wizard in the story could turn any object into gold.","exampleTranslation":"이야기 속 노련한 마법사는 어떤 물건이든 금으로 바꿀 수 있었습니다.","level":41,"category":"빈도 학습"},{"id":14964,"term":"worthwhile","meaning":"할 가치가 있는; 보람 있는","partOfSpeech":"adj.","example":"Learning a new language is always worthwhile, even if it takes time.","exampleTranslation":"새로운 언어를 배우는 것은 시간이 걸리더라도 항상 보람 있습니다.","level":41,"category":"빈도 학습"},{"id":14965,"term":"wrestle","meaning":"씨름하다; 격투하다; 고심하다","partOfSpeech":"v.","example":"He had to wrestle with a difficult decision about changing his career.","exampleTranslation":"그는 경력을 바꾸는 것에 대한 어려운 결정과 씨름해야 했습니다.","level":41,"category":"빈도 학습"},{"id":14966,"term":"wrinkle","meaning":"주름; 주름지다","partOfSpeech":"n.","example":"She ironed the shirt carefully to remove every wrinkle before the interview.","exampleTranslation":"그녀는 면접 전 모든 주름을 없애기 위해 셔츠를 꼼꼼히 다렸습니다.","level":41,"category":"빈도 학습"},{"id":14967,"term":"yacht","meaning":"요트","partOfSpeech":"n.","example":"They spent the weekend on a yacht sailing along the coast.","exampleTranslation":"그들은 해안을 따라 요트를 타며 주말을 보냈습니다.","level":41,"category":"빈도 학습"},{"id":14968,"term":"zip","meaning":"지퍼; 우편번호; 빠르게 움직이다","partOfSpeech":"n.","example":"Please enter your zip code to find the nearest store location.","exampleTranslation":"가장 가까운 매장 위치를 찾으려면 우편번호를 입력하세요.","level":41,"category":"빈도 학습"},{"id":14969,"term":"zoo","meaning":"동물원","partOfSpeech":"n.","example":"The children were excited to visit the zoo and see the pandas.","exampleTranslation":"아이들은 동물원에 가서 판다를 보게 되어 매우 신났습니다.","level":41,"category":"빈도 학습"}]`);export{e as default};